# ---------------------------------------------------------------------------
# PostgreSQL connection pool + SQLite-compatible wrapper
# ---------------------------------------------------------------------------

_pg_pool: "psycopg2.pool.ThreadedConnectionPool | None" = None


def _get_pool() -> "psycopg2.pool.ThreadedConnectionPool":
    global _pg_pool
    if _pg_pool is None:
        # Bigger pool — 1 gunicorn worker × 500 gevent connections + several
        # background threads (cloud-sync, pricing-prewarm, receipt-replay)
        # easily exceed 10 simultaneous PG conns under load.
        # TCP keepalives surface dead connections in seconds instead of minutes.
        _pg_pool = psycopg2.pool.ThreadedConnectionPool(
            int(os.environ.get("PG_POOL_MIN", "2")),
            int(os.environ.get("PG_POOL_MAX", "20")),
            dsn=DATABASE_URL,
            keepalives=1,
            keepalives_idle=30,
            keepalives_interval=10,
            keepalives_count=3,
            # Prevent a runaway query from holding a worker forever — 8 s ceiling.
            options=f"-c statement_timeout={os.environ.get('PG_STATEMENT_TIMEOUT_MS', '8000')}",
        )
    return _pg_pool


class _PgConn:
    """
    Wraps a raw psycopg2 connection to mimic the sqlite3 connection API so
    that all existing db.execute() / db.commit() call-sites stay unchanged.
    • Converts SQLite '?' placeholders → psycopg2 '%s' automatically.
    • Returns DictCursor rows that support both r["col"] and r[0] access.
    """

    def __init__(self, raw_conn):
        self._conn = raw_conn

    def execute(self, sql: str, params=()):
        cur = self._conn.cursor(cursor_factory=psycopg2.extras.DictCursor)
        try:
            cur.execute(sql.replace("?", "%s"), params or ())
        except Exception:
            try:
                self._conn.rollback()
            except Exception:
                pass
            raise
        return cur

    def executemany(self, sql: str, params_list):
        cur = self._conn.cursor(cursor_factory=psycopg2.extras.DictCursor)
        try:
            cur.executemany(sql.replace("?", "%s"), params_list)
        except Exception:
            try:
                self._conn.rollback()
            except Exception:
                pass
            raise
        return cur

    def cursor(self, *args, **kwargs):
        """
        Passthrough to the wrapped raw connection's .cursor(), defaulting
        to DictCursor so `with conn.cursor() as cur: cur.execute(...)` works
        exactly as it would on a bare psycopg2 connection.

        Lets newer modules (price_aggregator, scan_overrides,
        import_artwork_hashes) use the standard psycopg2 cursor idiom
        without caring whether they were handed a _PgConn wrapper or a raw
        connection.
        """
        kwargs.setdefault("cursor_factory", psycopg2.extras.DictCursor)
        return self._conn.cursor(*args, **kwargs)

    def commit(self):
        self._conn.commit()

    def rollback(self):
        self._conn.rollback()

    def close(self):
        commit_err = None
        try:
            self._conn.commit()
        except Exception as _e:
            commit_err = _e
            try:
                self._conn.rollback()
            except Exception:
                pass
            log.error("[_PgConn.close] commit failed — rolled back: %s", _e)
        # Always return the connection so the pool doesn't leak.
        try:
            _get_pool().putconn(self._conn)
        finally:
            if commit_err is not None:
                # Re-raise so the caller (request handler) sees the failure
                # instead of silently believing the write succeeded.
                raise commit_err

    # Compatibility no-ops for code that sets conn.row_factory = sqlite3.Row
    @property
    def row_factory(self):
        return None

    @row_factory.setter
    def row_factory(self, _):
        pass


def _direct_db() -> _PgConn:
    """Open a pooled connection for use outside a Flask request context."""
    return _PgConn(_get_pool().getconn())


class _PooledConn:
    """Context manager that checks out a raw psycopg2 connection from the pool
    and returns it on exit.  Used by routes that need cursor-level access."""

    def __init__(self):
        self._conn = None

    def __enter__(self):
        self._conn = _get_pool().getconn()
        return self._conn

    def __exit__(self, exc_type, exc_val, exc_tb):
        commit_err = None
        if self._conn is not None:
            try:
                if exc_type:
                    self._conn.rollback()
                else:
                    self._conn.commit()
            except Exception as _e:
                commit_err = _e
                try:
                    self._conn.rollback()
                except Exception:
                    pass
                log.error("[_PooledConn.__exit__] commit/rollback failed: %s", _e)
            try:
                _get_pool().putconn(self._conn)
            except Exception:
                log.exception("[_PooledConn.__exit__] putconn failed")
            self._conn = None
        if commit_err is not None and exc_type is None:
            # Surface DB write failure when the request thought it was succeeding.
            raise commit_err
        return False


def _get_conn():
    """Return a context-manager that provides a raw psycopg2 connection."""
    return _PooledConn()

# ---------------------------------------------------------------------------
# In-memory caches — dramatically reduces SQLite hits on hot endpoints
# ---------------------------------------------------------------------------
_cache_lock      = threading.Lock()
_inventory_cache = TTLCache(maxsize=1,   ttl=30)   # /inventory — 30 s TTL
_scan_cache      = TTLCache(maxsize=1,   ttl=1)    # /scan/pending — 1 s TTL
_health_cache    = TTLCache(maxsize=1,   ttl=5)    # /health — 5 s TTL
_qr_scan_cache   = TTLCache(maxsize=500, ttl=300)  # /card/scan — 5 min per QR code
_cache_stats     = {"inventory_hits": 0, "inventory_misses": 0,
                    "scan_hits": 0,      "scan_misses": 0}

# ---------------------------------------------------------------------------
# Scan-image prefetch — kiosk customer monitor preloads recently-scanned card
# images on idle so the next scan flips the picture instantly (chromium serves
# from local HTTP cache instead of doing a 100-300 ms fetch).
# ---------------------------------------------------------------------------
import collections as _collections
_recent_scan_image_urls: "_collections.deque[str]" = _collections.deque(maxlen=200)
_recent_scan_lock = threading.Lock()


def _track_scan_image(url: str):
    """Record a card image URL as 'recently scanned' for the kiosk to prefetch."""
    if not url or not isinstance(url, str):
        return
    if not (url.startswith("http://") or url.startswith("https://") or url.startswith("/")):
        return
    with _recent_scan_lock:
        # Keep most-recent ordering: remove duplicate then push to the right
        try:
            _recent_scan_image_urls.remove(url)
        except ValueError:
            pass
        _recent_scan_image_urls.append(url)

# ---------------------------------------------------------------------------
# Redis — lazy singleton, cross-worker pub/sub + L2 cache
# ---------------------------------------------------------------------------
_redis_client_obj  = None
_redis_client_lock = threading.Lock()
_REDIS_SCAN_CHAN   = "hanryx:scans"
_REDIS_INV_KEY     = "hv:inv:all"
_REDIS_QR_PREFIX   = "hv:qr:"


def _redis():
    """Return a live redis.Redis client, or None if Redis is not reachable."""
    global _redis_client_obj
    if _redis_client_obj is not None:
        return _redis_client_obj
    with _redis_client_lock:
        if _redis_client_obj is not None:
            return _redis_client_obj
        url = os.environ.get("REDIS_URL", "redis://redis:6379/0")
        try:
            c = _redis_mod.Redis.from_url(
                url,
                socket_connect_timeout=2,
                socket_timeout=2,
                decode_responses=False,
            )
            c.ping()
            _redis_client_obj = c
            log.info("[redis] Connected to %s", url)
        except Exception as _e:
            log.warning("[redis] Not available (%s) — SSE/cache will use in-process fallback", _e)
        return _redis_client_obj


# ---------------------------------------------------------------------------
# Server-side sessions (Redis-backed)
# ---------------------------------------------------------------------------
# Default Flask sessions are signed cookies — those alone DO survive a
# container restart, BUT login state is implemented via session keys (e.g.
# `session["admin"]=True`). Several deploy hooks rotate SESSION_SECRET at
# startup, which invalidates every cookie and logs every operator out.
#
# By moving session storage to Redis (which is a separate, persistent
# container that we never `--force-recreate`), the session ID in the cookie
# stays valid across pos-container redeploys. Operator stays logged in.
#
# Falls back gracefully to the default cookie store if Redis is unreachable
# OR if flask-session is not installed (e.g. fresh dev checkout).
try:
    from flask_session import Session as _FlaskSession
    _session_redis = _redis()
    if _session_redis is not None:
        app.config["SESSION_TYPE"]               = "redis"
        app.config["SESSION_REDIS"]              = _session_redis
        app.config["SESSION_PERMANENT"]          = True
        app.config["PERMANENT_SESSION_LIFETIME"] = 60 * 60 * 24 * 7  # 7 days
        app.config["SESSION_USE_SIGNER"]         = True
        app.config["SESSION_KEY_PREFIX"]         = "hv:sess:"
        _FlaskSession(app)
        log.info("[session] Redis-backed sessions enabled — operators persist across pos restarts (TTL 7d)")
    else:
        log.warning("[session] Redis unreachable — falling back to default cookie sessions (operators will be logged out on container restart)")
except ImportError:
    log.warning("[session] flask-session not installed — using default cookie sessions. `pip install flask-session` to fix.")


def _rcache_get(key: str):
    """Get a JSON-encoded value from Redis. Returns None on miss or error."""
    try:
        r = _redis()
        if not r:
            return None
        raw = r.get(key)
        return json.loads(raw) if raw else None
    except Exception:
        return None


def _rcache_set(key: str, value, ttl: int = 30):
    """Store a JSON-encoded value in Redis with a TTL (seconds)."""
    try:
        r = _redis()
        if r:
            r.set(key, json.dumps(value), ex=ttl)
    except Exception:
        pass


def _rcache_del(*keys: str):
    """Delete one or more keys from Redis."""
    try:
        r = _redis()
        if r and keys:
            r.delete(*keys)
    except Exception:
        pass


# ---------------------------------------------------------------------------
# Worker thread pool — replaces ad-hoc daemon threads for fire-and-forget work
# ---------------------------------------------------------------------------
_worker_pool = _TPE(max_workers=8, thread_name_prefix="hvault-worker")

def _bg(fn, *args, **kwargs):
    """Submit a fire-and-forget task to the shared worker pool."""
    try:
        _worker_pool.submit(fn, *args, **kwargs)
    except Exception as _e:
        log.warning("[worker] submit failed for %s: %s", getattr(fn, "__name__", fn), _e)

def _queue_unsynced(qr_code: str, change_type: str = "stock", delta: int = 0):
    """
    Record a stock/price change that has not yet been pushed to the storefront.
    Runs in the background so it never blocks the request path.
    change_type: 'stock' | 'price' | 'new' | 'delete'
    """
    def _write():
        try:
            db = _direct_db()
            db.execute(
                "INSERT INTO unsynced_changes (qr_code, change_type, delta) VALUES (%s, %s, %s)",
                (qr_code, change_type, delta),
            )
            db.commit()
            db.close()
        except Exception as _e:
            try: db.close()
            except Exception: pass
            log.debug("[unsynced] write failed: %s", _e)
    _bg(_write)

# ---------------------------------------------------------------------------
# HTTP retry wrapper — automatic exponential back-off on transient failures
# ---------------------------------------------------------------------------
def _http_get(url, *, retries=3, backoff=0.5, timeout=10, headers=None, **kwargs):
    """GET with retries on network / timeout errors. Raises on final failure."""
    last_exc = None
    for attempt in range(retries):
        try:
            r = _requests.get(url, timeout=timeout, headers=headers or {}, **kwargs)
            r.raise_for_status()
            return r
        except (_requests.Timeout, _requests.ConnectionError) as exc:
            last_exc = exc
            if attempt < retries - 1:
                _time.sleep(backoff * (2 ** attempt))
        except _requests.HTTPError as exc:
            if exc.response is not None and exc.response.status_code < 500:
                raise
            last_exc = exc
            if attempt < retries - 1:
                _time.sleep(backoff * (2 ** attempt))
    raise last_exc

def _http_post(url, *, retries=2, backoff=0.5, timeout=10, headers=None,
               json_body=None, data=None, **kwargs):
    """POST with retries on network / timeout errors. Raises on final failure."""
    last_exc = None
    for attempt in range(retries):
        try:
            r = _requests.post(url, timeout=timeout, headers=headers or {},
                               json=json_body, data=data, **kwargs)
            r.raise_for_status()
            return r
        except (_requests.Timeout, _requests.ConnectionError) as exc:
            last_exc = exc
            if attempt < retries - 1:
                _time.sleep(backoff * (2 ** attempt))
        except _requests.HTTPError as exc:
            if exc.response is not None and exc.response.status_code < 500:
                raise
            last_exc = exc
            if attempt < retries - 1:
                _time.sleep(backoff * (2 ** attempt))
    raise last_exc

