def _smart_normalize(text: str) -> str:
    """Strip everything except lowercase letters and digits for index comparison."""
    return re.sub(r'[^a-z0-9]', '', text.lower())


def _detect_variant(name: str, rarity: str, description: str) -> str:
    """
    Infer card variant from metadata fields.
    Priority: 1st Ed > Reverse Holo > Rainbow > Secret > Gold > Full Art >
              VSTAR > VMAX > V > GX > EX > Holo > Promo > ""
    """
    combined = f"{name} {rarity} {description}".lower()
    name_lc  = name.lower()
    rar_lc   = rarity.lower()
    if "1st edition" in combined or "first edition" in combined:
        return "1st Edition"
    if "reverse holo" in combined or "reverse" in rar_lc:
        return "Reverse Holo"
    if "rainbow" in combined:
        return "Rainbow Rare"
    if "secret" in rar_lc:
        return "Secret Rare"
    if "gold" in rar_lc:
        return "Gold"
    if "full art" in combined:
        return "Full Art"
    if "vstar" in name_lc:
        return "VSTAR"
    if "vmax" in name_lc:
        return "VMAX"
    if re.search(r'\bv\b', name_lc):
        return "V"
    if "gx" in name_lc:
        return "GX"
    if re.search(r'\bex\b', name_lc):
        return "EX"
    if "holo" in combined:
        return "Holo"
    if "promo" in combined:
        return "Promo"
    return ""


# ---------------------------------------------------------------------------
# CLIP + FAISS — visual card identification engine
# ---------------------------------------------------------------------------
_CLIP_CONFIDENCE_THRESHOLD = 0.92
# FAISS index lives on the USB drive at /mnt/cards/faiss/ when
# HANRYX_LOCAL_DB_DIR is set, so it survives container rebuilds without
# the 5-10 minute "rebuild from inventory images" boot delay. Falls back
# to the in-package faiss/ subdir on a dev box.
_FAISS_INDEX_PATH = _resolve_faiss_index_path()
_FAISS_IDS_PATH   = _resolve_faiss_ids_path()

_clip_model      = None
_clip_preprocess = None
_clip_lock       = threading.Lock()
_faiss_index_obj = None
_faiss_card_ids  : list = []
_faiss_lock      = threading.Lock()

# Duplicate-prevention: qr_code → last-seen epoch
_clip_last_seen  : dict = {}
_CLIP_COOLDOWN   = 2.0   # seconds between same-card auto-adds

_VARIANT_MULTIPLIERS: dict = {
    "1st edition":  3.50,
    "rainbow rare": 1.80,
    "secret rare":  1.60,
    "full art":     1.50,
    "alt art":      2.00,
    "gold":         2.50,
    "vstar":        1.30,
    "vmax":         1.25,
    "v":            1.10,
    "gx":           1.15,
    "ex":           1.10,
    "holo":         1.20,
    "reverse holo": 0.85,
    "promo":        1.05,
    "normal":       1.00,
}


def _apply_variant_multiplier(price: float, variant: str) -> float:
    mult = _VARIANT_MULTIPLIERS.get((variant or "").strip().lower(), 1.00)
    return round(float(price) * mult, 2)


def _clip_recently_seen(qr_code: str) -> bool:
    """Return True if this card was auto-added within the cooldown window."""
    now = _time.time()
    if qr_code in _clip_last_seen and now - _clip_last_seen[qr_code] < _CLIP_COOLDOWN:
        return True
    _clip_last_seen[qr_code] = now
    return False


def _load_clip_model() -> bool:
    """Lazy-load CLIP ViT-B/32 on CPU (thread-safe). Returns True on success."""
    global _clip_model, _clip_preprocess
    if _clip_model is not None:
        return True
    with _clip_lock:
        if _clip_model is not None:
            return True
        try:
            import clip as _openai_clip
            _clip_model, _clip_preprocess = _openai_clip.load("ViT-B/32", device="cpu")
            log.info("[CLIP] ViT-B/32 loaded on CPU")
            return True
        except Exception as exc:
            log.warning(f"[CLIP] unavailable — visual scan disabled: {exc}")
            return False


def _clip_embed_bytes(img_bytes: bytes):
    """Return unit-normalised CLIP embedding (1×512 float32 ndarray), or None."""
    if not _load_clip_model():
        return None
    try:
        import torch as _torch
        import numpy as _np
        from PIL import Image as _PILImg
        img    = _PILImg.open(io.BytesIO(img_bytes)).convert("RGB")
        tensor = _clip_preprocess(img).unsqueeze(0)
        with _torch.no_grad():
            emb = _clip_model.encode_image(tensor).float()
        emb = emb / emb.norm(dim=-1, keepdim=True)
        return emb.cpu().numpy()
    except Exception as exc:
        log.debug(f"[CLIP] embed error: {exc}")
        return None


def _build_faiss_index_bg():
    """Background thread: fetch card images, embed with CLIP, save FAISS index."""
    global _faiss_index_obj, _faiss_card_ids
    try:
        import faiss
        import numpy as _np
        if not _load_clip_model():
            return
        db   = _direct_db()
        rows = db.execute(
            "SELECT qr_code, image_url FROM inventory "
            "WHERE image_url != '' AND stock > 0"
        ).fetchall()
        vectors, ids = [], []
        for qr_code, image_url in rows:
            try:
                resp = _requests.get(image_url, timeout=8)
                emb  = _clip_embed_bytes(resp.content)
                if emb is not None:
                    vectors.append(emb)
                    ids.append(qr_code)
            except Exception as e:
                log.debug(f"[FAISS] skip {qr_code}: {e}")
        if not vectors:
            log.warning("[FAISS] no vectors built — no card images available")
            return
        all_vecs = _np.vstack(vectors).astype("float32")
        idx = faiss.IndexFlatIP(all_vecs.shape[1])
        idx.add(all_vecs)
        faiss.write_index(idx, _FAISS_INDEX_PATH)
        with open(_FAISS_IDS_PATH, "w") as f:
            json.dump(ids, f)
        with _faiss_lock:
            _faiss_index_obj = idx
            _faiss_card_ids  = ids
        log.info(f"[FAISS] index built: {len(ids)} cards indexed")
    except Exception as exc:
        log.error(f"[FAISS] build error: {exc}")


def _ensure_faiss_index():
    """Load FAISS index from disk, or trigger a background build if missing."""
    global _faiss_index_obj, _faiss_card_ids
    with _faiss_lock:
        if _faiss_index_obj is not None:
            return
        try:
            import faiss
            if os.path.exists(_FAISS_INDEX_PATH) and os.path.exists(_FAISS_IDS_PATH):
                _faiss_index_obj = faiss.read_index(_FAISS_INDEX_PATH)
                with open(_FAISS_IDS_PATH) as f:
                    _faiss_card_ids = json.load(f)
                log.info(f"[FAISS] loaded from disk: {len(_faiss_card_ids)} cards")
                return
        except Exception as exc:
            log.warning(f"[FAISS] disk load failed: {exc}")
    threading.Thread(target=_build_faiss_index_bg, daemon=True, name="faiss-build").start()


def _clip_find_top(img_bytes: bytes, k: int = 3) -> list:
    """Return top-k [{qr_code, confidence}] sorted by cosine similarity desc."""
    import numpy as _np
    _ensure_faiss_index()
    with _faiss_lock:
        idx = _faiss_index_obj
        ids = list(_faiss_card_ids)
    if idx is None or not ids:
        return []
    emb = _clip_embed_bytes(img_bytes)
    if emb is None:
        return []
    k_actual = min(k, len(ids))
    scores, indices = idx.search(emb.astype("float32"), k_actual)
    out = []
    for i in range(k_actual):
        j = int(indices[0][i])
        if 0 <= j < len(ids):
            out.append({"qr_code": ids[j], "confidence": round(float(scores[0][i]), 3)})
    return out


def _enrich_clip_matches(matches: list, db) -> list:
    """Look up inventory rows for each raw match and return enriched dicts."""
    out = []
    for m in matches:
        row = db.execute(
            "SELECT qr_code, name, price, stock, variant, condition, category, "
            "set_code, card_number, image_url FROM inventory WHERE qr_code=%s",
            (m["qr_code"],)
        ).fetchone()
        if not row:
            continue
        card  = dict(row)
        # Route image_url through /card/image so the kiosk and scanner UIs
        # get a local USB file when available and a 302-redirect to the
        # network URL otherwise. Keep the original network URL on a side
        # field so consumers that need the raw remote URL still have it.
        if card.get("set_code") and card.get("card_number"):
            card["image_url_remote"] = card.get("image_url") or ""
            card["image_url"] = _card_image_src(card)
        v     = card.get("variant") or "normal"
        price = _apply_variant_multiplier(float(card.get("price") or 0), v)
        out.append({"card": card, "price": price, "confidence": m["confidence"]})
    return out


_SET_YEAR_MAP: dict[str, int] = {
    "SV":   2023,  # Scarlet & Violet
    "SWSH": 2020,  # Sword & Shield
    "SM":   2017,  # Sun & Moon
    "XY":   2014,  # XY era
    "BW":   2011,  # Black & White
    "HGSS": 2010,  # HeartGold SoulSilver
    "PL":   2009,  # Platinum
    "DP":   2007,  # Diamond & Pearl
    "EX":   2003,  # EX era (vintage)
    "BASE": 1999,  # Base Set
    "GY":   1999,  # Gym Heroes/Challenge
    "TR":   2000,  # Team Rocket
    "N1":   2000,  # Neo Genesis
    "N2":   2000,  # Neo Discovery
    "N4":   2001,  # Neo Destiny
}


def _set_year_from_code(set_code: str) -> int:
    """
    Return the approximate release year for a known Pokémon set-code prefix.
    Checks longest prefix first so 'SWSH' beats 'SW'.
    Returns 0 if unknown.
    """
    sc = set_code.upper()
    for prefix in sorted(_SET_YEAR_MAP, key=len, reverse=True):
        if sc.startswith(prefix):
            return _SET_YEAR_MAP[prefix]
    # Heuristic: bare numeric suffix might encode year (e.g. BW01→2011)
    m = re.match(r'[A-Z]+(\d{2})', sc)
    if m:
        yr2 = int(m.group(1))
        if 99 <= yr2 <= 99:   return 1900 + yr2  # 99 = 1999
        if 0  <= yr2 <= 30:   return 2000 + yr2
    return 0


def _parse_release_year(release_date: str | None) -> int:
    """
    Parse a TCG API releaseDate string ('YYYY/MM/DD' or 'YYYY-MM-DD') into a year int.
    Returns 0 on failure.
    """
    if not release_date:
        return 0
    m = re.match(r'(\d{4})', str(release_date))
    return int(m.group(1)) if m else 0


def _extract_card_number(qr_code: str, name: str = "") -> str:
    """
    Extract the numeric card number from a QR/barcode string.
    Examples:
      'SV1-025'    → '25'
      'SV1EN-025'  → '25'
      'SWSH01-001' → '1'
    Falls back to parsing 'NNN/TTT' patterns from the card name.
    Returns empty string if nothing can be extracted.
    """
    # Primary: SET-NUM format in qr_code (e.g. 'SV1-025', 'SWSH01-001')
    m = re.search(r'[A-Za-z]{2,8}[-/]0*(\d{1,4}[a-zA-Z]?)', qr_code)
    if m:
        return m.group(1).lstrip("0") or "0"
    # Fallback: 'NNN/TTT' in card name (e.g. '025/165')
    m = re.search(r'\b0*(\d{1,4})/\d+\b', name)
    if m:
        return m.group(1).lstrip("0") or "0"
    return ""


class _SmartScanner:
    """
    In-memory scan resolution pipeline.  Runs on each worker process independently.

    Pipeline priority (returns on first confident match):
      1. Learning cache — previous confirmed mappings, instant
      2. Exact in-memory qr_code match
      3. Set-code + card-number parse and match
      4. rapidfuzz WRatio name match (threshold 70 / 100)
      5. FAIL — returns top-3 suggestions

    Invalidated whenever inventory changes (_invalidate_inventory).
    Loaded lazily on first smart_scan() call after invalidation.
    """

    FUZZY_THRESHOLD  = 70    # minimum rapidfuzz WRatio score (0–100)
    MAX_INDEX_SIZE   = 10_000  # safety cap for very large catalogues

    def __init__(self):
        self._lock         = threading.Lock()
        self._loaded       = False
        self._index: list  = []        # list of item dicts (all inventory rows)
        self._names: list  = []        # parallel list of card names for rapidfuzz
        self._qr_map: dict = {}        # qr_code → item dict (fast exact lookup)
        self._learn: dict  = {}        # raw_qr → qr_code (scan learning cache)

    # ── Public interface ──────────────────────────────────────────────────────

    def invalidate(self):
        with self._lock:
            self._loaded = False
            self._index.clear()
            self._names.clear()
            self._qr_map.clear()
            # Intentionally preserve _learn — learned mappings survive invalidations

    def learn(self, raw_qr: str, qr_code: str):
        """Record that raw_qr resolved to qr_code so future scans are instant."""
        if raw_qr and qr_code and raw_qr != qr_code:
            with self._lock:
                self._learn[raw_qr] = qr_code

    def smart_scan(self, qr: str, db) -> dict:
        """
        Run the full resolution pipeline.  Returns:
          {
            "found":      bool,
            "confidence": float (0.0–1.0),
            "method":     str,
            "variant":    str,
            "item":       dict | None,    # inventory row as dict (if found)
            "suggestions": list           # top-3 name matches (if not found)
          }
        """
        if not _RAPIDFUZZ_AVAILABLE:
            return self._not_found(qr, [])

        self._ensure_loaded(db)
        qr = qr.strip()

        # 1 — Learning cache (fastest — previous confirmed mapping)
        result = self._check_learning(qr)
        if result:
            return result

        # 2 — Exact in-memory qr_code match
        result = self._exact_match(qr)
        if result:
            return result

        # 3 — Set + number parse
        result = self._set_number_match(qr)
        if result:
            return result

        # 4 — Fuzzy name match (rapidfuzz WRatio)
        result = self._fuzzy_match(qr)
        if result:
            return result

        # 5 — Failed — return top-3 suggestions
        return self._not_found(qr, self._get_suggestions(qr))

    # ── Internal helpers ──────────────────────────────────────────────────────

    def _ensure_loaded(self, db):
        with self._lock:
            if self._loaded:
                return
        try:
            rows = db.execute(
                "SELECT qr_code, name, price, category, rarity, set_code, "
                "description, stock, image_url, tcg_id, condition, item_type, "
                "card_number, variant "
                "FROM inventory ORDER BY name ASC LIMIT %s",
                (self.MAX_INDEX_SIZE,)
            ).fetchall()
        except Exception as e:
            log.warning("[smart-scan] Could not load index: %s", e)
            return

        items = []
        names = []
        qr_map = {}
        for r in rows:
            item = dict(r)
            item["_norm_name"] = _smart_normalize(item.get("name") or "")
            # Use persisted variant; fall back to runtime detection for legacy rows
            if not item.get("variant"):
                item["variant"] = _detect_variant(
                    item.get("name") or "",
                    item.get("rarity") or "",
                    item.get("description") or "",
                )
            item["_variant"] = item["variant"]
            items.append(item)
            names.append(item.get("name") or "")
            qr_map[item["qr_code"]] = item

        with self._lock:
            self._index  = items
            self._names  = names
            self._qr_map = qr_map
            self._loaded = True
        log.info("[smart-scan] Index loaded: %d cards", len(items))

    def _build_result(self, item: dict, confidence: float, method: str) -> dict:
        return {
            "found":       True,
            "confidence":  round(confidence, 3),
            "method":      method,
            "variant":     item.get("_variant", ""),
            "item":        {k: v for k, v in item.items() if not k.startswith("_")},
            "suggestions": [],
        }

    def _not_found(self, qr: str, suggestions: list) -> dict:
        return {
            "found":       False,
            "confidence":  0.0,
            "method":      "none",
            "variant":     "",
            "item":        None,
            "suggestions": suggestions,
        }

    def _check_learning(self, qr: str) -> dict | None:
        with self._lock:
            qr_code = self._learn.get(qr)
            if not qr_code:
                return None
            item = self._qr_map.get(qr_code)
        if item:
            return self._build_result(item, 0.99, "learned")
        return None

    def _exact_match(self, qr: str) -> dict | None:
        with self._lock:
            item = self._qr_map.get(qr)
        if item:
            return self._build_result(item, 1.0, "exact")
        return None

    def _set_number_match(self, qr: str) -> dict | None:
        """Parse SET-NUM patterns like SV1-001 and match by set_code + number."""
        m = re.search(r'\b([A-Za-z]{2,8})[- ]?0*(\d{1,4}[a-zA-Z]?)\b', qr)
        if not m:
            return None
        set_code = m.group(1).upper()
        number   = m.group(2).lstrip("0") or "0"
        with self._lock:
            for item in self._index:
                if (item.get("set_code") or "").upper() == set_code:
                    qr_tail = (item.get("qr_code") or "").upper()
                    if qr_tail.endswith(f"-{number}") or qr_tail.endswith(number.zfill(3)):
                        return self._build_result(item, 0.95, "set_number")
        return None

    def _fuzzy_match(self, qr: str) -> dict | None:
        """Fuzzy name match using rapidfuzz WRatio (handles typos, partial names)."""
        with self._lock:
            names = list(self._names)
            index = list(self._index)
        if not names:
            return None

        result = _rfprocess.extractOne(
            qr,
            names,
            scorer=_fuzz.WRatio,
            score_cutoff=self.FUZZY_THRESHOLD,
        )
        if not result:
            return None

        matched_name, score, idx = result
        item = index[idx]
        confidence = score / 100.0
        method = "fuzzy_name" if confidence >= 0.85 else "fuzzy_low"
        return self._build_result(item, confidence, method)

    def _get_suggestions(self, qr: str) -> list:
        """
        Return up to 5 suggestions when no confident match is found.

        Two sources, merged and ranked:
          1. Inventory fuzzy match  — in-stock cards with similar names
          2. Canonical PokeAPI names — full Pokédex for "not in stock" hints

        Source 2 only fires when source 1 returns nothing useful (best score < 0.65),
        so we don't show "not in stock" suggestions when a real inventory hit exists.
        """
        with self._lock:
            names = list(self._names)
            index = list(self._index)

        suggestions = []

        # ── Source 1: inventory ───────────────────────────────────────────────
        if names:
            results = _rfprocess.extract(qr, names, scorer=_fuzz.WRatio, limit=3)
            for name, score, idx in results:
                item = index[idx]
                suggestions.append({
                    "name":       name,
                    "qrCode":     item.get("qr_code"),
                    "score":      round(score / 100.0, 3),
                    "price":      item.get("price"),
                    "rarity":     item.get("rarity") or "",
                    "variant":    item.get("_variant", ""),
                    "imageUrl":   item.get("image_url") or "",
                    "inStock":    True,
                    "source":     "inventory",
                })

        # ── Source 2: canonical Pokédex (only when inventory results are weak) ─
        best_inv_score = max((s["score"] for s in suggestions), default=0.0)
        if best_inv_score < 0.65 and _RAPIDFUZZ_AVAILABLE:
            _ensure_pokeapi_names()   # no-op if already loaded
            canon = _normalize_to_canonical(qr, threshold=65)
            if canon:
                # Only add if the canonical name isn't already in suggestions
                already = any(
                    s["name"].lower() == canon["canonical"].lower()
                    for s in suggestions
                )
                if not already:
                    suggestions.append({
                        "name":      canon["canonical"],
                        "qrCode":    None,
                        "score":     canon["score"],
                        "price":     None,
                        "rarity":    "",
                        "variant":   "",
                        "imageUrl":  (
                            f"https://raw.githubusercontent.com/PokeAPI/sprites/master/"
                            f"sprites/pokemon/other/official-artwork/{canon['pokedex_no']}.png"
                        ),
                        "inStock":   False,
                        "source":    "pokedex",
                        "pokedexNo": canon["pokedex_no"],
                        "hint":      "Not in your stock — add it via Trade-In or Purchase Order",
                    })

        # Sort by score descending, cap at 5
        suggestions.sort(key=lambda x: x["score"], reverse=True)
        return suggestions[:5]


_smart_scanner = _SmartScanner()


# ---------------------------------------------------------------------------
# PokéAPI canonical Pokémon name cache
# ---------------------------------------------------------------------------
# Fetches every species name once from pokeapi.co and stores it in PostgreSQL.
# Loaded into a module-level in-memory list for zero-latency lookups.
# Refreshed weekly in the background — no per-request network calls.
# ---------------------------------------------------------------------------

# Primary PokéAPI URL — defaults to the self-hosted offline mirror running in
# the `pokeapi` Docker service (see pi-setup/docker-compose.yml).  Override with
# POKEAPI_BASE_URL=… in the environment for development outside Docker.
_POKEAPI_BASE        = os.environ.get("POKEAPI_BASE_URL", "https://pokeapi.co/api/v2").rstrip("/")
_POKEAPI_FALLBACK    = "https://pokeapi.co/api/v2"
_POKEAPI_CACHE_TTL_DAYS = 7


def _pokeapi_get(path: str, *, params=None, timeout: int = 20):
    """
    GET against the PokéAPI, preferring the local offline mirror.
    Falls back to https://pokeapi.co/api/v2 if the mirror is unreachable
    or returns a 5xx response.  `path` should start with '/'.
    """
    headers = {"User-Agent": "HanryxVault-POS/1.0"}
    last_exc = None
    bases = [_POKEAPI_BASE]
    if _POKEAPI_BASE != _POKEAPI_FALLBACK:
        bases.append(_POKEAPI_FALLBACK)

    for base in bases:
        url = f"{base}{path}"
        try:
            r = _requests.get(url, params=params, timeout=timeout, headers=headers)
            if r.status_code >= 500:
                last_exc = RuntimeError(f"{url} → HTTP {r.status_code}")
                log.warning("[pokeapi] %s returned %d, trying next base", url, r.status_code)
                continue
            r.raise_for_status()
            return r
        except Exception as exc:
            last_exc = exc
            log.warning("[pokeapi] %s failed (%s), trying next base", url, exc)
            continue
    raise last_exc or RuntimeError("pokeapi: all bases failed")

# Slugs that need a special display name (PokeAPI returns lowercase-hyphen slugs)
_SLUG_SPECIAL: dict[str, str] = {
    "mr-mime":    "Mr. Mime",
    "mime-jr":    "Mime Jr.",
    "mr-rime":    "Mr. Rime",
    "type-null":  "Type: Null",
    "ho-oh":      "Ho-Oh",
    "porygon-z":  "Porygon-Z",
    "jangmo-o":   "Jangmo-o",
    "hakamo-o":   "Hakamo-o",
    "kommo-o":    "Kommo-o",
    "tapu-koko":  "Tapu Koko",
    "tapu-lele":  "Tapu Lele",
    "tapu-bulu":  "Tapu Bulu",
    "tapu-fini":  "Tapu Fini",
    "chi-yu":     "Chi-Yu",
    "chien-pao":  "Chien-Pao",
    "ting-lu":    "Ting-Lu",
    "wo-chien":   "Wo-Chien",
    "great-tusk": "Great Tusk",
    "scream-tail":"Scream Tail",
    "brute-bonnet":"Brute Bonnet",
    "flutter-mane":"Flutter Mane",
    "slither-wing":"Slither Wing",
    "sandy-shocks":"Sandy Shocks",
    "iron-treads": "Iron Treads",
    "iron-bundle": "Iron Bundle",
    "iron-hands":  "Iron Hands",
    "iron-jugulis":"Iron Jugulis",
    "iron-moth":   "Iron Moth",
    "iron-thorns": "Iron Thorns",
    "roaring-moon":"Roaring Moon",
    "iron-valiant":"Iron Valiant",
    "walking-wake":"Walking Wake",
    "iron-leaves": "Iron Leaves",
    "gouging-fire":"Gouging Fire",
    "raging-bolt": "Raging Bolt",
    "iron-boulder":"Iron Boulder",
    "iron-crown":  "Iron Crown",
    "terapagos":   "Terapagos",
}


def _slug_to_name(slug: str) -> str:
    """Convert a PokeAPI slug like 'mr-mime' to a display name like 'Mr. Mime'."""
    if slug in _SLUG_SPECIAL:
        return _SLUG_SPECIAL[slug]
    return " ".join(part.capitalize() for part in slug.split("-"))


# Module-level in-memory list: [{slug, name, pokedex_no}]
_pokeapi_names_lock  = threading.Lock()
_pokeapi_names_list: list[dict] = []   # full dicts
_pokeapi_names_strs: list[str]  = []   # just the display names (for rapidfuzz)
_pokeapi_names_ready = False


def _pokeapi_fetch_and_store() -> int:
    """
    Fetch all species names from PokeAPI and upsert into pokeapi_name_cache.
    Returns the count of names stored, or 0 on failure.
    """
    try:
        resp = _pokeapi_get(
            "/pokemon-species",
            params={"limit": 10000, "offset": 0},
            timeout=20,
        )
        data    = resp.json()
        results = data.get("results", [])
    except Exception as _e:
        log.warning("[pokeapi] fetch failed: %s", _e)
        return 0

    db  = _direct_db()
    now = _now_ms()
    for idx, entry in enumerate(results, start=1):
        slug = entry.get("name", "")
        name = _slug_to_name(slug)
        db.execute(
            """
            INSERT INTO pokeapi_name_cache (slug, name, pokedex_no, fetched_at)
            VALUES (%s, %s, %s, %s)
            ON CONFLICT (slug) DO UPDATE
              SET name=EXCLUDED.name,
                  pokedex_no=EXCLUDED.pokedex_no,
                  fetched_at=EXCLUDED.fetched_at
            """,
            (slug, name, idx, now),
        )
    db.commit()
    db.close()
    log.info("[pokeapi] stored %d species names", len(results))
    return len(results)


def _load_pokeapi_names_from_db() -> list[dict]:
    """Read all rows from pokeapi_name_cache into memory."""
    try:
        db   = _direct_db()
        rows = db.execute(
            "SELECT slug, name, pokedex_no FROM pokeapi_name_cache ORDER BY pokedex_no ASC"
        ).fetchall()
        db.close()
        return [{"slug": r["slug"], "name": r["name"], "pokedex_no": r["pokedex_no"]} for r in rows]
    except Exception as _e:
        log.warning("[pokeapi] db load failed: %s", _e)
        return []


def _ensure_pokeapi_names():
    """
    Load canonical Pokémon names into memory.
    On first call: checks DB freshness (< 7 days) — fetches from PokeAPI if stale.
    Thread-safe; subsequent calls are no-ops.
    """
    global _pokeapi_names_ready, _pokeapi_names_list, _pokeapi_names_strs
    with _pokeapi_names_lock:
        if _pokeapi_names_ready:
            return

    # Check cache freshness in DB
    try:
        db = _direct_db()
        row = db.execute(
            "SELECT MAX(fetched_at) as last_fetch, COUNT(*) as cnt FROM pokeapi_name_cache"
        ).fetchone()
        db.close()
        count      = row["cnt"] or 0
        last_fetch = row["last_fetch"] or 0
        age_days   = (_now_ms() - last_fetch) / 86_400_000
        stale      = count < 100 or age_days > _POKEAPI_CACHE_TTL_DAYS
    except Exception:
        try: db.close()
        except Exception: pass
        count  = 0
        stale  = True

    if stale:
        log.info("[pokeapi] cache stale (%d entries, %.1f days old) — fetching fresh", count, age_days if count else 0)
        _bg(_pokeapi_fetch_and_store)
        # Use whatever is already in DB while background fetch runs
    
    entries = _load_pokeapi_names_from_db()

    with _pokeapi_names_lock:
        _pokeapi_names_list  = entries
        _pokeapi_names_strs  = [e["name"] for e in entries]
        _pokeapi_names_ready = len(entries) > 0
    
    log.info("[pokeapi] canonical name index ready: %d species", len(entries))


def _normalize_to_canonical(query: str, threshold: int = 70) -> dict | None:
    """
    Find the closest canonical Pokémon species name to `query` using rapidfuzz.
    Returns {canonical, slug, pokedex_no, score} or None if below threshold.

    Used to:
      • Clean up typos before eBay price searches  (e.g. "Chrizard" → "Charizard")
      • Power "Did you mean?" suggestions for cards not in stock
    """
    if not _RAPIDFUZZ_AVAILABLE:
        return None
    with _pokeapi_names_lock:
        names   = list(_pokeapi_names_strs)
        entries = list(_pokeapi_names_list)
    if not names:
        return None

    # Use Jaro-Winkler for short name strings (prefix-heavy, good for species names)
    # then verify with WRatio for word-reordered inputs
    from rapidfuzz.distance import JaroWinkler as _jw
    jw_scores = [(i, _jw.similarity(query, n) * 100) for i, n in enumerate(names)]
    best_jw   = max(jw_scores, key=lambda x: x[1])

    wr_result = _rfprocess.extractOne(query, names, scorer=_fuzz.WRatio, score_cutoff=threshold)

    # Pick whichever algorithm scored higher
    if wr_result and wr_result[1] >= best_jw[1]:
        matched_name, score, idx = wr_result
    elif best_jw[1] >= threshold:
        idx  = best_jw[0]
        score = best_jw[1]
        matched_name = names[idx]
    else:
        return None

    entry = entries[idx]
    return {
        "canonical":   matched_name,
        "slug":        entry["slug"],
        "pokedex_no":  entry["pokedex_no"],
        "score":       round(score / 100.0, 3),
        "exact":       matched_name.lower() == query.lower(),
    }


# Warm up the name index on startup in the background
_bg(_ensure_pokeapi_names)


def _pokeapi_weekly_refresh_loop():
    """
    Background daemon thread: wakes every 24 h and re-fetches PokeAPI names
    when the cache is older than _POKEAPI_CACHE_TTL_DAYS (7 days).
    Means the cache stays current even on long-running Pi installs that
    never restart.
    """
    import time as _time
    while True:
        _time.sleep(86_400)   # check once a day
        try:
            db  = _direct_db()
            row = db.execute(
                "SELECT MAX(fetched_at) as last_fetch, COUNT(*) as cnt "
                "FROM pokeapi_name_cache"
            ).fetchone()
            db.close()
            age_days = (_now_ms() - (row["last_fetch"] or 0)) / 86_400_000
            if age_days >= _POKEAPI_CACHE_TTL_DAYS:
                log.info("[pokeapi] weekly refresh triggered (%.1f days old)", age_days)
                count = _pokeapi_fetch_and_store()
                if count:
                    entries = _load_pokeapi_names_from_db()
                    global _pokeapi_names_list, _pokeapi_names_strs, _pokeapi_names_ready
                    with _pokeapi_names_lock:
                        _pokeapi_names_list  = entries
                        _pokeapi_names_strs  = [e["name"] for e in entries]
                        _pokeapi_names_ready = True
                    log.info("[pokeapi] weekly refresh complete: %d names", count)
        except Exception as _e:
            log.debug("[pokeapi] weekly refresh error: %s", _e)


_pokeapi_refresh_thread = threading.Thread(
    target=_pokeapi_weekly_refresh_loop, daemon=True, name="pokeapi-refresh"
)
_pokeapi_refresh_thread.start()


# ---------------------------------------------------------------------------
# Pokémon TCG API — config + in-memory cache
# ---------------------------------------------------------------------------
_TCG_API_BASE   = "https://api.pokemontcg.io/v2"
_PTCG_API_KEY   = os.environ.get("PTCG_API_KEY", "")  # optional; free tier = 1k/day, with key = 20k/day
_tcg_cache_lock = threading.Lock()

# OpenAI — card photo identification via GPT-4o Vision
_OPENAI_API_KEY = os.environ.get("OPENAI_API_KEY", "").strip()
_tcg_mem_cache: dict = {}    # card_id → {"data": {...}, "fetched_ms": int}
_TCG_MEM_TTL_MS = 3_600_000           # 1 hour in-memory
_TCG_DB_TTL_MS  = 7 * 86_400_000      # 7 days fresh cache (was 24 h) — market prices barely move daily
_TCG_STALE_OK_MS = 30 * 86_400_000    # serve up to 30-day-old data on upstream failure ("stale-on-error")

# ---------------------------------------------------------------------------
# Pooled HTTP session for ALL TCG-related requests (api.pokemontcg.io, JustTCG,
# TCGCSV). Saves ~80-150 ms TLS handshake per call (huge over the day) and adds
# automatic retry + back-off on 429/5xx so a single hiccup doesn't poison a scan.
# ---------------------------------------------------------------------------
_tcg_session_obj  = None
_tcg_session_lock = threading.Lock()


def _build_tcg_session():
    from requests.adapters import HTTPAdapter
    try:
        from urllib3.util.retry import Retry
    except ImportError:
        from requests.packages.urllib3.util.retry import Retry  # type: ignore
    s = _requests.Session()
    retry = Retry(
        total=3, connect=3, read=3,
        backoff_factor=0.5,                        # 0.5, 1.0, 2.0 s between tries
        status_forcelist=(408, 425, 429, 500, 502, 503, 504),
        allowed_methods=frozenset(["GET", "HEAD"]),
        respect_retry_after_header=True,
        raise_on_status=False,
    )
    adapter = HTTPAdapter(
        pool_connections=10, pool_maxsize=20, max_retries=retry, pool_block=False,
    )
    s.mount("https://", adapter)
    s.mount("http://",  adapter)
    s.headers.update({"Accept": "application/json",
                      "User-Agent": "HanryxVault-POS/2.0 (+pi)"})
    return s


def _tcg_session():
    """Return a process-wide pooled requests.Session with retry/back-off."""
    global _tcg_session_obj
    if _tcg_session_obj is not None:
        return _tcg_session_obj
    with _tcg_session_lock:
        if _tcg_session_obj is None:
            _tcg_session_obj = _build_tcg_session()
    return _tcg_session_obj


# ---------------------------------------------------------------------------
# JustTCG — free secondary price source. Used as a fallback when
# api.pokemontcg.io is rate-limited or unreachable. Set JUSTTCG_API_KEY env
# var to enable; without it this is a no-op (returns None).
#   Docs: https://justtcg.com/docs (free key, generous quota)
# ---------------------------------------------------------------------------
_JUSTTCG_API_KEY  = os.environ.get("JUSTTCG_API_KEY", "").strip()
_JUSTTCG_BASE     = "https://api.justtcg.com/v1"


def _justtcg_lookup_by_id(card_id: str) -> dict | None:
    """Best-effort price lookup via JustTCG. Returns a pokemontcg.io-shaped
    dict with at least {id, name, tcgplayer.prices} so it slots into the same
    summarizer. Returns None when JustTCG is disabled, the card isn't found,
    or the call fails."""
    if not _JUSTTCG_API_KEY or not card_id:
        return None
    cid = card_id.lower().strip()
    m = re.match(r"^([a-z0-9]+)-(\d+[a-z]?)$", cid)
    if not m:
        return None
    set_id, number = m.group(1), m.group(2)
    try:
        params = {"game": "pokemon", "set": set_id, "number": number, "limit": 1}
        resp = _tcg_session().get(
            f"{_JUSTTCG_BASE}/cards",
            headers={"x-api-key": _JUSTTCG_API_KEY},
            params=params, timeout=8,
        )
        if resp.status_code != 200:
            return None
        items = (resp.json() or {}).get("data") or []
        if not items:
            return None
        item = items[0]
        # Pick best market price across variants — defensively coerce to float
        # (some upstreams return prices as strings, which would crash the
        # comparison and silently disable the entire fallback).
        market = None
        for v in item.get("variants") or []:
            raw = v.get("price") or v.get("market") or v.get("low")
            if raw is None:
                continue
            try:
                p = float(raw)
            except (TypeError, ValueError):
                continue
            if p > 0 and (market is None or p < market * 1.5):
                market = p
        if market is None:
            return None
        # Reshape to look like a pokemontcg.io card object so _tcg_to_summary works
        return {
            "id":     cid,
            "name":   item.get("name") or "",
            "number": number,
            "set":    {"id": set_id, "name": item.get("set") or set_id},
            "images": {"small": item.get("imageUrl"), "large": item.get("imageUrl")},
            "tcgplayer": {
                "url":       item.get("tcgplayerUrl") or "",
                "updatedAt": item.get("updatedAt") or "",
                "prices":    {"holofoil": {"market": market}},
            },
            "_source": "justtcg",
        }
    except Exception as e:
        log.debug("[justtcg] lookup failed for %s: %s", cid, e)
        return None


# ---------------------------------------------------------------------------
# TCGCSV — daily Pokémon TCGplayer price snapshot (no API key required).
# Downloads ProductsAndPrices for each Pokémon group (set) and stores in the
# tcgcsv_prices table. Used as a fast-path before hitting api.pokemontcg.io
# during enrichment / price refresh — once warmed, most lookups never touch
# the network at all.
#   Docs: https://tcgcsv.com  (CategoryId 3 = Pokémon)
# ---------------------------------------------------------------------------
_TCGCSV_BASE = "https://tcgcsv.com/tcgplayer/3"
_tcgcsv_lock = threading.Lock()


def _tcgcsv_norm(text: str) -> str:
    """Lowercase + strip non-alphanumerics for fuzzy joins."""
    return re.sub(r"[^a-z0-9]+", "", (text or "").lower())


def _tcgcsv_refresh_groups(session) -> list[dict]:
    """Pull the full Pokémon groups (sets) listing and upsert into tcgcsv_groups."""
    try:
        resp = session.get(f"{_TCGCSV_BASE}/groups", timeout=20)
        if resp.status_code != 200:
            log.warning("[tcgcsv] groups upstream %s", resp.status_code)
            return []
        groups = (resp.json() or {}).get("results") or []
    except Exception as e:
        log.warning("[tcgcsv] groups fetch failed: %s", e)
        return []
    try:
        db = _direct_db()
        for g in groups:
            db.execute(
                "INSERT INTO tcgcsv_groups (group_id, name, abbreviation, published_on) "
                "VALUES (%s,%s,%s,%s) "
                "ON CONFLICT (group_id) DO UPDATE SET name=EXCLUDED.name, "
                "abbreviation=EXCLUDED.abbreviation, published_on=EXCLUDED.published_on",
                (int(g.get("groupId") or 0),
                 g.get("name") or "",
                 g.get("abbreviation") or "",
                 g.get("publishedOn") or ""),
            )
        db.commit(); db.close()
    except Exception as e:
        try: db.close()
        except Exception: pass
        log.warning("[tcgcsv] groups DB persist failed: %s", e)
    return groups


def _tcgcsv_refresh_group_prices(session, group_id: int) -> int:
    """Download ProductsAndPrices for one group; upsert into tcgcsv_prices.
    Returns number of rows written."""
    try:
        resp = session.get(
            f"{_TCGCSV_BASE}/{group_id}/ProductsAndPrices.csv", timeout=30
        )
        if resp.status_code != 200:
            return 0
        text = resp.text
    except Exception as e:
        log.debug("[tcgcsv] group %s fetch failed: %s", group_id, e)
        return 0

    rows = list(csv.DictReader(io.StringIO(text)))
    if not rows:
        return 0
    now = _now_ms()
    written = 0
    try:
        db = _direct_db()
        for r in rows:
            try:
                pid = int(r.get("productId") or r.get("ProductId") or 0)
                if not pid:
                    continue
                name   = (r.get("name") or r.get("Name") or "").strip()
                number = (r.get("extNumber") or r.get("Number") or "").strip()
                sub    = (r.get("subTypeName") or r.get("SubTypeName") or "").strip()
                mkt    = _safe_float(r.get("marketPrice")  or r.get("MarketPrice"), 0)
                low    = _safe_float(r.get("lowPrice")     or r.get("LowPrice"),    0)
                mid    = _safe_float(r.get("midPrice")     or r.get("MidPrice"),    0)
                high   = _safe_float(r.get("highPrice")    or r.get("HighPrice"),   0)
                if mkt <= 0 and mid <= 0 and low <= 0:
                    continue
                db.execute(
                    "INSERT INTO tcgcsv_prices "
                    "(product_id, group_id, name, name_norm, number, sub_type_name, "
                    " market_price, low_price, mid_price, high_price, fetched_ms) "
                    "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) "
                    "ON CONFLICT (product_id) DO UPDATE SET "
                    "  market_price=EXCLUDED.market_price, low_price=EXCLUDED.low_price, "
                    "  mid_price=EXCLUDED.mid_price, high_price=EXCLUDED.high_price, "
                    "  fetched_ms=EXCLUDED.fetched_ms",
                    (pid, group_id, name, _tcgcsv_norm(name), number, sub,
                     mkt, low, mid, high, now),
                )
                written += 1
            except Exception:
                continue
        db.commit(); db.close()
    except Exception as e:
        try: db.close()
        except Exception: pass
        log.warning("[tcgcsv] group %s persist failed: %s", group_id, e)
    return written


def _tcgcsv_lookup_price(card_name: str, set_abbr: str = "",
                         number: str = "") -> float | None:
    """Fast-path market price lookup from the local TCGCSV snapshot.
    Match: same group abbreviation AND (same number OR fuzzy name match).
    Returns the market price (or mid/low fallback) in USD, or None if no hit."""
    if not card_name:
        return None
    name_norm = _tcgcsv_norm(card_name)
    if not name_norm:
        return None
    try:
        db = _direct_db()
        params: list = [name_norm]
        sql = (
            "SELECT p.market_price, p.mid_price, p.low_price, p.number, g.abbreviation "
            "FROM tcgcsv_prices p "
            "LEFT JOIN tcgcsv_groups g ON g.group_id = p.group_id "
            "WHERE p.name_norm = %s "
        )
        if set_abbr:
            sql += "AND (g.abbreviation ILIKE %s OR g.name ILIKE %s) "
            params += [set_abbr, f"%{set_abbr}%"]
        if number:
            num = number.lstrip("0") or "0"
            sql += "AND (p.number = %s OR p.number = %s) "
            params += [number, num]
        sql += "ORDER BY p.market_price DESC LIMIT 1"
        row = db.execute(sql, tuple(params)).fetchone()
        db.close()
        if not row:
            return None
        for k in ("market_price", "mid_price", "low_price"):
            v = _safe_float(row.get(k), 0)
            if v > 0:
                return v
    except Exception as e:
        log.debug("[tcgcsv] lookup failed for %r: %s", card_name, e)
        try: db.close()
        except Exception: pass
    return None


def _run_tcgcsv_refresh(group_cap: int = 60):
    """Refresh the TCGCSV snapshot. Caps groups per run so a single bad night
    can't hammer them — defaults to 60 groups (≈ all of Pokémon in 4-5 nights)."""
    if os.environ.get("DISABLE_BG_TCGCSV") == "1":
        log.info("[tcgcsv] disabled via env"); return
    if not _tcgcsv_lock.acquire(blocking=False):
        log.info("[tcgcsv] refresh already in progress, skipping")
        return
    started = _now_ms()
    try:
        s = _tcg_session()
        groups = _tcgcsv_refresh_groups(s)
        if not groups:
            log.warning("[tcgcsv] no groups returned; aborting refresh")
            return
        # Pick groups that haven't been refreshed in the last 6 days, oldest-first
        try:
            db = _direct_db()
            pending = db.execute(
                "SELECT g.group_id, COALESCE(MAX(p.fetched_ms), 0) AS last_fetched "
                "FROM tcgcsv_groups g LEFT JOIN tcgcsv_prices p ON p.group_id = g.group_id "
                "GROUP BY g.group_id "
                "HAVING COALESCE(MAX(p.fetched_ms), 0) < %s "
                "ORDER BY last_fetched ASC LIMIT %s",
                (_now_ms() - 6 * 86_400_000, group_cap),
            ).fetchall()
            db.close()
        except Exception as e:
            log.warning("[tcgcsv] pending-groups query failed: %s", e)
            return

        from concurrent.futures import ThreadPoolExecutor as _TPE
        total_rows = 0
        with _TPE(max_workers=4) as pool:
            results = list(pool.map(
                lambda gid: _tcgcsv_refresh_group_prices(s, gid),
                [int(r["group_id"]) for r in pending],
            ))
        total_rows = sum(results)
        elapsed = (_now_ms() - started) / 1000
        log.info("[tcgcsv] refreshed %d groups, %d price rows in %.1fs",
                 len(pending), total_rows, elapsed)
    finally:
        _tcgcsv_lock.release()


_tcgcsv_scheduler_started = False
_tcgcsv_scheduler_lock    = threading.Lock()


def _start_tcgcsv_scheduler():
    """Kick off a daily TCGCSV refresh (24 h interval). First run after 4 min.
    Singleton-guarded — repeated calls (e.g. from post_fork retries) are no-ops."""
    if os.environ.get("DISABLE_BG_TCGCSV") == "1":
        log.info("[bg] tcgcsv scheduler disabled via env"); return
    global _tcgcsv_scheduler_started
    with _tcgcsv_scheduler_lock:
        if _tcgcsv_scheduler_started:
            log.debug("[tcgcsv] scheduler already running, skipping duplicate start")
            return
        _tcgcsv_scheduler_started = True
    def _loop():
        _time.sleep(240)
        while True:
            try:
                _run_tcgcsv_refresh()
            except Exception as e:
                log.warning("[tcgcsv] scheduler iteration failed: %s", e)
            _time.sleep(24 * 3600)
    threading.Thread(target=_loop, daemon=True, name="tcgcsv-refresh").start()
    log.info("[tcgcsv] daily refresh scheduler started")

