def get_db() -> _PgConn:
    """Return a per-request PostgreSQL connection (from pool) stored on Flask's g."""
    if "db" not in g:
        g.db = _PgConn(_get_pool().getconn())
    return g.db


@app.teardown_appcontext
def close_db(exc):
    db = g.pop("db", None)
    if db is not None:
        if exc:
            db.rollback()
        db.close()


_NOW_MS_PG = "(EXTRACT(EPOCH FROM NOW()) * 1000)::BIGINT"


# ---------------------------------------------------------------------------
# Pricing engine  (ported from Card-Scanner-AI shared/schema.ts)
# ---------------------------------------------------------------------------

_LANGUAGE_PRICE_RULES: dict = {
    # Per the canonical pricing spec: KR sells at 55% of EN, JP at 80% of EN.
    # Any change here MUST also update test_pricing_rules.py, which pins the
    # values so the spec can't silently drift again (regression caught on
    # 2026-04-30 — code had KR=0.40 / JP=0.55).
    "English": 1.0,   "EN": 1.0,
    "Japanese": 0.80, "JP": 0.80,
    "Korean": 0.55,   "KR": 0.55,
}
_ITEM_TYPE_UNDERCUT: dict = {
    "Single": 0.95,
    "Sealed": 0.97,
    "Graded": 1.10,
}
_GRADE_MULTIPLIER: dict = {
    "10": 2.5, "9.5": 1.9, "9": 1.5, "8.5": 1.25, "8": 1.0,
}
_ROUNDING_RULES: list = [(5, 0.25), (20, 0.50), (100, 1.00), (9999, 5.00)]


def _round_price(price: float) -> float:
    for limit, step in _ROUNDING_RULES:
        if price <= limit:
            return round(round(price / step) * step, 2)
    return round(price, 2)


def _calculate_final_price(base: float, language: str = "English",
                            item_type: str = "Single", grade: str = "") -> float:
    """Apply language discount, grade premium, item-type undercut, then round."""
    p = base * _LANGUAGE_PRICE_RULES.get(language, 1.0)
    if grade:
        p *= _GRADE_MULTIPLIER.get(grade, 1.0)
    p *= _ITEM_TYPE_UNDERCUT.get(item_type, 1.0)
    return _round_price(p)


def _db_auth_preflight(max_wait_s: int = 30):
    """Fail-fast DB auth probe. Distinguishes auth errors (exit immediately,
    operator intervention required) from transient connect errors (retry until
    timeout). Prevents the silent /health 500 loop seen when DB volume password
    drifts out of sync with the app's credentials.
    """
    import sys, time as _t
    deadline = _t.time() + max_wait_s
    last_err = None
    while _t.time() < deadline:
        try:
            conn = _direct_db()
            try:
                conn.execute("SELECT 1")
            finally:
                try: conn.close()
                except Exception: pass
            log.info("[init] DB auth preflight OK")
            return
        except psycopg2.OperationalError as e:
            msg = str(e).lower()
            last_err = e
            if "password authentication failed" in msg or "role" in msg and "does not exist" in msg:
                log.error("[init] FATAL DB AUTH FAILURE: %s", e)
                log.error("[init] DB volume credentials are out of sync with app config.")
                log.error("[init] Fix: docker exec -u postgres <db-container> psql -U <user> -d <db> "
                          "-c \"ALTER USER <user> WITH PASSWORD '<pwd>';\"")
                sys.exit(2)
            log.warning("[init] DB not ready yet (%s) — retrying", e.__class__.__name__)
            _t.sleep(2)
        except Exception as e:
            last_err = e
            log.warning("[init] DB preflight unexpected error: %s — retrying", e)
            _t.sleep(2)
    log.error("[init] FATAL: DB unreachable after %ss: %s", max_wait_s, last_err)
    sys.exit(3)


