@app.route("/admin/multi/<game>/visual/rebuild", methods=["POST"])
def multi_visual_rebuild(game: str):
    if not _kr_admin_authorized(request):
        return jsonify({"error": "unauthorized"}), 401
    try:
        import multi_tcg_visual, threading
        # Build in background — embedding thousands of images takes minutes
        threading.Thread(
            target=lambda: multi_tcg_visual.build_index(
                _direct_db(), game.lower(), force=True),
            name=f"multi-visual-{game}", daemon=True).start()
        return jsonify({"game": game, "started": True,
                        "note": "build runs in background; poll /status"})
    except Exception as exc:
        return jsonify({"error": str(exc)}), 500


@app.route("/admin/errors", methods=["GET"])
@require_admin
def admin_errors():
    """Tail of recent WARNING+ log records — saves SSH'ing to the Pi for
    every glitch. Returns JSON when ?format=json, otherwise an HTML page."""
    level_filter = (request.args.get("level") or "").upper().strip()
    limit = max(1, min(500, _safe_int(request.args.get("limit"), 200)))
    rows = list(_ERROR_RING)[-limit:]
    if level_filter:
        rows = [r for r in rows if r["level"] == level_filter]
    rows.reverse()  # newest first

    if (request.args.get("format") or "").lower() == "json":
        return jsonify({"count": len(rows), "rows": rows})

    def _row_html(r):
        color = {"ERROR": "#f87171", "WARNING": "#facc15",
                 "CRITICAL": "#dc2626"}.get(r["level"], "#aaa")
        ts = datetime.datetime.fromtimestamp(r["ts"] / 1000).strftime("%H:%M:%S")
        msg = (r["msg"] or "").replace("<", "&lt;").replace(">", "&gt;")
        return (f'<tr><td style="color:#666">{ts}</td>'
                f'<td style="color:{color};font-weight:600">{r["level"]}</td>'
                f'<td><pre style="margin:0;white-space:pre-wrap;'
                f'font-family:ui-monospace,monospace;font-size:12px;'
                f'color:#ddd">{msg}</pre></td></tr>')

    body_rows = "".join(_row_html(r) for r in rows) or (
        '<tr><td colspan="3" style="text-align:center;color:#555;'
        'padding:40px">No warnings or errors in buffer 🎉</td></tr>'
    )
    return f"""<!DOCTYPE html><html><head><meta charset="utf-8">
<title>Recent Errors — HanryxVault</title>
<meta http-equiv="refresh" content="10">
<style>
  body{{background:#0a0a0a;color:#eee;font-family:system-ui,sans-serif;
       margin:0;padding:24px}}
  h1{{color:#facc15;margin:0 0 6px;font-size:22px}}
  .meta{{color:#666;font-size:12px;margin-bottom:18px}}
  .links a{{color:#60a5fa;text-decoration:none;margin-right:14px;font-size:13px}}
  table{{width:100%;border-collapse:collapse;margin-top:16px}}
  td{{padding:6px 10px;vertical-align:top;border-bottom:1px solid #181818;
     font-size:13px}}
  th{{text-align:left;padding:8px 10px;color:#666;font-size:11px;
     text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid #222}}
</style></head>
<body>
  <h1>⚠️ Recent Errors & Warnings</h1>
  <div class="meta">Live ring buffer (last {len(_ERROR_RING)} of 500). Auto-refreshes every 10 s.</div>
  <div class="links">
    <a href="/admin/errors">All</a>
    <a href="/admin/errors?level=ERROR">ERROR only</a>
    <a href="/admin/errors?level=WARNING">WARNING only</a>
    <a href="/admin/errors?format=json">JSON</a>
    <a href="/admin">← Admin</a>
  </div>
  <table>
    <thead><tr><th>Time</th><th>Level</th><th>Message</th></tr></thead>
    <tbody>{body_rows}</tbody>
  </table>
</body></html>"""


@app.route("/admin/monitor-stats", methods=["GET"])
def admin_monitor_stats():
    """JSON dashboard for the desktop monitor (Windows + Pi). No auth required on LAN."""
    db = get_db()
    midnight = int(datetime.datetime.combine(
        datetime.date.today(), datetime.time.min
    ).timestamp() * 1000)

    today = db.execute("""
        SELECT COUNT(*) as cnt,
               COALESCE(SUM(total_amount),0) as rev,
               COALESCE(SUM(tip_amount),0)   as tips
        FROM sales WHERE timestamp_ms >= ?
    """, (midnight,)).fetchone()

    total_sales   = db.execute("SELECT COUNT(*) FROM sales").fetchone()[0]
    inv_count     = db.execute("SELECT COUNT(*) FROM inventory").fetchone()[0]
    low_stock     = db.execute(
        "SELECT COUNT(*) FROM inventory WHERE stock <= 5 AND stock > 0"
    ).fetchone()[0]
    out_stock     = db.execute(
        "SELECT COUNT(*) FROM inventory WHERE stock = 0"
    ).fetchone()[0]
    pending_scans = db.execute(
        "SELECT COUNT(*) FROM scan_queue WHERE processed=0"
    ).fetchone()[0]

    open_trade_ins = 0
    try:
        open_trade_ins = db.execute(
            "SELECT COUNT(*) FROM trade_ins WHERE status='open'"
        ).fetchone()[0]
    except Exception:
        pass

    open_laybys = 0
    layby_outstanding = 0.0
    try:
        r = db.execute("""
            SELECT COUNT(*),
                   COALESCE(SUM(total_amount - paid_amount), 0)
            FROM laybys WHERE status='active'
        """).fetchone()
        open_laybys       = r[0]
        layby_outstanding = float(r[1])
    except Exception:
        pass

    open_pos = 0
    try:
        open_pos = db.execute(
            "SELECT COUNT(*) FROM purchase_orders WHERE status IN ('draft','ordered')"
        ).fetchone()[0]
    except Exception:
        pass

    eod_today = False
    try:
        eod_today = bool(db.execute(
            "SELECT 1 FROM eod_reconciliations WHERE date_str=? LIMIT 1",
            (datetime.date.today().isoformat(),)
        ).fetchone())
    except Exception:
        pass

    period_ms  = midnight - (30 * 86400 * 1000)
    pl_revenue = 0.0
    pl_cogs    = 0.0
    try:
        rows = db.execute("""
            SELECT si.quantity, si.unit_price, i.purchase_price
            FROM sale_items si
            JOIN sales s ON s.id = si.sale_id
            LEFT JOIN inventory i ON i.qr_code = si.qr_code
            WHERE s.timestamp_ms >= ?
        """, (period_ms,)).fetchall()
        for r in rows:
            pl_revenue += float(r[1] or 0) * int(r[0] or 0)
            pl_cogs    += float(r[2] or 0) * int(r[0] or 0)
    except Exception:
        pass
    pl_profit = pl_revenue - pl_cogs
    pl_margin = round(pl_profit / pl_revenue * 100, 1) if pl_revenue > 0 else 0.0

    db_size_mb = 0.0
    try:
        row = db.execute("SELECT pg_database_size(current_database())").fetchone()
        if row:
            db_size_mb = round(row[0] / (1024 * 1024), 2)
    except Exception:
        pass

    return jsonify({
        "today_sales":       today["cnt"],
        "today_revenue":     round(float(today["rev"]), 2),
        "today_tips":        round(float(today["tips"]), 2),
        "total_sales":       total_sales,
        "inv_count":         inv_count,
        "low_stock":         low_stock,
        "out_stock":         out_stock,
        "pending_scans":     pending_scans,
        "open_trade_ins":    open_trade_ins,
        "open_laybys":       open_laybys,
        "layby_outstanding": round(layby_outstanding, 2),
        "open_pos":          open_pos,
        "eod_today":         eod_today,
        "pl_30d_revenue":    round(pl_revenue, 2),
        "pl_30d_cogs":       round(pl_cogs, 2),
        "pl_30d_profit":     round(pl_profit, 2),
        "pl_30d_margin":     pl_margin,
        "db_size_mb":        db_size_mb,
        "uptime_s":          int(_time.time() - _server_start_time),
    })


