def _jpn_card_lookup(db, *, name: str = "", set_code: str = "",
                     card_num: str = "", limit: int = 10) -> list:
    """Look up Japanese cards in cards_jpn (PokeScraper output)."""
    name = (name or "").strip()
    set_code = (set_code or "").strip()
    card_num = (card_num or "").strip()
    if not (name or set_code or card_num):
        return []

    where, params = [], []
    if name:
        # match either the JP or EN name
        where.append("(name_jp ILIKE %s OR name_en ILIKE %s)")
        params.extend([f"%{name}%", f"%{name}%"])
    if set_code:
        where.append("(UPPER(set_code) = %s OR UPPER(set_name) ILIKE %s)")
        params.extend([set_code.upper(), f"%{set_code}%"])
    if card_num:
        where.append("split_part(card_number, '/', 1) = %s")
        params.append(card_num.lstrip("0") or "0")

    sql = (
        "SELECT url, set_code, set_name, card_number, name_en, name_jp, "
        "       rarity, image_url FROM cards_jpn "
        "WHERE " + " AND ".join(where) + " ORDER BY imported_at DESC LIMIT %s"
    )
    params.append(int(limit))

    try:
        rows = db.execute(sql, params).fetchall()
    except Exception as exc:
        log.warning("[jpn-lookup] query failed: %s", exc)
        try: db.rollback()
        except Exception: pass
        return []

    out = []
    for r in rows:
        out.append({
            "id":          f"{r[1]}-{r[3]}" if r[1] else r[0],
            "setCode":     r[1] or "",
            "set_code":    r[1] or "",
            "setName":     r[2],
            "cardNumber":  (r[3] or "").split("/")[0],
            "card_number": (r[3] or "").split("/")[0],
            "name":        r[5] or r[4],   # prefer JP name
            "name_en":     r[4],
            "name_jp":     r[5],
            "rarity":      r[6],
            "imageUrl":    r[7],
            "image_url":   r[7],
            "language":    "Japanese",
            "source":      "PokeScraper_3.0",
            "url":         r[0],
            "price":       0,
        })
    return out


def _jpn_pocket_card_lookup(db, *, name: str = "", set_code: str = "",
                             card_num: str = "", limit: int = 10) -> list:
    """Look up cards in cards_jpn_pocket (Pocket app dataset)."""
    name = (name or "").strip()
    set_code = (set_code or "").strip().upper()
    card_num = (card_num or "").strip().lstrip("0")
    if not (name or set_code or card_num):
        return []

    where, params = [], []
    if name:
        where.append("name ILIKE %s"); params.append(f"%{name}%")
    if set_code:
        where.append("UPPER(set_code) = %s"); params.append(set_code)
    if card_num:
        where.append("card_number = %s"); params.append(int(card_num) if card_num.isdigit() else 0)

    sql = (
        "SELECT set_code, card_number, name, rarity, image_url, packs "
        "FROM cards_jpn_pocket WHERE " + " AND ".join(where) + " "
        "ORDER BY set_code, card_number LIMIT %s"
    )
    params.append(int(limit))

    try:
        rows = db.execute(sql, params).fetchall()
    except Exception as exc:
        log.warning("[jpn-pocket-lookup] query failed: %s", exc)
        try: db.rollback()
        except Exception: pass
        return []

    out = []
    for r in rows:
        out.append({
            "id":          f"{r[0]}-{r[1]}",
            "setCode":     r[0],
            "set_code":    r[0],
            "cardNumber":  str(r[1]),
            "card_number": str(r[1]),
            "name":        r[2],
            "rarity":      r[3],
            "imageUrl":    r[4],
            "image_url":   r[4],
            "packs":       r[5],
            "language":    "Japanese (Pocket)",
            "source":      "pokemon-tcg-pocket-database",
            "price":       0,
        })
    return out


def _multi_card_lookup(db, *, game: str, name: str = "", set_code: str = "",
                       card_num: str = "", limit: int = 10) -> list:
    """Look up cards in cards_multi for a specific game (mtg/onepiece/lorcana/dbs)."""
    game = (game or "").strip().lower()
    if game not in ("mtg", "onepiece", "lorcana", "dbs"):
        return []
    name = (name or "").strip()
    set_code = (set_code or "").strip().upper()
    card_num = (card_num or "").strip().lstrip("0")
    if not (name or set_code or card_num):
        return []

    where = ["game = %s"]
    params: list = [game]
    if name:
        where.append("name ILIKE %s"); params.append(f"%{name}%")
    if set_code:
        where.append("(UPPER(set_code) = %s OR UPPER(set_name) ILIKE %s)")
        params.extend([set_code, f"%{set_code}%"])
    if card_num:
        # collector_number can be "001" or "1" — strip the leading-zero comparison
        where.append("regexp_replace(card_number, '^0+', '') = %s")
        params.append(card_num or "0")

    sql = (
        "SELECT card_id, name, set_code, set_name, card_number, rarity, "
        "       image_url, language, price_usd FROM cards_multi "
        "WHERE " + " AND ".join(where) + " "
        "ORDER BY set_code, card_number LIMIT %s"
    )
    params.append(int(limit))

    try:
        rows = db.execute(sql, params).fetchall()
    except Exception as exc:
        log.warning("[multi-lookup:%s] query failed: %s", game, exc)
        try: db.rollback()
        except Exception: pass
        return []

    pretty = {"mtg": "Magic: The Gathering", "onepiece": "One Piece TCG",
              "lorcana": "Disney Lorcana",     "dbs": "Dragon Ball Super CG"}
    out = []
    for r in rows:
        out.append({
            "id":          r[0],
            "name":        r[1],
            "setCode":     r[2], "set_code":    r[2],
            "setName":     r[3],
            "cardNumber":  r[4], "card_number": r[4],
            "rarity":      r[5],
            "imageUrl":    r[6], "image_url":   r[6],
            "language":    r[7],
            "price":       float(r[8]) if r[8] is not None else 0,
            "price_usd":   float(r[8]) if r[8] is not None else None,
            "game":        game,
            "source":      pretty.get(game, game),
        })
    return out


def _run_multi_import_safely(game: str) -> None:
    """Background-thread entry point for One Piece / Lorcana / etc imports."""
    try:
        import import_multi_tcg
        fn = import_multi_tcg.IMPORTERS.get(game)
        if not fn:
            log.warning("[multi-import] unknown game: %s", game)
            return
        conn = _direct_db()
        try:
            result = fn(conn, force=False)
            log.info("[multi-import:%s] background result: %s", game, result)
        finally:
            try: conn.close()
            except Exception: pass
    except Exception as exc:
        log.warning("[multi-import:%s] failed: %s", game, exc, exc_info=True)


