# ---------------------------------------------------------------------------
# Multi-language OCR endpoint — accepts an image upload, recognises EN/KO/JA/ZH
# text via Tesseract, then routes the recognised text through the appropriate
# language-specific lookup (cards_kr / cards_chs / inventory).
# ---------------------------------------------------------------------------

def _ocr_preprocess(img):
    """
    Image-preprocessing pipeline to wring more accuracy out of Tesseract.

    Steps (each is best-effort, individual failures are swallowed):
      1. EXIF auto-orientation                         (PIL.ImageOps.exif_transpose)
      2. Detect rotation via Tesseract OSD if needed   (image_to_osd)
      3. Upscale tiny images so x-height ≥ ~30 px      (LANCZOS resample)
      4. Grayscale + contrast & sharpness boost
      5. Light unsharp-mask denoise

    Returns a new PIL.Image; never raises (logs and returns the original
    image if anything goes sideways).
    """
    from PIL import Image, ImageOps, ImageEnhance, ImageFilter
    try:
        img = ImageOps.exif_transpose(img)
    except Exception:
        pass

    # OSD-based rotation only kicks in when EXIF didn't help (most camera
    # uploads from the kiosk/tablet have no EXIF).
    try:
        import pytesseract
        osd = pytesseract.image_to_osd(img)
        m = re.search(r"Rotate:\s*(\d+)", osd)
        if m:
            angle = int(m.group(1))
            if angle in (90, 180, 270):
                img = img.rotate(-angle, expand=True)
    except Exception:
        pass  # OSD requires the `osd` traineddata; fall through if missing

    # Upscale small images — Tesseract wants character height ≥ ~30 px.
    w, h = img.size
    if max(w, h) < 1200:
        scale = 1200 / max(w, h)
        img = img.resize((int(w * scale), int(h * scale)), Image.LANCZOS)

    # Grayscale + enhance
    img = img.convert("L")
    img = ImageEnhance.Contrast(img).enhance(1.4)
    img = ImageEnhance.Sharpness(img).enhance(1.6)
    img = img.filter(ImageFilter.UnsharpMask(radius=1.2, percent=130, threshold=3))
    return img


@app.route("/card/scan/image", methods=["POST"])
def card_scan_image():
    """
    OCR-based card scan.

    Accepts:
      - multipart/form-data with field `image` (a JPEG/PNG card photo), OR
      - JSON body `{"image_b64": "<base64>"}`
      - optional `lang` query param to force a language (eng/kor/jpn/chi_sim)
      - optional `limit` query param (default 10, max 50)

    Returns:
      {
        "recognized_text": "...",     # raw Tesseract output
        "candidate":       "...",     # the line we used for lookup (longest)
        "scripts":         [...],     # detected scripts: hangul/cjk/kana/latin
        "results":         [...],     # ranked card matches (same shape as
                                       # /card/lookup)
        "count":           N,
      }
    """
    try:
        import pytesseract
        from PIL import Image
    except ImportError as exc:
        return jsonify({"error": f"OCR dependencies missing: {exc}"}), 500

    # ── 1. Read the uploaded image ───────────────────────────────────────────
    img = None
    upload = request.files.get("image")
    if upload is not None and upload.filename:
        try:
            img = Image.open(upload.stream)
        except Exception as exc:
            return jsonify({"error": f"could not open image: {exc}"}), 400
    else:
        body = request.get_json(silent=True) or {}
        b64 = body.get("image_b64") or body.get("image")
        if b64:
            import base64, io
            try:
                if "," in b64 and b64.startswith("data:"):
                    b64 = b64.split(",", 1)[1]
                img = Image.open(io.BytesIO(base64.b64decode(b64)))
            except Exception as exc:
                return jsonify({"error": f"bad image_b64: {exc}"}), 400

    if img is None:
        return jsonify({
            "error": "no image provided. POST multipart 'image' field "
                     "or JSON {'image_b64': '...'}"
        }), 400

    # Convert to RGB to satisfy Tesseract on RGBA / palette images
    if img.mode not in ("RGB", "L"):
        img = img.convert("RGB")

    # ── 1b. Pre-process to maximise OCR accuracy ─────────────────────────────
    # Auto-orient via EXIF, then run a small enhance pipeline (upscale small
    # photos, grayscale, contrast/sharpness boost, light denoise).  Tesseract's
    # OSD pass gives us a real rotation angle when EXIF is missing.
    if request.args.get("preprocess", "1") != "0":
        try:
            img = _ocr_preprocess(img)
        except Exception as _pp_err:
            log.info("[ocr] preprocess skipped: %s", _pp_err)

    # ── 2. Pick OCR languages ────────────────────────────────────────────────
    forced = (request.args.get("lang") or "").strip().lower()
    lang_map = {
        "en": "eng", "eng": "eng",
        "kr": "kor", "kor": "kor", "ko": "kor",
        "jp": "jpn", "jpn": "jpn", "ja": "jpn",
        "zh": "chi_sim", "chs": "chi_sim", "chi_sim": "chi_sim",
    }
    if forced in lang_map:
        ocr_langs = lang_map[forced]
    else:
        # Run multi-language pass — Tesseract is decent at picking the right
        # script when several langs are loaded together
        ocr_langs = "eng+kor+jpn+chi_sim"

    # ── 3. Run Tesseract — with confidence-based retry ───────────────────────
    # First pass uses image_to_data so we can read a per-word confidence score.
    # If the mean confidence is < 50, we retry with a single forced language
    # picked from whichever script the (low-confidence) text contains the most
    # of — Tesseract is markedly more accurate when given one language at a time.
    try:
        data = pytesseract.image_to_data(
            img, lang=ocr_langs, output_type=pytesseract.Output.DICT)
        words = [w for w in data.get("text", []) if w and w.strip()]
        confs = [int(c) for c in data.get("conf", [])
                 if str(c).lstrip("-").isdigit() and int(c) >= 0]
        text = " ".join(words).strip()
        mean_conf = round(sum(confs) / len(confs), 1) if confs else 0.0

        if mean_conf < 50 and len(ocr_langs) > 4:
            # Score scripts in the low-confidence text and retry with the winner
            scores = {
                "kor":     sum(1 for c in text if _has_hangul(c)),
                "jpn":     sum(1 for c in text if _has_kana(c)),
                "chi_sim": sum(1 for c in text if _has_cjk(c)
                               and not _has_kana(c) and not _has_hangul(c)),
                "eng":     sum(1 for c in text if c.isascii() and c.isalpha()),
            }
            winner = max(scores, key=scores.get) if any(scores.values()) else None
            if winner and winner != ocr_langs:
                retry = pytesseract.image_to_string(img, lang=winner).strip()
                if retry and len(retry) >= len(text):
                    log.info("[ocr] retry lang=%s improved (%.1f → ?)",
                             winner, mean_conf)
                    text = retry; ocr_langs = winner
    except pytesseract.TesseractError as exc:
        return jsonify({"error": f"tesseract failed: {exc}",
                        "lang": ocr_langs}), 500
    except Exception:
        # If image_to_data isn't supported, fall back to simple string mode
        try:
            text = pytesseract.image_to_string(img, lang=ocr_langs).strip()
            mean_conf = None
        except pytesseract.TesseractError as exc:
            return jsonify({"error": f"tesseract failed: {exc}",
                            "lang": ocr_langs}), 500

    # ── 4. Detect scripts and pick a candidate line ──────────────────────────
    scripts = []
    if _has_hangul(text): scripts.append("hangul")
    if _has_kana(text):   scripts.append("kana")
    if _has_cjk(text):    scripts.append("cjk")
    if any((c.isascii() and c.isalpha()) for c in text): scripts.append("latin")

    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    # Prefer lines that contain Asian characters when present (card name is
    # usually one of the largest pieces of text on the card)
    def _line_score(ln: str) -> tuple:
        return (
            _has_hangul(ln) or _has_kana(ln) or _has_cjk(ln),
            len(ln),
        )
    candidate = max(lines, key=_line_score, default="") if lines else ""

    try:
        limit = min(_safe_int(request.args.get("limit", 10), 10), 50)
    except (ValueError, TypeError):
        limit = 10

    # ── 5. Route to the right lookup based on detected script ────────────────
    db = get_db()
    results: list = []

    if candidate:
        if "hangul" in scripts:
            results = _kr_card_lookup(db, name=candidate, limit=limit)
        elif "kana" in scripts:
            # Japanese — no JP table yet, fall through to English/general
            results = _card_lookup(db, q=candidate, limit=limit)
        elif "cjk" in scripts:
            results = _chs_card_lookup(db, name=candidate, limit=limit)

        # Always also try the general English lookup — many Asian cards print
        # the English name underneath
        if not results:
            results = _card_lookup(db, q=candidate, limit=limit)

    return jsonify({
        "recognized_text": text,
        "candidate":       candidate,
        "scripts":         scripts,
        "ocr_lang":        ocr_langs,
        "results":         results,
        "count":           len(results),
    })


def _kr_admin_authorized(req) -> bool:
    """Check ADMIN_TOKEN env var against either ?token=... or X-Admin-Token header."""
    expected = (os.environ.get("ADMIN_TOKEN") or "").strip()
    if not expected:
        # No admin token configured → only allow from localhost
        remote = (req.remote_addr or "")
        return remote in ("127.0.0.1", "::1", "localhost")
    provided = (req.args.get("token")
                or req.headers.get("X-Admin-Token")
                or "").strip()
    return bool(provided) and provided == expected


