@app.route("/admin/en-cards/status", methods=["GET"])
def en_cards_status():
    """Quick check on EN catalogue coverage.

    EN doesn't have a dedicated `cards_en` table — EN data lives in
    cards_master.name_en. This endpoint reports:
      * how many cards_master rows have a non-empty name_en
      * how many EN rows TCGdex provides as the canonical (src_tcgdex_multi
        with `names ? 'en'`)
      * the most recent en_set_gap roll-up (total missing / extra)
      * a 5-row sample of recently imported EN cards
    Mirrors the kr-cards/status JSON shape so dashboards reuse the same
    parser.
    """
    try:
        db = get_db()
        cnt_row = db.execute(
            "SELECT COUNT(*) FROM cards_master "
            "WHERE name_en IS NOT NULL AND name_en <> ''"
        ).fetchone()
        cnt = int((cnt_row or [0])[0] or 0)

        # Canonical-side count from TCGdex (NULL-safe: table may be empty
        # if import_tcgdex hasn't run yet on this Pi).
        try:
            tcgdex_row = db.execute(
                "SELECT COUNT(*) FROM src_tcgdex_multi WHERE names ? 'en'"
            ).fetchone()
            tcgdex_en_count = int((tcgdex_row or [0])[0] or 0)
        except Exception:
            tcgdex_en_count = 0

        # Latest gap roll-up (single-row aggregate; safe on empty table)
        try:
            gap_row = db.execute(
                "SELECT COALESCE(SUM(expected_count),0), "
                "       COALESCE(SUM(actual_count),0), "
                "       COALESCE(SUM(jsonb_array_length(missing_numbers)),0), "
                "       COALESCE(SUM(jsonb_array_length(extra_numbers)),0), "
                "       COALESCE(MAX(audited_at),0), "
                "       COUNT(*) "
                "FROM en_set_gap"
            ).fetchone()
            gap = {
                "expected_total": int((gap_row or [0])[0] or 0),
                "actual_total":   int((gap_row or [0,0])[1] or 0),
                "missing_total":  int((gap_row or [0,0,0])[2] or 0),
                "extra_total":    int((gap_row or [0,0,0,0])[3] or 0),
                "last_audited_at": int((gap_row or [0,0,0,0,0])[4] or 0),
                "sets_audited":   int((gap_row or [0,0,0,0,0,0])[5] or 0),
            }
        except Exception:
            gap = {"expected_total": 0, "actual_total": 0,
                   "missing_total": 0, "extra_total": 0,
                   "last_audited_at": 0, "sets_audited": 0}

        sample = db.execute(
            "SELECT name_en, set_id, card_number, rarity "
            "FROM cards_master "
            "WHERE name_en IS NOT NULL AND name_en <> '' "
            "ORDER BY last_built DESC LIMIT 5"
        ).fetchall()
        return jsonify({
            "count": cnt,
            "tcgdex_en_count": tcgdex_en_count,
            "gap": gap,
            "sample": [
                {"name": r[0], "set": r[1], "number": r[2], "rarity": r[3]}
                for r in (sample or [])
            ],
        })
    except Exception as exc:
        return jsonify({"error": str(exc), "count": 0}), 500


@app.route("/admin/pipelines/status", methods=["GET"])
def pipelines_status():
    """Aggregated, read-only pipeline status across every catalogue.

    Single-curl shortcut for the per-language verification checklist in
    docs/KR_ZH_VERIFICATION.md. Composes existing helpers and direct SQL
    in one transaction so a dashboard can poll one endpoint instead of
    eight. Strictly read-only — no admin mutation surface introduced.

    Response shape:
      {
        "kr":  {count, gap:{...}},
        "chs": {count, gap_sc:{...}},
        "tc":  {gap_tc:{...}},
        "jpn": {count},
        "en":  {count, tcgdex_en_count, gap:{...}},
        "aliases": {by_match_method:{...}, total},
        "workers": {<worker_name>: {last_status, last_finished_at,
                                    failed_in_queue}, ...}
      }
    Non-fatal: any sub-section that errors out is reported as
    {"error": "<msg>"} so a single bad table doesn't blank the
    whole report.
    """
    db = get_db()
    out: dict = {}

    def _safe_one(sql, default=0):
        try:
            row = db.execute(sql).fetchone()
            return int((row or [default])[0] or default)
        except Exception:
            return default

    def _gap_summary(table: str, where: str = "") -> dict:
        try:
            row = db.execute(
                f"SELECT COALESCE(SUM(expected_count),0), "
                f"       COALESCE(SUM(actual_count),0), "
                f"       COALESCE(SUM(jsonb_array_length(missing_numbers)),0), "
                f"       COALESCE(SUM(jsonb_array_length(extra_numbers)),0), "
                f"       COALESCE(MAX(audited_at),0), "
                f"       COUNT(*) "
                f"FROM {table} {where}"
            ).fetchone()
            return {
                "expected_total":   int((row or [0])[0] or 0),
                "actual_total":     int((row or [0,0])[1] or 0),
                "missing_total":    int((row or [0,0,0])[2] or 0),
                "extra_total":      int((row or [0,0,0,0])[3] or 0),
                "last_audited_at":  int((row or [0,0,0,0,0])[4] or 0),
                "sets_audited":     int((row or [0,0,0,0,0,0])[5] or 0),
            }
        except Exception as exc:
            return {"error": str(exc)}

    # KR
    try:
        import import_kr_cards
        out["kr"] = {
            "count": import_kr_cards.kr_cards_count(db),
            "gap":   _gap_summary("kr_set_gap"),
        }
    except Exception as exc:
        out["kr"] = {"error": str(exc)}

    # CHS (Simplified Chinese)
    try:
        import import_chs_cards
        out["chs"] = {
            "count":  import_chs_cards.chs_cards_count(db),
            "gap_sc": _gap_summary("zh_set_gap",
                                   "WHERE lang_variant = 'SC'"),
        }
    except Exception as exc:
        out["chs"] = {"error": str(exc)}

    # TC (Traditional Chinese — no dedicated cards table; gap-only view)
    out["tc"] = {
        "gap_tc": _gap_summary("zh_set_gap", "WHERE lang_variant = 'TC'"),
    }

    # JPN
    try:
        import import_jpn_cards
        out["jpn"] = {"count": import_jpn_cards.cards_count(db)}
    except Exception as exc:
        out["jpn"] = {"error": str(exc)}

    # EN
    try:
        out["en"] = {
            "count": _safe_one(
                "SELECT COUNT(*) FROM cards_master "
                "WHERE name_en IS NOT NULL AND name_en <> ''"),
            "tcgdex_en_count": _safe_one(
                "SELECT COUNT(*) FROM src_tcgdex_multi "
                "WHERE names ? 'en'"),
            "gap":   _gap_summary("en_set_gap"),
        }
    except Exception as exc:
        out["en"] = {"error": str(exc)}

    # Cross-region aliases — break out by match_method so the operator
    # can see at a glance how many fell back to 'unmatched'.
    try:
        rows = db.execute(
            "SELECT match_method, COUNT(*) FROM card_alias "
            "GROUP BY match_method"
        ).fetchall() or []
        by_method = {(r[0] or "unknown"): int(r[1] or 0) for r in rows}
        out["aliases"] = {
            "by_match_method": by_method,
            "total": sum(by_method.values()),
        }
    except Exception as exc:
        out["aliases"] = {"error": str(exc)}

    # Worker health: one block per audit + alias worker.
    # bg_worker_run columns are worker_type / started_at / ended_at /
    # items_claimed / items_ok / items_failed / notes — there is no
    # `status` column so we derive 'OK' / 'FAILED' / 'NONE' from the
    # item counters. The string keys here MUST match each Worker
    # subclass's TASK_TYPE constant verbatim (that's what base.py
    # writes into worker_type and what seed() puts into task_type).
    worker_types = (
        "kr_set_audit",
        "zh_set_audit",
        "en_set_audit",
        "cross_region_alias",
    )
    workers: dict = {}
    for wt in worker_types:
        block: dict = {}
        try:
            row = db.execute(
                "SELECT ended_at, items_claimed, items_ok, items_failed, "
                "       COALESCE(notes, '') "
                "FROM bg_worker_run "
                "WHERE worker_type = %s "
                "ORDER BY started_at DESC LIMIT 1",
                (wt,),
            ).fetchone()
            if row:
                ended_at = int(row[0] or 0) if row[0] is not None else 0
                claimed = int(row[1] or 0)
                ok = int(row[2] or 0)
                failed = int(row[3] or 0)
                if ended_at == 0:
                    derived = "RUNNING"
                elif failed > 0 and ok == 0:
                    derived = "FAILED"
                elif failed > 0:
                    derived = "PARTIAL"
                else:
                    derived = "OK"
                block.update({
                    "last_status":      derived,
                    "last_ended_at":    ended_at,
                    "items_claimed":    claimed,
                    "items_ok":         ok,
                    "items_failed":     failed,
                    "last_notes":       (row[4] or "")[:240],
                })
            else:
                block["last_status"] = "NONE"
        except Exception as exc:
            block["error"] = str(exc)
        try:
            block["failed_in_queue"] = _safe_one(
                "SELECT COUNT(*) FROM bg_task_queue "
                f"WHERE task_type = '{wt}' AND status = 'FAILED'"
            )
        except Exception as exc:
            block["failed_in_queue_error"] = str(exc)
        workers[wt] = block
    out["workers"] = workers

    return jsonify(out)


@app.route("/admin/cards/en-match", methods=["GET"])
def admin_cards_en_match():
    """
    Resolve the English-edition equivalent of whatever card the operator
    is currently looking at, so the language-pricing chips on
    /admin/market can render a "matched-as" header strip with the actual
    EN card image, name, set, number, rarity, and artist next to the
    KR/JP/CHS price percentages.

    The booth is intentionally offline-first — see USB_OFFLINE_DB.md.
    Every piece of data this endpoint returns resolves locally:

      * name_en / set_id / card_number / rarity / artist come from
        cards_master in the Pi's Postgres.
      * image_local_url points at the existing /card/image route, which
        already serves USB-mirrored files first and only falls back to
        a network 302 if the image hasn't been mirrored yet.
      * ebay_sold_url is the only network-dependent piece — it's built
        server-side so the URL is always present in the response, but
        the frontend disables the link when navigator.onLine is false
        (or the fetch to eBay's domain fails). The card-search and
        price-display flows must stay fully usable without WiFi.

    Match strategy (most-specific wins, returned in `confidence`):
      1. exact          — set_id + card_number both supplied and matched
      2. name_set       — name fuzzy-match restricted to a known set
      3. name           — name fuzzy-match across cards_master
      4. null           — no row found; frontend renders a placeholder

    Query params:
      name       card name in any language (KR/JP/CHS/EN) — required
                 unless set_id+card_number is fully specified
      set        set code (optional)
      number     collector number, normalised or raw (optional)

    Returns:
      { "match": {name_en, set_id, card_number, rarity, artist,
                  image_local_url, ebay_sold_url, confidence} | null }
    """
    from unified.en_match import resolve_en_match

    name      = (request.args.get("name") or "").strip()
    set_code  = (request.args.get("set")  or "").strip()
    number    = (request.args.get("number") or "").strip()

    if not name and not (set_code and number):
        return jsonify({"error": "name or (set+number) required",
                        "match": None}), 400

    db = None
    try:
        db = _direct_db()
        match = resolve_en_match(db, name, set_code, number)
    except Exception as exc:
        log.exception("[admin/cards/en-match] db lookup failed")
        return jsonify({"error": str(exc), "match": None}), 500
    finally:
        if db is not None:
            try:
                db.close()
            except Exception:
                pass

    return jsonify({"match": match})


# ---------------------------------------------------------------------------
# Operator-curated set-alias workflow
# ---------------------------------------------------------------------------
#
# When /admin/cards/en-match returns set_match='raw' it means the operator
# typed a set name/code we couldn't canonicalise to a ref_set_mapping row.
# Rather than hand-edit JSON on the Pi, the operator hits these two
# endpoints from the booth tablet:
#
#   1. GET  /admin/cards/set-alias-suggest?needle=<text>
#      → top 3 ref_set_mapping rows whose name in *any* of the 5
#        languages is within Levenshtein distance ≤ 2 of <needle>.
#        Each row carries its current aliases array so the operator
#        can see what's already curated before adding a new one.
#
#   2. POST /admin/cards/set-alias-add  {set_id, alias}
#      → idempotent append of <alias> into ref_set_mapping.aliases
#        (case-insensitive dedupe). Returns {added: bool} so the
#        UI can distinguish "newly added" from "already curated".
#
# Both depend on the fuzzystrmatch Postgres extension. The bootstrap
# in init_db best-effort enables it; the suggest endpoint detects the
# missing-function case and returns 503 with a helpful message rather
# than 500'ing.

# Cap needle length before levenshtein() to stay well under the
# 255-byte input limit of fuzzystrmatch (Korean/Japanese chars are
# multi-byte so we cap at 64 source chars).
_ALIAS_NEEDLE_MAX = 100
_ALIAS_LEV_CAP    = 2

_ALIAS_SUGGEST_SQL = """
WITH dist AS (
  SELECT set_id, name_en, name_kr, name_jp, name_chs, name_cht, aliases,
         CASE WHEN COALESCE(name_en,  '') <> ''
              THEN levenshtein(lower(left(%s, 64)), lower(left(name_en,  64)))
              ELSE 999 END AS d_en,
         CASE WHEN COALESCE(name_kr,  '') <> ''
              THEN levenshtein(lower(left(%s, 64)), lower(left(name_kr,  64)))
              ELSE 999 END AS d_kr,
         CASE WHEN COALESCE(name_jp,  '') <> ''
              THEN levenshtein(lower(left(%s, 64)), lower(left(name_jp,  64)))
              ELSE 999 END AS d_jp,
         CASE WHEN COALESCE(name_chs, '') <> ''
              THEN levenshtein(lower(left(%s, 64)), lower(left(name_chs, 64)))
              ELSE 999 END AS d_chs,
         CASE WHEN COALESCE(name_cht, '') <> ''
              THEN levenshtein(lower(left(%s, 64)), lower(left(name_cht, 64)))
              ELSE 999 END AS d_cht
    FROM ref_set_mapping
)
SELECT set_id, name_en, name_kr, name_jp, name_chs, name_cht, aliases,
       LEAST(d_en, d_kr, d_jp, d_chs, d_cht) AS distance,
       CASE LEAST(d_en, d_kr, d_jp, d_chs, d_cht)
            WHEN d_en  THEN 'en'
            WHEN d_kr  THEN 'kr'
            WHEN d_jp  THEN 'jp'
            WHEN d_chs THEN 'chs'
            WHEN d_cht THEN 'cht'
            ELSE 'unknown'
       END AS matched_lang
  FROM dist
 WHERE LEAST(d_en, d_kr, d_jp, d_chs, d_cht) <= %s
 ORDER BY distance ASC, set_id ASC
 LIMIT 3
"""

# Idempotent append: only adds the alias if no existing entry in the
# JSONB array matches case-insensitively. Returns rowcount=1 on add,
# 0 if the alias is already present (or the set_id doesn't exist).
_ALIAS_ADD_SQL = """
UPDATE ref_set_mapping
   SET aliases = COALESCE(aliases, '[]'::jsonb) || jsonb_build_array(%s::text)
 WHERE set_id = %s
   AND NOT EXISTS (
       SELECT 1
         FROM jsonb_array_elements_text(COALESCE(aliases, '[]'::jsonb)) AS a
        WHERE lower(a) = lower(%s)
   )
"""


@app.route("/admin/cards/set-alias-suggest", methods=["GET"])
def admin_cards_set_alias_suggest():
    """
    Suggest the closest ref_set_mapping rows for an unrecognised set
    name/code so the operator can curate it as an alias.

    Query params:
      needle  the unrecognised text the operator just typed — required.

    Returns:
      { "needle": str,
        "suggestions": [
          { "set_id": str, "name_en": str, "name_kr": str, "name_jp": str,
            "name_chs": str, "name_cht": str,
            "current_aliases": [str, ...],
            "distance": int, "matched_lang": "en"|"kr"|"jp"|"chs"|"cht" },
          ... up to 3
        ] }

    Returns 503 (not 500) when the fuzzystrmatch extension is missing,
    so the booth UI can quietly hide the Curate Alias button.
    """
    needle = (request.args.get("needle") or "").strip()
    if not needle:
        return jsonify({"error": "needle required",
                        "suggestions": []}), 400
    if len(needle) > _ALIAS_NEEDLE_MAX:
        return jsonify({"error": f"needle too long (max {_ALIAS_NEEDLE_MAX} chars)",
                        "suggestions": []}), 400

    db = None
    try:
        db = _direct_db()
        cur = db.cursor()
        try:
            cur.execute(_ALIAS_SUGGEST_SQL,
                        (needle, needle, needle, needle, needle, _ALIAS_LEV_CAP))
            rows = cur.fetchall()
        except Exception as exc:
            # Most likely cause: fuzzystrmatch extension not installed
            # on this Postgres image. Roll back the failed txn so the
            # connection is reusable, then return a friendly 503.
            try: db.rollback()
            except Exception: pass
            log.warning("[admin/cards/set-alias-suggest] suggester failed: %s", exc)
            return jsonify({
                "error": ("alias suggester unavailable on this server "
                          "(fuzzystrmatch extension missing or function error)"),
                "detail": str(exc),
                "suggestions": [],
            }), 503

        suggestions = []
        for row in rows:
            (set_id, n_en, n_kr, n_jp, n_chs, n_cht,
             aliases, distance, matched_lang) = row
            # `aliases` comes back as a Python list from psycopg2's
            # JSONB adapter (or None if the column is NULL).
            suggestions.append({
                "set_id":          set_id,
                "name_en":         n_en  or "",
                "name_kr":         n_kr  or "",
                "name_jp":         n_jp  or "",
                "name_chs":        n_chs or "",
                "name_cht":        n_cht or "",
                "current_aliases": list(aliases) if aliases else [],
                "distance":        int(distance),
                "matched_lang":    matched_lang,
            })
        return jsonify({"needle": needle, "suggestions": suggestions})
    except Exception as exc:
        log.exception("[admin/cards/set-alias-suggest] db error")
        return jsonify({"error": str(exc), "suggestions": []}), 500
    finally:
        if db is not None:
            try: db.close()
            except Exception: pass


@app.route("/admin/cards/set-alias-add", methods=["POST"])
def admin_cards_set_alias_add():
    """
    Push <alias> into ref_set_mapping.aliases for <set_id>.

    Body (JSON or form):
      set_id  canonical set_id from ref_set_mapping — required
      alias   the alternate name/code the operator wants curated — required

    Returns:
      { "set_id": str, "alias": str, "added": bool }

    `added` is True only when the alias was newly inserted. If the
    alias was already present (case-insensitive) or the set_id is
    unknown, `added` is False — the caller can use this to show
    "already curated" vs "added" toasts without a second round-trip.
    """
    body = request.get_json(silent=True) or request.form or {}
    set_id = (body.get("set_id") or "").strip()
    alias  = (body.get("alias")  or "").strip()
    if not set_id or not alias:
        return jsonify({"error": "set_id and alias required",
                        "added": False}), 400
    if len(alias) > _ALIAS_NEEDLE_MAX:
        return jsonify({"error": f"alias too long (max {_ALIAS_NEEDLE_MAX} chars)",
                        "added": False}), 400

    db = None
    try:
        db = _direct_db()
        cur = db.cursor()
        cur.execute(_ALIAS_ADD_SQL, (alias, set_id, alias))
        added = bool(cur.rowcount)
        db.commit()
        return jsonify({"set_id": set_id, "alias": alias, "added": added})
    except Exception as exc:
        try:
            if db is not None: db.rollback()
        except Exception: pass
        log.exception("[admin/cards/set-alias-add] db error")
        return jsonify({"error": str(exc), "added": False}), 500
    finally:
        if db is not None:
            try: db.close()
            except Exception: pass


# ---------------------------------------------------------------------------
# Card lookup — fuzzy / multi-field search for Pokémon (and any) cards
# ---------------------------------------------------------------------------

@app.route("/card/lookup", methods=["GET"])
def card_lookup():
    """
    Fuzzy card lookup used by the website and any scanner client.

    Query params (at least one required):
      qr    — raw scanner value (URL or plain code); normalised automatically
      q     — general search string (name fragment, set+number, etc.)
      name  — card name (can be partial)
      set   — set code, e.g. "SV1", "XY3", "BW"
      num   — card number within the set, e.g. "001" or "1"
      limit — max results to return (default 10, max 50)

    Returns:
      {"results": [...], "count": N, "query": {...}}

    Examples:
      GET /card/lookup?q=charizard           → all Charizard cards
      GET /card/lookup?q=SV1-001             → card 1 from Scarlet & Violet base
      GET /card/lookup?qr=https://pokemon.com/...?set=SV1&number=1
      GET /card/lookup?name=pikachu&set=sv1  → Pikachu in SV1
    """
    qr       = request.args.get("qr",    "").strip()
    q        = request.args.get("q",     "").strip()
    name     = request.args.get("name",  "").strip()
    set_code = request.args.get("set",   "").strip().upper()
    card_num = request.args.get("num",   "").strip().lstrip("0")
    try:
        limit = min(_safe_int(request.args.get("limit", 10), 10), 50)
    except (ValueError, TypeError):
        limit = 10

    if not any([qr, q, name, set_code]):
        return jsonify({"error": "Provide at least one of: qr, q, name, set"}), 400

    db      = get_db()
    game    = (request.args.get("game") or "").strip().lower()

    if game in ("mtg", "onepiece", "lorcana", "dbs"):
        # Explicit non-Pokémon TCG lookup — query cards_multi directly and skip
        # the Pokémon-centric lookup pipeline.
        results = _multi_card_lookup(db, game=game, name=(name or q),
                                     set_code=set_code, card_num=card_num,
                                     limit=limit)
    else:
        results = _card_lookup(db, q=q, qr=qr, name=name,
                               set_code=set_code, card_num=card_num, limit=limit)
        # Asian-language fallbacks (Korean / Chinese / JP / Pocket)
        lang = (request.args.get("lang") or "").strip().lower()
        qtext = name or q
        results = _maybe_extend_with_asian(db, results, qtext, set_code,
                                           card_num, limit, lang)

    if request.args.get("kiosk") == "1" and results:
        _kiosk_push_lookup(results[0])

    return jsonify({
        "results": results,
        "count":   len(results),
        "query":   {
            "qr": qr, "q": q, "name": name,
            "set": set_code, "num": card_num,
            "game": game,
        },
    })


@app.route("/card/lookup", methods=["POST"])
def card_lookup_post():
    """
    POST version of /card/lookup — used by the website camera scanner.

    Body (JSON):
      {"qr": "...", "q": "...", "name": "...", "set": "...", "num": "...",
       "limit": 10, "kiosk": true}

    Same response as GET version.
    If kiosk=true, the first result is pushed to the kiosk display.
    """
    body     = request.get_json(silent=True) or {}
    qr       = (body.get("qr")   or "").strip()
    q        = (body.get("q")    or "").strip()
    name     = (body.get("name") or "").strip()
    set_code = (body.get("set")  or "").strip().upper()
    card_num = (body.get("num")  or "").strip().lstrip("0")
    try:
        limit = min(int(body.get("limit", 10)), 50)
    except (ValueError, TypeError):
        limit = 10

    if not any([qr, q, name, set_code]):
        return jsonify({"error": "Provide at least one of: qr, q, name, set"}), 400

    db      = get_db()
    game    = (body.get("game") or "").strip().lower()

    if game in ("mtg", "onepiece", "lorcana", "dbs"):
        results = _multi_card_lookup(db, game=game, name=(name or q),
                                     set_code=set_code, card_num=card_num,
                                     limit=limit)
    else:
        results = _card_lookup(db, q=q, qr=qr, name=name,
                               set_code=set_code, card_num=card_num, limit=limit)
        lang = (body.get("lang") or "").strip().lower()
        qtext = name or q
        results = _maybe_extend_with_asian(db, results, qtext, set_code,
                                           card_num, limit, lang)

    if body.get("kiosk") and results:
        _kiosk_push_lookup(results[0])

    return jsonify({"results": results, "count": len(results)})


def _card_image_src(card: dict, lang: str = "") -> str:
    """
    Pick the best `<img src>` for a card: when we have set_code + card_number,
    route through /card/image so the resolver can serve a local USB file
    (instant, works offline) and fall back to a 302-redirect to the network
    URL only when no mirror exists. Falls back to the raw image URL only if
    we lack the keys to call the resolver.
    """
    set_code = (card.get("setCode") or card.get("set_code")
                or card.get("set_id") or "").strip()
    card_no  = (card.get("cardNumber") or card.get("card_number") or "").strip()
    if set_code and card_no:
        suffix = f"&lang={lang}" if lang else ""
        return f"/card/image?set_id={set_code}&card_number={card_no}{suffix}"
    return (card.get("imageUrl") or card.get("image_url") or "").strip()


def _kiosk_push_lookup(card: dict):
    """Push a card lookup result to the kiosk display for the customer to see."""
    # ── Live price-comparison across Asian + EU sources (best effort) ───────
    # This is what makes the kiosk genuinely useful for a Korean-customer-heavy
    # store: we surface the median USD price and the cheapest-by-region so
    # customers see we're not gouging.  Failure here never blocks the broadcast.
    price_compare: dict = {}
    try:
        import price_scrapers, fx_rates
        q = (card.get("name") or "").strip()
        if q:
            cmp_out = price_scrapers.search_all(q, limit_per_source=3)
            flat: list = []
            for rows in cmp_out.get("results", {}).values():
                rows = fx_rates.normalize_listings(rows)
                flat.extend(rows)
            usd_vals = [r["price_usd"] for r in flat
                        if r.get("price_usd") is not None]
            if usd_vals:
                cheapest = min(flat, key=lambda r: r.get("price_usd") or 9e9)
                price_compare = {
                    "median_usd":   fx_rates.median_usd(flat),
                    "cheapest_usd": cheapest.get("price_usd"),
                    "cheapest_src": cheapest.get("source"),
                    "samples":      len(usd_vals),
                }
    except Exception as _pc_err:
        log.debug("[kiosk-push] price compare skipped: %s", _pc_err)

    _kiosk_broadcast({
        "mode":       "lookup",
        "card_name":  card.get("name", ""),
        "card_price": float(card.get("price") or 0),
        "card_image": _card_image_src(card),
        "card_rarity": card.get("rarity") or "",
        "card_set":   card.get("setCode") or card.get("set_code") or "",
        "card_number": card.get("cardNumber") or card.get("card_number") or "",
        "stock_qty":  int(card.get("stockQuantity") or card.get("quantity") or 0),
        "price_compare": price_compare,
    })


# ---------------------------------------------------------------------------
# Fast scanner endpoint — exact QR match + in-memory cache for real-time use
# ---------------------------------------------------------------------------

@app.route("/card/scan", methods=["GET", "OPTIONS"])
def card_scan_fast():
    """
    Ultra-low-latency QR scan lookup for real-time mobile scanner clients.

    Exact QR match only (no fuzzy search). Results cached in-memory for 5 min
    so repeated scans of the same card respond without any DB hit.

    Supports CORS so the mobile app can call it directly (bypassing the scanner
    server proxy) to eliminate one full network round trip.

    GET /card/scan?qr=SV1-4

    Response matches the LookupResult shape the mobile app expects:
      { found, code, name, sku, description, price, stock, rawResponse }
    """
    # Handle CORS preflight
    if request.method == "OPTIONS":
        resp = app.make_default_options_response()
        resp.headers["Access-Control-Allow-Origin"]  = "*"
        resp.headers["Access-Control-Allow-Methods"] = "GET, OPTIONS"
        resp.headers["Access-Control-Allow-Headers"] = "Content-Type, X-API-KEY"
        return resp

    qr = request.args.get("qr", "").strip()
    if not qr:
        return jsonify({"error": "qr parameter is required"}), 400

    # Check in-memory cache first
    with _cache_lock:
        cached = _qr_scan_cache.get(qr)
    if cached is not None:
        resp = jsonify(cached)
        resp.headers["Access-Control-Allow-Origin"] = "*"
        resp.headers["X-Cache"] = "HIT"
        return resp

    # Exact DB lookup (primary key — extremely fast)
    db  = get_db()
    try:
        row = db.execute(
            "SELECT qr_code, name, price, category, rarity, set_code, description, "
            "stock, image_url, tcg_id FROM inventory WHERE qr_code = %s LIMIT 1",
            (qr,)
        ).fetchone()
    except Exception as _db_err:
        log.error("[card/scan] DB lookup failed: %s", _db_err)
        return jsonify({"found": False, "code": qr, "error": "Database error"}), 500

    if not row:
        # Try once with normalised QR
        norm = _normalize_qr(qr)
        if norm != qr:
            try:
                row = db.execute(
                    "SELECT qr_code, name, price, category, rarity, set_code, description, "
                    "stock, image_url, tcg_id FROM inventory WHERE qr_code = %s LIMIT 1",
                    (norm,)
                ).fetchone()
            except Exception:
                pass

    # ── Smart scan fallback — rapidfuzz fuzzy match when exact DB lookup fails ──
    smart_result = None
    if not row:
        smart_result = _smart_scanner.smart_scan(qr, db)
        if smart_result and smart_result["found"]:
            item = smart_result["item"]
            # Teach the scanner so future identical scans skip fuzzy entirely
            _smart_scanner.learn(qr, item["qr_code"])
            # Trigger background enrichment if this card has no TCG data yet
            if not item.get("tcg_id"):
                def _bg_enrich(qr_code=item["qr_code"]):
                    try:
                        _enrich_with_tcg(None, qr_code)
                    except Exception as _ee:
                        log.debug("[smart-scan] bg enrich failed for %s: %s", qr_code, _ee)
                _bg(_bg_enrich)

    def _row_to_scan_result(r, confidence=1.0, method="exact", variant=""):
        return {
            "found":      True,
            "code":       r["qr_code"],
            "name":       r["name"],
            "sku":        r.get("set_code") or r["qr_code"],
            "description": r.get("description") or "",
            "price":      str(r["price"])  if r["price"]  is not None else None,
            "stock":      str(r["stock"])  if r["stock"]  is not None else None,
            "confidence": confidence,
            "method":     method,
            "variant":    variant or _detect_variant(
                r.get("name") or "", r.get("rarity") or "", r.get("description") or ""
            ),
            "rawResponse": {
                "qrCode":        r["qr_code"],
                "name":          r["name"],
                "price":         r["price"],
                "category":      r.get("category") or "General",
                "rarity":        r.get("rarity")   or "",
                "setCode":       r.get("set_code") or "",
                "description":   r.get("description") or "",
                "stockQuantity": r["stock"],
                "imageUrl":      r.get("image_url") or "",
                "tcgId":         r.get("tcg_id")   or "",
            },
        }

    if row:
        result = _row_to_scan_result(row, confidence=1.0, method="exact")
        _track_scan_image(row.get("image_url") or "")
    elif smart_result and smart_result["found"]:
        item = smart_result["item"]
        result = _row_to_scan_result(
            item,
            confidence=smart_result["confidence"],
            method=smart_result["method"],
            variant=smart_result["variant"],
        )
        _track_scan_image(item.get("image_url") or "")
    else:
        # Nothing found — include fuzzy suggestions so the app can show "Did you mean?"
        suggestions = (smart_result or {}).get("suggestions", []) if smart_result else []
        result = {
            "found":       False,
            "code":        qr,
            "name":        None,
            "sku":         None,
            "description": None,
            "price":       None,
            "stock":       None,
            "confidence":  0.0,
            "method":      "none",
            "variant":     "",
            "rawResponse": None,
            "suggestions": suggestions,
        }

    # Only cache confident matches — low-confidence fuzzy results should re-evaluate
    # as new inventory is added.
    if result.get("found") and result.get("confidence", 1.0) >= 0.85:
        with _cache_lock:
            _qr_scan_cache[qr] = result

    resp = jsonify(result)
    resp.headers["Access-Control-Allow-Origin"] = "*"
    resp.headers["X-Cache"] = "MISS"
    return resp


# ---------------------------------------------------------------------------
# Card enrichment — local inventory + full TCG API data merged
# ---------------------------------------------------------------------------

@app.route("/card/enrich", methods=["GET", "POST"])
def card_enrich():
    """
    Return the richest possible card data by combining local inventory with
    the Pokémon TCG API (cached 24 h).

    GET  /card/enrich?qr=SV1-1
    GET  /card/enrich?name=Charizard&set=sv3
    POST /card/enrich  {"qr":"SV1-1"}

    Response includes:
      • All local inventory fields (price, stock, rarity, …)
      • tcgData: {name, hp, types, rarity, set, images{small,large},
                  attacks, weaknesses, tcgplayer{marketPrice, priceTiers}}
      • inLocalInventory: bool
      • isDuplicate: bool — card already in stock
      • suggestedPrice: float — TCG market price when no local price set
      • imageUrl: large card image
    """
    if request.method == "POST":
        body = request.get_json(silent=True) or {}
        qr   = (body.get("qr") or body.get("qrCode") or "").strip()
        name = (body.get("name") or "").strip()
        set_code = (body.get("set") or "").strip()
        num      = (body.get("num") or "").strip().lstrip("0")
    else:
        qr       = request.args.get("qr",   "").strip()
        name     = request.args.get("name", "").strip()
        set_code = request.args.get("set",  "").strip()
        num      = request.args.get("num",  "").strip().lstrip("0")

    # Build a canonical qr code to look up
    if not qr:
        if set_code and num:
            qr = f"{set_code.upper()}-{num}"
        elif name:
            qr = name  # will be used as text search below

    if not qr:
        return jsonify({"error": "Provide qr, name, or set+num"}), 400

    norm_qr = _normalize_qr(qr)
    db      = get_db()
    matches = _card_lookup(db, qr=norm_qr, name=name,
                           set_code=set_code, card_num=num, limit=1)
    local   = matches[0] if matches else None
    result  = _enrich_with_tcg(local, norm_qr)
    result["normalizedQr"] = norm_qr

    # Persist market price to price_history for trend tracking
    _ph_price = (result.get("tcgData") or {}).get("tcgplayer", {}).get("marketPrice")
    if _ph_price:
        try:
            db.execute(
                "INSERT INTO price_history (card_id, card_name, market_price, fetched_ms) "
                "VALUES (%s,%s,%s,%s)",
                (norm_qr, result.get("name") or norm_qr, float(_ph_price), _now_ms())
            )
            db.commit()
        except Exception:
            pass

    return jsonify(result)


# ---------------------------------------------------------------------------
# Card condition — NM / LP / MP / HP / DMG per qr_code
# ---------------------------------------------------------------------------

_CONDITIONS = {"NM", "LP", "MP", "HP", "DMG"}

@app.route("/card/condition/<path:qr_code>", methods=["GET"])
def card_condition_get(qr_code):
    db  = get_db()
    row = db.execute(
        "SELECT condition, notes, updated_ms FROM card_conditions WHERE qr_code=?", (qr_code,)
    ).fetchone()
    if row:
        return jsonify({"qrCode": qr_code, "condition": row["condition"],
                        "notes": row["notes"], "updatedMs": row["updated_ms"]})
    return jsonify({"qrCode": qr_code, "condition": "NM", "notes": "", "updatedMs": None})


@app.route("/card/condition/<path:qr_code>", methods=["POST"])
def card_condition_set(qr_code):
    """
    POST /card/condition/SV1-1
    Body: {"condition": "LP", "notes": "minor corner wear"}

    condition must be one of: NM, LP, MP, HP, DMG
    """
    body      = request.get_json(silent=True) or {}
    condition = (body.get("condition") or "NM").strip().upper()
    notes     = (body.get("notes") or "").strip()[:500]
    if condition not in _CONDITIONS:
        return jsonify({"error": f"condition must be one of {sorted(_CONDITIONS)}"}), 400
    db = get_db()
    db.execute("""
        INSERT INTO card_conditions (qr_code, condition, notes, updated_ms)
        VALUES (%s,%s,%s,%s)
        ON CONFLICT(qr_code) DO UPDATE SET
            condition=excluded.condition, notes=excluded.notes, updated_ms=excluded.updated_ms
    """, (qr_code, condition, notes, _now_ms()))
    db.commit()
    return jsonify({"ok": True, "qrCode": qr_code, "condition": condition})


# ---------------------------------------------------------------------------
# Bulk export — JSON or CSV for website upload
# ---------------------------------------------------------------------------

@app.route("/admin/export-cards", methods=["GET"])
@require_admin
def admin_export_cards():
    """
    Export Pokémon card inventory in a format ready for bulk import on the
    HanRYX website.

    GET /admin/export-cards           → JSON array
    GET /admin/export-cards?fmt=csv   → CSV download
    GET /admin/export-cards?cat=Trading+Card  → filter by category
    GET /admin/export-cards?enrich=1  → include TCG images + market prices (slow!)

    Each row contains: qrCode, name, price, category, rarity, setCode,
    description, stock, imageUrl, tcgId, condition, tcgMarketPrice
    """
    fmt      = request.args.get("fmt", "json").lower()
    cat      = request.args.get("cat", "").strip()
    do_enrich = request.args.get("enrich", "0") == "1"

    db = get_db()
    if cat:
        rows = db.execute(
            "SELECT * FROM inventory WHERE LOWER(category) LIKE %s ORDER BY name ASC",
            (f"%{cat.lower()}%",)
        ).fetchall()
    else:
        rows = db.execute("SELECT * FROM inventory ORDER BY name ASC").fetchall()

    # Fetch conditions in one query
    cond_rows = db.execute("SELECT qr_code, condition, notes FROM card_conditions").fetchall()
    cond_map  = {r["qr_code"]: {"condition": r["condition"], "notes": r["notes"]}
                 for r in cond_rows}

    cards = []
    for r in rows:
        qr = r["qr_code"]
        c  = cond_map.get(qr, {})
        entry = {
            "qrCode":      qr,
            "name":        r["name"],
            "price":       r["price"],
            "category":    r["category"] or "General",
            "rarity":      r["rarity"] or "",
            "setCode":     r["set_code"] or "",
            "description": r["description"] or "",
            "stock":       r["stock"],
            "imageUrl":    r["image_url"] if "image_url" in r.keys() else "",
            "tcgId":       r["tcg_id"]    if "tcg_id"    in r.keys() else "",
            "condition":   c.get("condition", "NM"),
            "conditionNotes": c.get("notes", ""),
            "lastUpdated": r["last_updated"],
        }
        if do_enrich:
            enriched = _enrich_with_tcg(entry, qr)
            mkt = (enriched.get("tcgData") or {}).get("tcgplayer", {}).get("marketPrice")
            if mkt:
                entry["tcgMarketPrice"] = mkt
            if enriched.get("imageUrl") and not entry["imageUrl"]:
                entry["imageUrl"] = enriched["imageUrl"]
        else:
            entry["tcgMarketPrice"] = None
        cards.append(entry)

    if fmt == "csv":
        fields = ["qrCode","name","price","stock","category","rarity","setCode",
                  "condition","imageUrl","tcgId","tcgMarketPrice","description",
                  "conditionNotes","lastUpdated"]
        buf = io.StringIO()
        w   = csv.DictWriter(buf, fieldnames=fields, extrasaction="ignore")
        w.writeheader()
        w.writerows(cards)
        from flask import Response as _Resp
        return _Resp(
            buf.getvalue(),
            mimetype="text/csv",
            headers={"Content-Disposition": "attachment; filename=hanryx_inventory.csv"},
        )

    return jsonify({"count": len(cards), "cards": cards})


# ---------------------------------------------------------------------------
# QR code generation — single image + full-inventory print sheet
# ---------------------------------------------------------------------------

def _make_qr_png(text: str, box_size: int = 6, border: int = 2) -> bytes:
    """Generate a QR code PNG for *text* and return raw bytes."""
    qr = _qrcode.QRCode(
        version=None,
        error_correction=_qrcode_const.ERROR_CORRECT_M,
        box_size=box_size,
        border=border,
    )
    qr.add_data(text)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return buf.getvalue()


@app.route("/admin/qr/<path:qr_code>", methods=["GET"])
def admin_qr_image(qr_code: str):
    """
    GET /admin/qr/<qr_code>
    Returns a QR code PNG for the given qr_code string.
    No login required so <img> tags in the print sheet load without auth cookies.
    """
    size = min(max(_safe_int(request.args.get("size", 6), 6), 2), 15)
    try:
        png = _make_qr_png(qr_code, box_size=size)
    except Exception as e:
        log.error("[qr] generation failed for %r: %s", qr_code, e)
        return ("QR error", 500)
    return Response(png, mimetype="image/png",
                    headers={"Cache-Control": "public, max-age=86400"})


@app.route("/admin/qr-sheet", methods=["GET"])
@require_admin
def admin_qr_sheet():
    """
    GET /admin/qr-sheet
    GET /admin/qr-sheet?q=charizard     — filter by name
    GET /admin/qr-sheet?cat=Singles     — filter by category
    GET /admin/qr-sheet?zero=1          — include out-of-stock items too
    GET /admin/qr-sheet?cols=3          — labels per row (2–5, default 4)

    Returns a print-ready HTML page with one QR label per inventory card.
    Each label shows: QR code image, card name, set code, price, stock, qr_code text.
    Print from the browser (Ctrl+P / Cmd+P) — the page CSS hides the nav bar.
    """
    q    = request.args.get("q", "").strip().lower()
    cat  = request.args.get("cat", "").strip().lower()
    zero = request.args.get("zero", "0") == "1"
    try:
        cols = min(max(_safe_int(request.args.get("cols", 4), 4), 2), 5)
    except ValueError:
        cols = 4

    db   = get_db()
    rows = db.execute(
        "SELECT qr_code, name, price, category, rarity, set_code, stock "
        "FROM inventory ORDER BY name ASC"
    ).fetchall()

    items = []
    for r in rows:
        if not zero and (r["stock"] or 0) <= 0:
            continue
        if q and q not in (r["name"] or "").lower() and q not in (r["qr_code"] or "").lower():
            continue
        if cat and cat not in (r["category"] or "").lower():
            continue
        items.append(dict(r))

    # Build label HTML
    label_width_pct = 100 // cols
    labels_html = ""
    for it in items:
        qr    = it["qr_code"] or ""
        name  = (it["name"] or "Unknown").replace("<", "&lt;").replace(">", "&gt;")
        price = f"£{it['price']:.2f}" if it.get("price") else "—"
        stock = it.get("stock") or 0
        setc  = (it.get("set_code") or "").replace("<", "&lt;")
        cat_d = (it.get("category") or "").replace("<", "&lt;")
        stock_style = "color:#c00;font-weight:bold" if stock == 0 else ("color:#e07000" if stock <= 2 else "color:#060")
        labels_html += f"""
<div class="label">
  <img src="/admin/qr/{urllib.parse.quote(qr, safe='')}" alt="QR:{qr}" class="qr-img">
  <div class="lname">{name}</div>
  <div class="lmeta">{setc}{' · ' + cat_d if cat_d and cat_d != setc else ''}</div>
  <div class="lprice">{price} &nbsp; <span style="{stock_style}">Stock: {stock}</span></div>
  <div class="lcode">{qr.replace('<','&lt;')}</div>
</div>"""

    total    = len(items)
    filter_s = ""
    if q:
        filter_s += f" · search: <b>{q}</b>"
    if cat:
        filter_s += f" · category: <b>{cat}</b>"
    if not zero:
        filter_s += " · in-stock only"

    html = f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>QR Label Sheet — HanryxVault</title>
<style>
  * {{ box-sizing: border-box; margin: 0; padding: 0; }}
  body {{ font-family: Arial, sans-serif; background: #fff; color: #000; }}

  /* ── Screen toolbar ─────────────────────────── */
  .toolbar {{
    background: #1a1a1a; color: #fff; padding: 10px 16px;
    display: flex; align-items: center; gap: 12px; flex-wrap: wrap;
  }}
  .toolbar h1 {{ font-size: 16px; font-weight: bold; flex: 1; }}
  .toolbar a  {{ color: #f59e0b; font-size: 13px; }}
  .toolbar .info {{ font-size: 13px; color: #aaa; }}
  .toolbar form {{ display:flex; gap:8px; align-items:center; }}
  .toolbar input {{ padding:4px 8px; border-radius:4px; border:none; font-size:13px; }}
  .toolbar select {{ padding:4px; border-radius:4px; border:none; font-size:13px; }}
  .toolbar button {{ padding:5px 14px; border:none; border-radius:4px; cursor:pointer;
                     background:#f59e0b; font-weight:bold; font-size:13px; }}

  /* ── Label grid ─────────────────────────────── */
  .grid {{
    display: flex;
    flex-wrap: wrap;
    padding: 8mm;
    gap: 4mm;
  }}
  .label {{
    width: calc({label_width_pct}% - 4mm);
    border: 1px solid #bbb;
    border-radius: 4px;
    padding: 4mm;
    display: flex;
    flex-direction: column;
    align-items: center;
    page-break-inside: avoid;
    background: #fff;
  }}
  .qr-img  {{ width: 100%; max-width: 120px; height: auto; display: block; margin-bottom: 3mm; }}
  .lname   {{ font-size: 10pt; font-weight: bold; text-align: center; line-height: 1.2;
               margin-bottom: 1mm; max-width: 100%; word-break: break-word; }}
  .lmeta   {{ font-size: 8pt; color: #555; text-align: center; margin-bottom: 1mm; }}
  .lprice  {{ font-size: 9pt; text-align: center; margin-bottom: 1mm; }}
  .lcode   {{ font-size: 7pt; color: #777; text-align: center; word-break: break-all; }}

  /* ── Print overrides ────────────────────────── */
  @media print {{
    .toolbar {{ display: none !important; }}
    .grid    {{ padding: 6mm; gap: 3mm; }}
    body     {{ background: #fff; }}
  }}
</style>
</head>
<body>

<div class="toolbar">
  <h1>🏷 QR Label Sheet — HanryxVault</h1>
  <span class="info">{total} label{'s' if total != 1 else ''}{filter_s}</span>
  <form method="get" action="/admin/qr-sheet">
    <input name="q"    placeholder="Search name…" value="{q}">
    <input name="cat"  placeholder="Category…"    value="{cat}">
    <select name="cols">
      {''.join(f'<option value="{c}"{"selected" if c == cols else ""}>{c} per row</option>' for c in range(2,6))}
    </select>
    <label style="font-size:13px;color:#ccc">
      <input type="checkbox" name="zero" value="1" {'checked' if zero else ''}> incl. out-of-stock
    </label>
    <button type="submit">Filter</button>
    <button type="button" onclick="window.print()">🖨 Print</button>
  </form>
  <a href="/admin">← Dashboard</a>
</div>

<div class="grid">
{labels_html if labels_html else '<p style="padding:20px;color:#888">No items match the current filter.</p>'}
</div>

</body>
</html>"""

    return Response(html, mimetype="text/html")


