@app.route("/tablet/trade/<int:ti_id>/modify", methods=["POST"])
@require_api_token
def tablet_trade_modify(ti_id):
    """
    Customer-side edits on the tablet (delete cards, lower offered prices)
    sync back here so the operator sees what the customer actually agreed to.

    Updates the Redis snapshot only — does NOT touch the underlying
    trade_in_items rows. The operator reconciles at finalize time.
    Only succeeds while status='pending'.

    Body (all fields optional except items):
      {
        "items":          [TradeItem, ...],
        "item_count":     <int>           (defaults to len(items)),
        "total_cash":     <float>,
        "total_credit":   <float>,
        "outgoing_items": [TradeItem, ...] (optional)
      }
    """
    body = request.get_json(silent=True) or {}
    items = body.get("items")
    if not isinstance(items, list):
        return jsonify({"error": "items[] required"}), 400

    snap = _tablet_offer_load()
    if not snap or int(snap.get("ti_id", 0)) != int(ti_id):
        return jsonify({"error": "offer not found", "ti_id": ti_id}), 404
    if snap.get("status") != "pending":
        return jsonify({"error": f"offer already {snap.get('status')}"}), 409

    now_ms = int(time.time() * 1000)
    snap["items"]        = items
    snap["item_count"]   = int(body.get("item_count") or len(items))
    snap["total_cash"]   = float(body.get("total_cash")   or 0.0)
    snap["total_credit"] = float(body.get("total_credit") or 0.0)
    snap["modified_at"]  = now_ms
    # Bump sent_at too so tablet clients keying on `${ti_id}_${sent_at}`
    # detect the modification without needing a contract change. The original
    # send timestamp is preserved in `modified_at` semantics: callers that
    # want "first sent" can still treat sent_at == modified_at as unmodified.
    snap["sent_at"]      = now_ms

    out = body.get("outgoing_items")
    if isinstance(out, list):
        snap["outgoing_items"] = out

    _tablet_offer_save(snap)
    log.info("[tablet] modify ti=%s items=%d cash=$%.2f",
             ti_id, snap["item_count"], snap["total_cash"])
    return jsonify({"ok": True, "status": "pending"})


def _kiosk_push_trade(ti_id, complete=False, cancelled=False):
    """Broadcast current trade-in state to kiosk SSE clients."""
    if cancelled:
        _kiosk_broadcast({"mode": "idle", "active": False})
        return
    try:
        db    = get_db()
        ti    = db.execute("SELECT * FROM trade_ins WHERE id=%s", (ti_id,)).fetchone()
        if not ti:
            return
        items = db.execute(
            "SELECT * FROM trade_in_items WHERE trade_in_id=%s ORDER BY id", (ti_id,)
        ).fetchall()
        cash_total   = float(ti["total_value"] or 0)
        credit_total = round(cash_total * 1.20, 2)
        _kiosk_broadcast({
            "mode":             "trade",
            "active":           True,
            "trade_complete":   complete,
            "trade_customer":   ti["customer"] or "Customer",
            "trade_reference":  ti["reference"],
            "trade_items":      [{"name":      it["name"],
                                  "condition": it["condition"],
                                  "offer":     float(it["offered_price"] or 0),
                                  "market":    float(it["market_price"] or 0),
                                  "accepted":  bool(it["accepted"])} for it in items],
            "trade_cash":       cash_total,
            "trade_credit":     credit_total,
        })
    except Exception:
        log.exception("[kiosk] trade broadcast failed")


@app.route("/admin/market/quick-trade-in", methods=["POST"])
@require_admin
def admin_market_quick_trade_in():
    import traceback as _tb
    try:
        return _admin_market_quick_trade_in_impl()
    except Exception as _e:
        _tb_str = _tb.format_exc()
        app.logger.error("quick-trade-in CRASH: %s\n%s", _e, _tb_str)
        print("=" * 70, flush=True)
        print("QUICK-TRADE-IN TRACEBACK:", flush=True)
        print(_tb_str, flush=True)
        print("=" * 70, flush=True)
        return jsonify({
            "error":     str(_e),
            "exception": type(_e).__name__,
            "traceback": _tb_str.splitlines()[-12:],
        }), 500


def _admin_market_quick_trade_in_impl():
    """One-click: from the Market page, push the currently-shown card straight
    to the customer tablet as a trade-in offer.

    Auto-creates a Walk-in trade-in if none is open, computes a fair-buy offer
    from the displayed market price (market * 0.55, the FAIR_BUY_FRAC default),
    inserts the item, refreshes the kiosk display, and writes the offer to
    Redis so the tablet picks it up on its next 2s poll.

    Body JSON: {name, market_price, condition?, qr_code?, set?, number?}
    Returns:   {ok, ti_id, reference, offer, market, total_cash, item_count}
    """
    data         = request.get_json(silent=True) or {}
    name         = (data.get("name") or "").strip()[:200]
    market_price = _safe_float(data.get("market_price"), 0)
    condition    = (data.get("condition") or "NM").strip()[:8]
    qr_code      = (data.get("qr_code") or "").strip()[:80]
    set_name     = (data.get("set") or "").strip()[:100]
    number       = (data.get("number") or "").strip()[:20]

    if not name:
        return jsonify({"error": "name is required"}), 400
    if market_price <= 0:
        return jsonify({"error": "market_price must be > 0"}), 400

    # Fair-buy offer: 55% of condition-adjusted market price (matches
    # buy_price.FAIR_BUY_FRAC default). Operator can override later.
    offered_price = round(market_price * 0.55, 2)

    # Auto-generate a QR if none given so the tablet has a stable line id.
    if not qr_code:
        qr_code = f"MKT-{int(time.time() * 1000)}"

    # Friendly display name = "Charizard ex 199 — Obsidian Flames"
    display_name = name
    if number and number not in display_name:
        display_name = f"{display_name} {number}"
    if set_name and set_name.lower() not in display_name.lower():
        display_name = f"{display_name} — {set_name}"

    db = get_db()

    # Find the most recent open Walk-in trade-in, else create a new one.
    ti = db.execute(
        "SELECT * FROM trade_ins WHERE status='open' "
        "ORDER BY created_at DESC LIMIT 1"
    ).fetchone()
    if not ti:
        ref = _trade_in_ref()
        row = db.execute(
            "INSERT INTO trade_ins (reference, customer, notes) "
            "VALUES (%s,%s,%s) RETURNING id, reference",
            (ref, "Walk-in", "Created from Market quick-push")
        ).fetchone()
        if not row:
            return jsonify({"error": "Failed to create trade-in"}), 500
        ti_id     = row["id"]
        reference = row["reference"]
    else:
        ti_id     = ti["id"]
        reference = ti["reference"]

    db.execute(
        "INSERT INTO trade_in_items "
        "(trade_in_id, qr_code, name, condition, offered_price, market_price) "
        "VALUES (%s,%s,%s,%s,%s,%s)",
        (ti_id, qr_code, display_name, condition, offered_price, market_price)
    )
    total = db.execute(
        "SELECT COALESCE(SUM(offered_price),0) FROM trade_in_items "
        "WHERE trade_in_id=%s AND accepted=1",
        (ti_id,)
    ).fetchone()[0]
    db.execute("UPDATE trade_ins SET total_value=%s WHERE id=%s", (total, ti_id))
    db.commit()

    item_count = db.execute(
        "SELECT COUNT(*) FROM trade_in_items WHERE trade_in_id=%s AND accepted=1",
        (ti_id,)
    ).fetchone()[0]

    # Push to satellite kiosk display (existing channel).
    threading.Thread(target=_kiosk_push_trade, args=(ti_id,), daemon=True).start()

    # Push to customer tablet (Redis-backed offer channel).
    payload = _tablet_offer_build_payload(ti_id)
    if payload:
        payload["status"]      = "pending"
        payload["pushed_at"]   = int(time.time() * 1000)
        payload["sent_at"]     = payload["pushed_at"]   # tablet dedup key wants sent_at
        _tablet_offer_save(payload)

    return jsonify({
        "ok":          True,
        "ti_id":       ti_id,
        "reference":   reference,
        "offer":       offered_price,
        "market":      market_price,
        "total_cash":  float(total),
        "item_count":  int(item_count),
        "tablet_pushed": payload is not None,
    })


@app.route("/admin/trade-in/<int:ti_id>/add-item", methods=["POST"])
@require_admin
def admin_trade_in_add_item(ti_id):
    db   = get_db()
    ti   = db.execute("SELECT * FROM trade_ins WHERE id=%s AND status='open'", (ti_id,)).fetchone()
    if not ti:
        return jsonify({"error": "Trade-in not found or not open"}), 404
    data          = request.get_json(silent=True) or {}
    qr_code       = (data.get("qr_code") or "").strip()
    name          = (data.get("name") or "").strip()
    condition     = (data.get("condition") or "NM").strip()
    offered_price = _safe_float(data.get("offered_price"), 0)
    market_price  = _safe_float(data.get("market_price"), 0)
    if not qr_code or not name:
        return jsonify({"error": "qr_code and name required"}), 400
    db.execute(
        "INSERT INTO trade_in_items (trade_in_id,qr_code,name,condition,offered_price,market_price) "
        "VALUES (%s,%s,%s,%s,%s,%s)",
        (ti_id, qr_code, name, condition, offered_price, market_price)
    )
    # Recalculate total
    total = db.execute(
        "SELECT COALESCE(SUM(offered_price),0) FROM trade_in_items WHERE trade_in_id=%s AND accepted=1",
        (ti_id,)
    ).fetchone()[0]
    db.execute("UPDATE trade_ins SET total_value=%s WHERE id=%s", (total, ti_id))
    db.commit()
    items = db.execute("SELECT * FROM trade_in_items WHERE trade_in_id=%s ORDER BY id", (ti_id,)).fetchall()
    threading.Thread(target=_kiosk_push_trade, args=(ti_id,), daemon=True).start()
    return jsonify({"ok": True, "items": [dict(i) for i in items]})


@app.route("/admin/trade-in/<int:ti_id>/remove-item/<int:item_id>", methods=["POST"])
@require_admin
def admin_trade_in_remove_item(ti_id, item_id):
    db = get_db()
    db.execute("DELETE FROM trade_in_items WHERE id=%s AND trade_in_id=%s", (item_id, ti_id))
    total = db.execute(
        "SELECT COALESCE(SUM(offered_price),0) FROM trade_in_items WHERE trade_in_id=%s AND accepted=1",
        (ti_id,)
    ).fetchone()[0]
    db.execute("UPDATE trade_ins SET total_value=%s WHERE id=%s", (total, ti_id))
    db.commit()
    items = db.execute("SELECT * FROM trade_in_items WHERE trade_in_id=%s ORDER BY id", (ti_id,)).fetchall()
    threading.Thread(target=_kiosk_push_trade, args=(ti_id,), daemon=True).start()
    return jsonify({"ok": True, "items": [dict(i) for i in items]})


@app.route("/admin/trade-in/<int:ti_id>/complete", methods=["POST"])
@require_admin
def admin_trade_in_complete(ti_id):
    db   = get_db()
    ti   = db.execute("SELECT * FROM trade_ins WHERE id=%s AND status='open'", (ti_id,)).fetchone()
    if not ti:
        return jsonify({"error": "Trade-in not found or not open"}), 404
    items = db.execute(
        "SELECT * FROM trade_in_items WHERE trade_in_id=%s AND accepted=1", (ti_id,)
    ).fetchall()
    if not items:
        return jsonify({"error": "No accepted items in this trade-in"}), 400

    # ── Customer-consent gate ─────────────────────────────────────────────
    # If an offer was ever sent to the tablet, the customer must have
    # accepted it before we finalize. Operator can override with
    # {"force": true} for edge cases (e.g. tablet dead, customer signed
    # paper). Trade-ins that never went through the tablet at all skip
    # this check (back-compat with the original flow).
    body = request.get_json(silent=True) or {}
    force = bool(body.get("force"))
    snap  = _tablet_offer_load()
    if (snap and int(snap.get("ti_id", 0)) == int(ti_id)
            and snap.get("status") != "accepted" and not force):
        return jsonify({
            "error":  "Customer has not accepted the offer on the tablet yet.",
            "status": snap.get("status", "pending"),
        }), 409

    added = 0
    for it in items:
        db.execute("""
            INSERT INTO inventory (qr_code, name, price, category, stock, last_updated)
            VALUES (%s, %s, %s, 'Trade-In', 1, %s)
            ON CONFLICT(qr_code) DO UPDATE SET
                stock        = inventory.stock + 1,
                last_updated = excluded.last_updated
        """, (it["qr_code"], it["name"], it["offered_price"], _now_ms()))
        db.execute("""
            INSERT INTO card_conditions (qr_code, condition, notes, updated_ms)
            VALUES (%s, %s, %s, %s)
            ON CONFLICT(qr_code) DO UPDATE SET
                condition  = excluded.condition,
                notes      = excluded.notes,
                updated_ms = excluded.updated_ms
        """, (it["qr_code"], it["condition"], f"Trade-in {ti['reference']}", _now_ms()))
        added += 1

    db.execute(
        "UPDATE trade_ins SET status='completed', completed_at=%s WHERE id=%s",
        (_now_ms(), ti_id)
    )
    db.commit()
    _invalidate_inventory()
    threading.Thread(target=_kiosk_push_trade, args=(ti_id,), kwargs={"complete": True}, daemon=True).start()
    # Final receipt → customer transparency screen + clear the tablet
    try:
        cash_total   = float(ti["total_value"] or 0)
        credit_total = round(cash_total * 1.20, 2)
        _kiosk_transparency_save({
            "mode":      "trade_complete",
            "headline":  "Trade complete — thank you!",
            "card":      {"name": f"{added} card(s) accepted",
                          "set":  ti["customer"] or "",
                          "image_url": ""},
            "buy":       {"fair": cash_total, "max": credit_total},
            "sold_90d":  {},
            "condition": {"label": "—", "multiplier": 1.0},
            "pushed_at": int(time.time() * 1000),
        })
    except Exception:
        pass
    _tablet_offer_clear()
    return jsonify({"ok": True, "added": added})


@app.route("/admin/trade-in/<int:ti_id>/cancel", methods=["POST"])
@require_admin
def admin_trade_in_cancel(ti_id):
    db = get_db()
    db.execute(
        "UPDATE trade_ins SET status='cancelled' WHERE id=%s AND status='open'", (ti_id,)
    )
    db.commit()
    threading.Thread(target=_kiosk_push_trade, args=(ti_id,), kwargs={"cancelled": True}, daemon=True).start()
    _tablet_offer_clear()
    return jsonify({"ok": True})


