@app.route("/admin/inventory", methods=["POST"])
@require_admin
def admin_add_product():
    data    = request.get_json(force=True, silent=True) or {}
    qr_code = (data.get("qrCode") or data.get("qr_code") or "").strip()
    name    = (data.get("name") or "").strip()
    if not qr_code or not name:
        return jsonify({"error": "qrCode and name are required"}), 400

    image_url      = (data.get("imageUrl")     or data.get("image_url")      or "").strip()
    tcg_id         = (data.get("tcgId")        or data.get("tcg_id")         or "").strip()
    back_image_url = (data.get("backImageUrl") or data.get("back_image_url") or "").strip()
    language       = (data.get("language")      or "English").strip()
    condition      = (data.get("condition")     or "NM").strip()
    item_type      = (data.get("itemType")      or data.get("item_type")  or "Single").strip()
    grading_co     = (data.get("gradingCompany") or data.get("grading_company") or "").strip()
    grade          = (data.get("grade")         or "").strip()
    cert_number    = (data.get("certNumber")    or data.get("cert_number")    or "").strip()
    tags           = ",".join(data.get("tags") or []) if isinstance(data.get("tags"), list) \
                     else (data.get("tags") or "").strip()
    featured       = 1 if data.get("featured") in (True, 1, "1", "true") else 0
    listed_for_sale = 0 if data.get("listedForSale") in (False, 0, "0", "false") else 1

    base_price     = float(data.get("price", 0))
    purchase_price = float(data.get("purchasePrice") or data.get("purchase_price") or 0)
    sale_price     = float(data.get("salePrice")     or data.get("sale_price")     or 0)

    # Auto-apply pricing engine if caller sends base_market_price
    base_market = float(data.get("baseMarketPrice") or data.get("base_market_price") or 0)
    if base_market and not base_price:
        base_price = _calculate_final_price(base_market, language, item_type, grade)

    db = get_db()
    db.execute("""
        INSERT INTO inventory
            (qr_code, name, price, category, rarity, set_code, description, stock,
             image_url, tcg_id, last_updated,
             language, condition, item_type, grading_company, grade, cert_number,
             back_image_url, purchase_price, sale_price, tags, featured, listed_for_sale)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        ON CONFLICT(qr_code) DO UPDATE SET
            name=excluded.name, price=excluded.price, category=excluded.category,
            rarity=excluded.rarity, set_code=excluded.set_code,
            description=excluded.description, stock=excluded.stock,
            image_url=CASE WHEN excluded.image_url!='' THEN excluded.image_url ELSE inventory.image_url END,
            tcg_id=CASE WHEN excluded.tcg_id!=''    THEN excluded.tcg_id    ELSE inventory.tcg_id    END,
            language=excluded.language, condition=excluded.condition,
            item_type=excluded.item_type, grading_company=excluded.grading_company,
            grade=excluded.grade, cert_number=excluded.cert_number,
            back_image_url=CASE WHEN excluded.back_image_url!='' THEN excluded.back_image_url ELSE inventory.back_image_url END,
            purchase_price=excluded.purchase_price, sale_price=excluded.sale_price,
            tags=excluded.tags, featured=excluded.featured,
            listed_for_sale=excluded.listed_for_sale, last_updated=excluded.last_updated
    """, (
        qr_code, name,
        base_price, data.get("category", "General"),
        data.get("rarity", ""), data.get("setCode") or data.get("set_code", ""),
        data.get("description", ""), int(data.get("stock", 0)),
        image_url, tcg_id, _now_ms(),
        language, condition, item_type, grading_co, grade, cert_number,
        back_image_url, purchase_price, sale_price, tags, featured, listed_for_sale,
    ))
    db.commit()
    _invalidate_inventory()

    # Fire webhook in background (non-blocking) if configured
    webhook_payload = {
        "event":       "card_saved",
        "qrCode":      qr_code,
        "name":        name,
        "price":       base_price,
        "category":    data.get("category", "General"),
        "rarity":      data.get("rarity", ""),
        "setCode":     data.get("setCode") or data.get("set_code", ""),
        "stock":       int(data.get("stock", 0)),
        "imageUrl":    image_url,
        "tcgId":       tcg_id,
        "language":    language,
        "condition":   condition,
        "itemType":    item_type,
        "grade":       grade,
        "tags":        tags,
        "savedAt":     _now_ms(),
    }
    _bg(_fire_webhook, webhook_payload)

    return jsonify({"ok": True, "qrCode": qr_code})


@app.route("/admin/inventory/<qr_code>", methods=["PATCH"])
@require_admin
def admin_patch_product(qr_code):
    """Partial update — toggle featured / listed_for_sale, or update stock / price."""
    data = request.get_json(force=True, silent=True) or {}
    db   = get_db()
    sets, vals = [], []
    if "featured" in data:
        sets.append("featured = %s")
        vals.append(1 if data["featured"] in (True, 1, "1", "true") else 0)
    if "listedForSale" in data or "listed_for_sale" in data:
        v = data.get("listedForSale", data.get("listed_for_sale"))
        sets.append("listed_for_sale = %s")
        vals.append(0 if v in (False, 0, "0", "false") else 1)
    if "stock" in data:
        sets.append("stock = %s")
        vals.append(int(data["stock"]))
    if "price" in data:
        sets.append("price = %s")
        vals.append(float(data["price"]))
    if not sets:
        return jsonify({"error": "No updatable fields provided"}), 400
    sets.append("last_updated = %s")
    vals.append(_now_ms())
    vals.append(qr_code)
    db.execute(f"UPDATE inventory SET {', '.join(sets)} WHERE qr_code = %s", vals)
    db.commit()
    _invalidate_inventory()
    return jsonify({"ok": True, "qrCode": qr_code})


@app.route("/admin/inventory/<qr_code>", methods=["DELETE"])
@require_admin
def admin_delete_product(qr_code):
    db = get_db()
    db.execute("DELETE FROM inventory WHERE qr_code = %s", (qr_code,))
    db.commit()
    _invalidate_inventory()
    return jsonify({"ok": True, "deleted": qr_code})


# ---------------------------------------------------------------------------
# Receipt Printer — ESC/POS over Bluetooth (/dev/rfcomm0) or USB (/dev/usb/lp0)
# ---------------------------------------------------------------------------

_PRINTER_CONF_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "printer.conf")

# ESC/POS byte commands — no external library needed
_ESC             = b'\x1b'
_GS              = b'\x1d'
_PR_INIT         = _ESC + b'@'           # initialise printer
_PR_BOLD_ON      = _ESC + b'E\x01'
_PR_BOLD_OFF     = _ESC + b'E\x00'
_PR_CENTER       = _ESC + b'a\x01'
_PR_LEFT         = _ESC + b'a\x00'
_PR_DOUBLE       = _ESC + b'!\x30'       # double width + double height
_PR_NORMAL       = _ESC + b'!\x00'
_PR_CUT          = _GS  + b'V\x42\x00'  # partial cut + feed
# Cash drawer kick — ESC p m t1 t2.  m=0 (pin 2, the standard RJ11 drawer pin),
# t1=25, t2=250  →  ~50 ms pulse, plenty for any star/epson-compatible drawer.
_PR_KICK_DRAWER  = _ESC + b'p\x00\x19\xfa'
_PR_LF           = b'\n'
_PR_DIVIDER_WIDE      = b'-' * 42 + b'\n'    # 80 mm paper (42 chars)
_PR_DIVIDER_NARR      = b'-' * 32 + b'\n'    # 58 mm paper (32 chars)
_PR_DIVIDER_WIDE_BOLD = b'=' * 42 + b'\n'    # 80 mm — major section break
_PR_DIVIDER_NARR_BOLD = b'=' * 32 + b'\n'    # 58 mm — major section break

# Dragon-only emblem (no wordmark) — printed small above the QR as a
# "wax-seal" style brand mark to bookend the receipt. Cropped from the same
# source as receipt_logo.png. Lives on the Pi filesystem so we don't depend
# on the tablet sending a second image.
_DRAGON_EMBLEM_PATH = os.path.join(
    os.path.dirname(os.path.abspath(__file__)), "assets", "dragon_emblem.png"
)


def _load_printer_conf() -> dict:
    conf = {
        "printer_path":   None,
        "printer_type":   "auto",
        "printer_usb_path": "/dev/usb/lp0",
        # ── Ethernet/network ESC/POS printers (e.g. MUNBYN P047) ─────────────
        # Set printer_network_host=192.168.x.y in pi-setup/printer.conf to use
        # the printer over LAN/Tailscale. Port defaults to 9100 (RAW/JetDirect).
        "printer_network_host": os.environ.get("PRINTER_NETWORK_HOST"),
        "printer_network_port": int(os.environ.get("PRINTER_NETWORK_PORT", "9100")),
        "receipt_header":   "HanryxVault",
        "receipt_subheader": "Korean Pokemon TCG Specialists",
        "receipt_footer":   "hanryxvault.cards",
        # Paper width in millimetres — "58" (most compact thermal printers,
        # 384 px / 32 chars wide) or "80" (MUNBYN P047 etc., 576 px / 42 chars).
        # Used by the logo + QR raster helpers to fit images correctly. Set
        # `paper_width=80` in pi-setup/printer.conf if your printer is 80 mm.
        "paper_width":      "58",
    }
    if os.path.exists(_PRINTER_CONF_PATH):
        with open(_PRINTER_CONF_PATH) as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith("#") and "=" in line:
                    k, v = line.split("=", 1)
                    conf[k.strip()] = v.strip() or None
    return conf


def _open_printer():
    """Return an open writable file handle to the first available printer."""
    conf = _load_printer_conf()

    # Order of preference: Bluetooth rfcomm → USB lp → rfcomm1 fallback
    candidates = []
    if conf.get("printer_path"):
        candidates.append(conf["printer_path"])
    candidates += ["/dev/rfcomm0", "/dev/usb/lp0", "/dev/rfcomm1", "/dev/ttyUSB0"]

    for path in candidates:
        if os.path.exists(path):
            try:
                fh = open(path, "wb")
                return fh, path, conf
            except OSError:
                continue

    # Last resort: CUPS lp command
    return None, "cups", conf


def _open_printer_with_retry(max_attempts: int = 5, interval_s: float = 0.4):
    """Try _open_printer up to `max_attempts` times with `interval_s` between.

    Survives a USB cable that's been briefly unplugged or is mid-replug
    when a print fires (operator nudged it, replugged it, immediately
    tried to reprint). Total wait at defaults: ~1.6 s before falling
    back to CUPS — short enough that an actually-unplugged printer still
    fails fast, long enough that udev has time to recreate /dev/usb/lp0
    after a hot-replug.
    """
    fh, path, conf = _open_printer()
    if fh is not None:
        return fh, path, conf
    for attempt in range(1, max_attempts):
        time.sleep(interval_s)
        fh, path, conf = _open_printer()
        if fh is not None:
            try:
                log.info("[print] device %s recovered after %d retr%s",
                         path, attempt, "y" if attempt == 1 else "ies")
            except Exception:
                pass
            return fh, path, conf
    return fh, path, conf  # likely (None, "cups", conf)


# ── Logo + QR raster helpers ────────────────────────────────────────────────
# The tablet (MainViewModel.kt) sends an optional store logo and an optional
# customer-facing QR code inside the /print/receipt JSON body:
#
#   logoBase64   — base64-encoded PNG/JPEG (with or without data: URI prefix)
#   qrEnabled    — bool, gates the QR block
#   qrData       — string to encode (e.g. https://hanryxvault.cards)
#
# We rasterise both to ESC/POS GS v 0 bit-image bytes so any compatible
# thermal printer (MUNBYN P047, Star, Epson clones) renders them correctly.
# Both helpers are wrapped in try/except → on any failure they return b"" so
# a corrupt logo or QR generation hiccup never breaks an actual sale receipt.

def _paper_width_px(conf: dict) -> int:
    """Pixels across one row at the printer head. 80 mm → 576, 58 mm → 384."""
    pw = str(conf.get("paper_width") or "58").strip()
    return 576 if pw == "80" else 384


def _image_to_escpos_raster(img, max_width_px: int) -> bytes:
    """Convert a PIL Image into ESC/POS GS v 0 raster bytes.

    - Dithers to 1-bit, resizes (preserving aspect) to fit within max_width_px.
    - Pads width up to a multiple of 8 (one byte per 8 horizontal pixels).
    - Inverts because PIL mode "1" stores 1=white, ESC/POS wants 1=black.
    Returns raw bytes ready to be written to the printer (no centering/init).
    """
    from PIL import Image as _PILImage

    if img.mode != "L":
        img = img.convert("L")
    # Floyd-Steinberg dither to 1-bit (PIL's default for L → 1).
    img = img.convert("1")
    w, h = img.size
    if w > max_width_px:
        new_h = max(1, int(h * (max_width_px / w)))
        img = img.resize((max_width_px, new_h), _PILImage.LANCZOS).convert("1")
        w, h = img.size
    # Pad width up to a multiple of 8 (extra pixels white = no print).
    if w % 8 != 0:
        pad = 8 - (w % 8)
        new_img = _PILImage.new("1", (w + pad, h), 1)  # 1 = white in mode "1"
        new_img.paste(img, (0, 0))
        img = new_img
        w = w + pad
    width_bytes = w // 8
    raw = img.tobytes()
    # PIL "1" packs MSB-first with 1=white; ESC/POS wants 1=print(black).
    inverted = bytes(b ^ 0xFF for b in raw)
    xL = width_bytes & 0xFF
    xH = (width_bytes >> 8) & 0xFF
    yL = h & 0xFF
    yH = (h >> 8) & 0xFF
    # GS v 0 m xL xH yL yH d1...dk  (m=0 → normal density)
    header = _GS + b'v0' + bytes([0, xL, xH, yL, yH])
    return header + inverted


def _render_logo_raster(b64_str: str, paper_width_px: int, *, max_w_frac: float = 0.50) -> bytes:
    """Decode a base64 logo and render to centered ESC/POS raster bytes.

    The header crest is capped at ~1.4" wide (≈50% of paper width) and
    ~1.2" tall (244 px at the printer's ~203 DPI), preserving the source
    aspect ratio. This stops oversized PNGs from the tablet eating 3"+
    of paper. Tweak the `max_w_frac` / `max_h_px` constants below to
    resize without rebuilding the APK.

    Returns b"" on any failure so the caller can safely concatenate.
    """
    try:
        from PIL import Image as _PILImage
        from io import BytesIO as _BytesIO
        from base64 import b64decode as _b64dec

        if not b64_str:
            return b""
        # Strip optional "data:image/png;base64," prefix the tablet may send.
        if "," in b64_str and b64_str.lstrip().lower().startswith("data:"):
            b64_str = b64_str.split(",", 1)[1]
        img = _PILImage.open(_BytesIO(_b64dec(b64_str)))

        # Crest size caps — caller can override max_w_frac to print a smaller
        # "seal" emblem (e.g. 0.28 above the QR) vs the full header logo.
        max_h_px = 244             # ~1.2" at 203 DPI
        max_w_px = max(80, int(paper_width_px * max_w_frac))

        w0, h0 = img.size
        scale = min(max_w_px / w0, max_h_px / h0, 1.0)
        if scale < 1.0:
            new_w = max(1, int(w0 * scale))
            new_h = max(1, int(h0 * scale))
            img = img.resize((new_w, new_h), _PILImage.LANCZOS)

        # Pass img.size[0] as max_width so _image_to_escpos_raster doesn't
        # try to scale up to paper width and undo our cap.
        raster = _image_to_escpos_raster(img, img.size[0])
        return _PR_CENTER + raster + _PR_LF + _PR_LEFT
    except Exception as e:
        try:
            log.warning("[print] logo render skipped: %s", e)
        except Exception:
            pass
        return b""


def _render_qr_raster(data: str, paper_width_px: int, *, max_w_frac: float = 0.40) -> bytes:
    """Generate a QR for `data` and render to centered ESC/POS raster bytes.

    QR defaults to ~40% of paper width (caller can override). Returns b"" on
    any failure. The smaller default is intentional: a 60% QR dominates the
    receipt for low-value sales and wastes thermal paper without helping the
    customer scan it any better.
    """
    try:
        if not data:
            return b""
        from PIL import Image as _PILImage

        target = max(120, int(paper_width_px * max_w_frac))
        qr = _qrcode.QRCode(
            version=None,
            error_correction=_qrcode_const.ERROR_CORRECT_M,
            box_size=10,
            border=2,
        )
        qr.add_data(data)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white").convert("L")
        if img.size[0] != target:
            img = img.resize((target, target), _PILImage.NEAREST)
        raster = _image_to_escpos_raster(img, paper_width_px)
        return _PR_CENTER + raster + _PR_LF + _PR_LEFT
    except Exception as e:
        try:
            log.warning("[print] QR render skipped: %s", e)
        except Exception:
            pass
        return b""


def _load_dragon_emblem_b64() -> str:
    """Load the dragon-only emblem PNG (lives on the Pi at assets/dragon_emblem.png)
    and return base64. Returns "" silently if the file is missing or unreadable
    so the receipt still prints fine without the seal."""
    try:
        import base64
        with open(_DRAGON_EMBLEM_PATH, "rb") as f:
            return base64.b64encode(f.read()).decode("ascii")
    except Exception:
        return ""


def _enrich_items_for_receipt(items: list) -> list:
    """Look up set_code / condition / language for each line item by qrCode and
    attach them as `_set_code`, `_condition`, `_language` keys (underscored to
    avoid colliding with anything the tablet might send in the future).

    Single batched query against `inventory`. Defensive: any DB hiccup falls
    back to the original items list — the receipt will still print, just
    without the rich subline.
    """
    if not items:
        return items
    qrs = [it.get("qrCode") or it.get("qr_code") for it in items]
    qrs = [q for q in qrs if q]
    if not qrs:
        return items

    by_qr = {}
    db = None
    try:
        db = _direct_db()
        placeholders = ",".join(["%s"] * len(qrs))
        rows = db.execute(
            f"SELECT qr_code, set_code, condition, language "
            f"FROM inventory WHERE qr_code IN ({placeholders})",
            qrs,
        ).fetchall()
        for r in rows:
            by_qr[r["qr_code"]] = dict(r)
    except Exception as _e:
        try: log.warning("[receipt] item enrichment skipped: %s", _e)
        except Exception: pass
    finally:
        if db:
            try: db.close()
            except Exception: pass

    out = []
    for it in items:
        qr   = it.get("qrCode") or it.get("qr_code") or ""
        meta = by_qr.get(qr) or {}
        enriched = dict(it)
        enriched["_set_code"]  = (meta.get("set_code")  or "").strip()
        enriched["_condition"] = (meta.get("condition") or "").strip()
        enriched["_language"]  = (meta.get("language")  or "").strip()
        out.append(enriched)
    return out


def _format_receipt(
    sale: dict,
    conf: dict,
    *,
    copy_label: str | None = None,
    include_disclosure: bool = True,
    emblem_b64: str | None = None,
) -> bytes:
    """Build ESC/POS byte string for one sale receipt.

    Premium B&W layout designed to FEEL professional on a single-color
    thermal printer:
      • Centered header logo (sent by tablet) with breathing room
      • Double-height bold store name + tagline
      • Optional COPY label (CUSTOMER COPY / MERCHANT COPY)
      • Friendly date + short receipt # (R-XXXXXX) + internal txn id
      • Detailed line items: qty, name, set/condition/language subline
      • Items count summary on the same row as the subtotal
      • Tax shows the rate ("Tax (6%)")
      • Bold TOTAL
      • Payment + change
      • Optional disclosure block (skipped on merchant copy by default)
      • Dragon emblem above the QR (loaded from assets/dragon_emblem.png)
      • Smaller QR (~40% paper width)
      • Branded thank-you line
    """
    header     = (conf.get("receipt_header")     or "HanryxVault").encode()
    subheader  = (conf.get("receipt_subheader")  or "Korean Pokemon TCG Specialists").encode()
    disclosure = (conf.get("receipt_disclosure") or "").strip()
    if not disclosure:
        disclosure = (
            "All sales are final. No refunds, returns, or exchanges. "
            "Cards are inspected and graded at point of sale; condition is "
            "accepted as-is once the receipt is issued. Authenticity is "
            "guaranteed on every card we sell."
        )

    # ── Paper-width-aware layout ─────────────────────────────────────────────
    # 58 mm = 32 chars / 384 px wide.  80 mm = 42 chars / 576 px wide.
    paper_w = _paper_width_px(conf)
    if paper_w >= 576:                # 80 mm
        char_w     = 42
        item_trunc = 27               # qty(2)+sp+name(27)+' $'+price(8) = 41
        div_thick  = _PR_DIVIDER_WIDE_BOLD
        div_thin   = _PR_DIVIDER_WIDE
    else:                             # 58 mm
        char_w     = 32
        item_trunc = 19               # qty(2)+sp+name(19)+' $'+price(8) = 32
        div_thick  = _PR_DIVIDER_NARR_BOLD
        div_thin   = _PR_DIVIDER_NARR

    timestamp = sale.get("timestamp", 0)
    dt_obj = (datetime.datetime.fromtimestamp(timestamp / 1000)
              if timestamp else datetime.datetime.now())
    # Friendly: "Apr 27, 2026  5:34 AM" — fall back if %-I not supported
    try:
        dt_str = dt_obj.strftime("%b %d, %Y  %-I:%M %p")
    except ValueError:
        dt_str = dt_obj.strftime("%b %d, %Y  %I:%M %p").replace(" 0", " ")

    txn_id   = (sale.get("transactionId") or sale.get("transaction_id") or "")
    short_no = ""
    if txn_id:
        digits = "".join(c for c in txn_id if c.isalnum())
        short_no = "R-" + digits[-6:].upper() if digits else ""

    method  = sale.get("paymentMethod") or sale.get("payment_method") or "CARD"
    items   = sale.get("items", []) or []

    def _row(left: str, right: str) -> bytes:
        """Pad `left` and `right` to fill exactly char_w columns."""
        pad = max(1, char_w - len(left) - len(right))
        return (left + (" " * pad) + right + "\n").encode()

    # ── Build receipt bytes ──────────────────────────────────────────────────
    out = bytearray()
    out += _PR_INIT

    # Dragon emblem at the very top (above the store name).
    if emblem_b64:
        out += _PR_LF
        out += _render_logo_raster(emblem_b64, paper_w, max_w_frac=0.42)

    # Optional header logo from the tablet — suppressed whenever the Pi has
    # its own dragon emblem so we don't double-stack two crests on the
    # receipt (the tablet's stored logo is often a big solid-black square
    # with the wordmark and just wastes paper next to the emblem).
    if not emblem_b64:
        logo_b64 = sale.get("logoBase64") or sale.get("logo_base64")
        if logo_b64:
            out += _render_logo_raster(logo_b64, paper_w)
    out += _PR_LF

    # Store name (double height) + tagline
    out += _PR_CENTER + _PR_DOUBLE + header + _PR_LF
    out += _PR_NORMAL + subheader + _PR_LF
    out += _PR_LEFT

    # COPY label (centered, bold, small)
    if copy_label:
        out += _PR_LF
        out += _PR_CENTER + _PR_BOLD_ON + copy_label.encode() + _PR_BOLD_OFF + _PR_LF
        out += _PR_LEFT

    out += _PR_LF + div_thick

    # ── Date + receipt numbers ───────────────────────────────────────────────
    out += f"{dt_str}\n".encode()
    if short_no:
        out += f"Receipt: {short_no}\n".encode()
    if txn_id:
        out += f"Txn:     {txn_id[:24]}\n".encode()
    out += div_thick

    # ── Line items ───────────────────────────────────────────────────────────
    item_count = 0
    for item in items:
        name  = (item.get("name") or "Item")
        qty   = int(item.get("qty") or item.get("quantity") or 1)
        price = float(item.get("unitPrice") or item.get("unit_price") or item.get("price") or 0)
        total = float(item.get("lineTotal") or item.get("line_total") or (price * qty))
        item_count += qty

        # Main: ` 1 Charizard ex                $  45.00`
        name_short = name[:item_trunc]
        out += f"{qty:>2} {name_short:<{item_trunc}} ${total:>7.2f}\n".encode()

        # Subline: set / condition / language — only if any are present
        sub_bits = []
        if item.get("_set_code"):
            sub_bits.append(item["_set_code"])
        cl = "/".join(b for b in (item.get("_condition", ""), item.get("_language", "")) if b)
        if cl:
            sub_bits.append(cl)
        if sub_bits:
            sub = "   " + " · ".join(sub_bits)
            out += (sub[:char_w] + "\n").encode()

        # Per-unit price line when qty > 1 (helps customer reconcile)
        if qty > 1:
            out += f"   ({qty} x ${price:.2f})\n".encode()

    out += div_thin

    # ── Totals ───────────────────────────────────────────────────────────────
    subtotal = float(sale.get("subtotal", 0))
    tax      = float(sale.get("taxAmount") or sale.get("tax_amount") or 0)
    tip      = float(sale.get("tipAmount") or sale.get("tip_amount") or 0)
    total    = float(sale.get("totalAmount") or sale.get("total_amount") or 0)

    # Items count + subtotal on a single row (left/right justified)
    out += _row(f"Items: {item_count}", f"Subtotal ${subtotal:>7.2f}")

    if tax > 0:
        # Derive the rate from subtotal so the customer sees the % they paid.
        rate_pct = ""
        if subtotal > 0:
            r = round((tax / subtotal) * 100, 1)
            rate_pct = f" ({r:g}%)"
        out += _row(f"Tax{rate_pct}", f"${tax:>7.2f}")
    if tip > 0:
        out += _row("Tip", f"${tip:>7.2f}")

    out += div_thin
    out += _PR_BOLD_ON
    out += _row("TOTAL", f"${total:>7.2f}")
    out += _PR_BOLD_OFF

    # ── Payment ──────────────────────────────────────────────────────────────
    out += div_thin
    out += f"Payment: {method}\n".encode()
    cash = float(sale.get("cashReceived") or sale.get("cash_received") or 0)
    if cash > 0:
        change = float(sale.get("changeGiven") or sale.get("change_given") or 0)
        out += _row(f"Cash:   ${cash:.2f}", f"Change: ${change:.2f}")

    out += div_thick

    # ── Disclosure (optional, skipped on merchant copy) ──────────────────────
    if include_disclosure and disclosure:
        import textwrap
        out += _PR_CENTER + _PR_BOLD_ON + b"DISCLOSURE\n" + _PR_BOLD_OFF + _PR_LEFT
        for raw_para in disclosure.split("\n"):
            wrapped = textwrap.wrap(raw_para, width=char_w) or [""]
            for line in wrapped:
                out += (line + "\n").encode()
        out += _PR_LF

    # ── QR code (smaller — 40% of paper width) ───────────────────────────────
    qr_enabled = sale.get("qrEnabled")
    if qr_enabled is None:
        qr_enabled = sale.get("qr_enabled", False)
    qr_data = (sale.get("qrData") or sale.get("qr_data") or "").strip()
    if qr_enabled and qr_data:
        out += _PR_CENTER + _PR_BOLD_ON + b"Check out the vault\n" + _PR_BOLD_OFF + _PR_LEFT
        out += _render_qr_raster(qr_data, paper_w, max_w_frac=0.40)

    # ── Thank-you (re-assert center after raster blocks left-align) ──────────
    out += _PR_CENTER
    out += b"Thank you for collecting with us!\n"
    out += _PR_NORMAL + _PR_LEFT

    # Cash drawer — only kick on the customer copy, never on the merchant copy.
    kick = sale.get("kickDrawer")
    if kick is None:
        kick = sale.get("kick_drawer", True)
    if kick and (copy_label is None or copy_label.upper().startswith("CUSTOMER")):
        out += _PR_KICK_DRAWER

    # Feed + cut
    out += _PR_LF * 4
    out += _PR_CUT

    return bytes(out)


def _print_over_network(host: str, port: int, payload: bytes, timeout: float = 5.0) -> bool:
    """Send raw ESC/POS bytes to a network thermal printer (RAW/JetDirect, port 9100).
    Used by MUNBYN P047 and most modern Ethernet receipt printers."""
    import socket
    try:
        with socket.create_connection((host, int(port)), timeout=timeout) as sock:
            sock.sendall(payload)
            # Most ESC/POS printers don't respond — just close cleanly.
            try:
                sock.shutdown(socket.SHUT_WR)
            except OSError:
                pass
        return True
    except Exception as e:
        log.error("[print] network send to %s:%s failed: %s", host, port, e)
        return False


def _do_print(sale: dict):
    """Background-thread print job — tries Network → BT/USB → CUPS in order.

    Builds 1 or 2 receipt copies (configurable on the Receipt Settings page).
    The merchant copy can optionally skip the disclosure block to save paper —
    you already know your own return policy. Both copies use the same
    enriched item list (DB lookup once) so they're identical apart from the
    COPY label and the disclosure block.

    Uses _open_printer_with_retry so a brief USB hot-replug (operator nudged
    the cable) doesn't fail the print — we'll wait up to ~1.6 s for the
    device node to come back before falling through to CUPS.
    """
    fh, path, conf = _open_printer_with_retry()

    # Merge rich receipt settings (store name, instagram, footer, etc.)
    rs = _load_receipt_settings()
    conf["receipt_header"]     = rs.get("store_name", conf.get("receipt_header", "HanryxVault"))
    conf["receipt_subheader"]  = rs.get("tagline",    conf.get("receipt_subheader", "Korean Pokemon TCG Specialists"))
    footer_parts = [p for p in [rs.get("website"), rs.get("instagram"), rs.get("phone")] if p]
    conf["receipt_footer"]     = "  |  ".join(footer_parts) if footer_parts else rs.get("footer_msg", "hanryxvault.cards")
    conf["paper_width"]        = rs.get("paper_width", "80")
    conf["receipt_disclosure"] = rs.get("disclosure", "")

    # Enrich items once (single DB query) so both copies print identical detail.
    enriched_sale = dict(sale)
    enriched_sale["items"] = _enrich_items_for_receipt(sale.get("items", []) or [])

    # Number of copies + whether merchant copy skips the disclosure.
    try:
        copies = max(1, min(2, int(rs.get("print_copies", 1))))
    except Exception:
        copies = 1
    merchant_skip = str(rs.get("merchant_skip_disclosure", "1")).lower() in ("1", "true", "on", "yes")

    emblem_b64 = _load_dragon_emblem_b64()

    try:
        if copies == 1:
            receipt_bytes = _format_receipt(
                enriched_sale, conf,
                copy_label=None,
                include_disclosure=True,
                emblem_b64=emblem_b64,
            )
        else:
            # Customer copy first (always with disclosure), then merchant copy.
            customer = _format_receipt(
                enriched_sale, conf,
                copy_label="CUSTOMER COPY",
                include_disclosure=True,
                emblem_b64=emblem_b64,
            )
            merchant = _format_receipt(
                enriched_sale, conf,
                copy_label="MERCHANT COPY",
                include_disclosure=not merchant_skip,
                emblem_b64=emblem_b64,
            )
            receipt_bytes = customer + merchant

        # ── Preferred path: Ethernet/network printer (MUNBYN P047 etc.) ─────
        net_host = conf.get("printer_network_host")
        net_port = conf.get("printer_network_port") or 9100
        if net_host:
            if _print_over_network(net_host, net_port, receipt_bytes):
                log.info("[print] Receipt sent to %s:%s", net_host, net_port)
                if fh:
                    try: fh.close()
                    except Exception: pass
                return
            log.warning("[print] network printer %s:%s unreachable — falling back to local devices", net_host, net_port)

        if fh is not None:
            try:
                fh.write(receipt_bytes)
                fh.flush()
                fh.close()
                log.info("[print] Receipt sent to %s", path)
            except OSError as werr:
                # Cable disconnected mid-write or device went away. Close, wait
                # for udev to recreate the node, reopen, and try one more time.
                log.warning("[print] write to %s failed (%s) — reopening once", path, werr)
                try: fh.close()
                except Exception: pass
                time.sleep(0.5)
                fh2, path2, _ = _open_printer_with_retry()
                if fh2 is not None and path2 != "cups":
                    try:
                        fh2.write(receipt_bytes)
                        fh2.flush()
                        fh2.close()
                        log.info("[print] Receipt sent to %s on retry", path2)
                    except OSError as werr2:
                        log.error("[print] retry write to %s also failed: %s", path2, werr2)
                        try: fh2.close()
                        except Exception: pass
                else:
                    log.error("[print] no printer available after retry — receipt lost")

        elif path == "cups":
            # Write temp file and submit via lp
            import tempfile
            with tempfile.NamedTemporaryFile(suffix=".bin", delete=False) as tmp:
                tmp.write(receipt_bytes)
                tmp_path = tmp.name
            result = subprocess.run(
                ["lp", "-o", "raw", tmp_path],
                capture_output=True, timeout=10
            )
            os.unlink(tmp_path)
            if result.returncode == 0:
                log.info("[print] Receipt submitted via CUPS lp")
            else:
                log.error("[print] CUPS lp failed: %s", result.stderr.decode())

        else:
            log.warning("[print] No printer found — receipt not printed")

    except Exception as e:
        log.error("[print] Print error: %s", e)
        if fh:
            try:
                fh.close()
            except Exception:
                pass


@app.route("/print/receipt", methods=["POST"])
def print_receipt():
    """
    Print a receipt on the connected Bluetooth or USB thermal printer.
    Body: sale JSON (same format as /sync/sales items).
    Tablet app calls this after every completed sale.
    Non-blocking — returns immediately, prints in background.
    """
    sale = request.get_json(force=True, silent=True) or {}
    if not sale:
        return jsonify({"error": "Sale JSON body required"}), 400

    _bg(_do_print, sale)
    return jsonify({"ok": True, "queued": True}), 202


@app.route("/print/status", methods=["GET"])
def print_status():
    """Returns which printer device is currently available.

    IMPORTANT: USB lp devices like /dev/usb/lp0 are exclusive — only one
    process can have them open at a time. If we leak the file handle here
    (even briefly until GC), concurrent print jobs or other gunicorn workers
    will get EBUSY and the route will start reporting 'cups' incorrectly.
    Close the handle synchronously the moment we have it.
    """
    fh, path, conf = _open_printer()
    if fh is not None:
        try:
            fh.close()
        except Exception:
            pass
    return jsonify({
        "printer_available": path is not None and path != "cups",
        "printer_path":      path,
        "bt_mac":            conf.get("printer_bt_mac"),
    })


