@app.route("/system/wg-peer-name", methods=["POST"])
@require_admin
def system_wg_peer_name():
    """Set a friendly name for a WireGuard peer public key."""
    data    = request.get_json(silent=True) or {}
    pubkey  = (data.get("pubkey") or "").strip()
    friendly = (data.get("name") or "").strip()[:64]
    if not pubkey:
        return jsonify({"error": "pubkey required"}), 400
    db = get_db()
    db.execute(
        "INSERT INTO wg_peer_names (pubkey, friendly_name) VALUES (%s,%s) "
        "ON CONFLICT(pubkey) DO UPDATE SET friendly_name=excluded.friendly_name",
        (pubkey, friendly)
    )
    db.commit()
    return jsonify({"ok": True, "pubkey": pubkey[:16] + "…", "name": friendly})


# ---------------------------------------------------------------------------
# /system/service-action  — restart / stop a systemd service
# ---------------------------------------------------------------------------

@app.route("/system/service-action", methods=["POST"])
@require_admin
def system_service_action():
    data    = request.get_json(silent=True) or {}
    action  = data.get("action", "")
    service = data.get("service", "")
    allowed_actions  = {"restart", "stop", "start", "status"}
    allowed_services = {svc for _, svc in _SYS_SERVICES}
    if action not in allowed_actions:
        return jsonify({"ok": False, "error": "Unknown action"}), 400
    if service not in allowed_services:
        return jsonify({"ok": False, "error": "Service not allowed"}), 400
    try:
        subprocess.Popen(
            ["sudo", "systemctl", action, service],
            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL
        )
        return jsonify({"ok": True, "message": f"{action} sent to {service}"})
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500


# ---------------------------------------------------------------------------
# /system/backup-db  — pg_dump the PostgreSQL database to a timestamped SQL file
# ---------------------------------------------------------------------------

@app.route("/system/backup-db", methods=["POST"])
@require_admin
def system_backup_db():
    import subprocess
    ts      = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    backup  = f"/app/data/vaultpos_backup_{ts}.sql"
    try:
        result = subprocess.run(
            ["pg_dump", "--no-password", DATABASE_URL, "-f", backup],
            capture_output=True, text=True, timeout=60,
        )
        if result.returncode != 0:
            return jsonify({"ok": False, "error": result.stderr.strip()}), 500
        size = os.path.getsize(backup)
        return jsonify({"ok": True, "path": backup, "size_kb": round(size / 1024, 1)})
    except FileNotFoundError:
        return jsonify({"ok": False, "error": "pg_dump not found — install postgresql-client"}), 500
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500


# ---------------------------------------------------------------------------
# /admin/ota-update  — git pull + docker compose rebuild, streamed live
# ---------------------------------------------------------------------------

_OTA_LOG:    list  = []     # rolling buffer of output lines (max 1000)
_OTA_LOCK         = threading.Lock()
_OTA_RUNNING      = False

@app.route("/admin/ota-update", methods=["POST"])
@require_admin
def admin_ota_update():
    global _OTA_RUNNING
    with _OTA_LOCK:
        if _OTA_RUNNING:
            return jsonify({"ok": False, "error": "Update already in progress"}), 409
        _OTA_RUNNING = True
        _OTA_LOG.clear()

    def _run() -> None:
        global _OTA_RUNNING
        try:
            env = {**os.environ, "DOCKER_CLI_HINTS": "false"}
            if os.environ.get("HANRYX_DEBUG_INSECURE_GIT", "0") == "1":
                _OTA_LOG.append(
                    "WARNING: HANRYX_DEBUG_INSECURE_GIT=1 set, disabling SSL "
                    "verification for git. Do NOT use in production.\n"
                )
                # hanryx-allow-insecure: gated by HANRYX_DEBUG_INSECURE_GIT, logs a warning. See replit.md "Security Policy — TLS verification".
                env["GIT_SSL_NO_VERIFY"] = "1"
            else:
                # hanryx-allow-insecure: secure default — clears the bypass env var.
                env.pop("GIT_SSL_NO_VERIFY", None)
            repo_dir   = os.environ.get("REPO_DIR", "/app")
            compose    = os.path.join(repo_dir, "pi-setup", "docker-compose.yml")
            cmds = [
                ["git", "-C", repo_dir, "pull", "--ff-only", "origin", "main"],
                ["docker", "compose", "-f", compose, "up", "-d", "--build",
                 "--remove-orphans"],
            ]
            for cmd in cmds:
                _OTA_LOG.append(f"$ {' '.join(cmd)}\n")
                try:
                    proc = subprocess.Popen(
                        cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                        text=True, env=env, bufsize=1,
                    )
                    for line in proc.stdout:
                        _OTA_LOG.append(line)
                        if len(_OTA_LOG) > 1000:
                            _OTA_LOG.pop(0)
                    proc.wait()
                    _OTA_LOG.append(f"[exit {proc.returncode}]\n")
                except FileNotFoundError as fe:
                    _OTA_LOG.append(f"[command not found: {fe}]\n")
        except Exception as exc:
            _OTA_LOG.append(f"ERROR: {exc}\n")
        finally:
            _OTA_LOG.append("__DONE__\n")
            _OTA_RUNNING = False

    threading.Thread(target=_run, daemon=True).start()
    return jsonify({"ok": True, "message": "Update started — watch the log stream."})


@app.route("/admin/ota-stream", methods=["GET"])
@require_admin
def admin_ota_stream():
    """SSE stream that tails _OTA_LOG until __DONE__ is emitted."""
    def generate():
        sent = 0
        while True:
            while sent < len(_OTA_LOG):
                line = _OTA_LOG[sent]
                sent += 1
                yield f"data: {json.dumps({'line': line})}\n\n"
                if line.strip() == "__DONE__":
                    return
            time.sleep(0.15)
    return Response(
        generate(),
        mimetype="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )


# ---------------------------------------------------------------------------
# /satellite/heartbeat  — satellite Pi registers itself here every 60 s
# /satellite/status     — admin reads last heartbeat
# ---------------------------------------------------------------------------

_SAT_HB_PATH = "/data/satellite_heartbeat.json"


@app.route("/satellite/heartbeat", methods=["POST"])
def satellite_heartbeat():
    """Called by the satellite Pi launcher (no auth needed — Tailscale only)."""
    try:
        body = request.get_json(silent=True) or {}
        data = {
            "ip":          body.get("ip") or request.remote_addr,
            "ts_ip":       str(body.get("ts_ip", "")),
            "uptime":      str(body.get("uptime", "")),
            "chromium_ok": bool(body.get("chromium_ok", True)),
            "tailscale":   str(body.get("tailscale", "unknown")),
            "last_seen":   _time.time(),
            "version":     str(body.get("version", "v5")),
        }
        os.makedirs(os.path.dirname(_SAT_HB_PATH), exist_ok=True)
        with open(_SAT_HB_PATH, "w") as fh:
            json.dump(data, fh)
        return jsonify({"ok": True})
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500


@app.route("/satellite/status", methods=["GET"])
@require_admin
def satellite_status():
    try:
        with open(_SAT_HB_PATH) as fh:
            data = json.load(fh)
        age = _time.time() - data.get("last_seen", 0)
        data["age_s"]  = round(age)
        data["online"] = age < 90     # heartbeat every 60 s → 90 s grace
        return jsonify(data)
    except FileNotFoundError:
        return jsonify({"online": False, "ip": None, "age_s": None, "uptime": ""})
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500


