@app.route("/api/v1/stock-alerts", methods=["GET"])
@require_admin
def api_list_stock_alerts():
    """
    List low-stock alert configs.  Only sealed products appear here — singles are excluded.
    Query params: ?eligible=1 lists all sealed products in inventory (for adding alerts).
    """
    db = get_db()

    # ?eligible=1 → return all sealed products that could have an alert configured
    if request.args.get("eligible"):
        rows = db.execute(
            "SELECT i.qr_code, i.name, i.stock, i.item_type, "
            "   lsc.threshold, lsc.alerted "
            "FROM inventory i "
            "LEFT JOIN low_stock_config lsc ON lsc.qr_code=i.qr_code "
            "WHERE LOWER(i.item_type) NOT IN ('single', 'card', '') "
            "ORDER BY i.item_type, i.name"
        ).fetchall()
        return jsonify([dict(r) for r in rows])

    rows = db.execute(
        "SELECT lsc.qr_code, lsc.threshold, lsc.alerted, i.name, i.stock, i.item_type "
        "FROM low_stock_config lsc "
        "LEFT JOIN inventory i ON i.qr_code=lsc.qr_code "
        "WHERE LOWER(COALESCE(i.item_type,'')) NOT IN ('single', 'card') "
        "ORDER BY i.name"
    ).fetchall()
    return jsonify([dict(r) for r in rows])


@app.route("/api/v1/stock-alerts", methods=["POST"])
@require_admin
def api_set_stock_alert():
    """
    Set a low-stock alert threshold for a product.
    Only valid for sealed products (booster packs, ETBs, boxes, etc.).
    Individual card singles are excluded — use reorder logic for those.
    """
    body      = request.get_json(silent=True) or {}
    qr_code   = (body.get("qr_code") or "").strip()
    threshold = max(1, _safe_int(body.get("threshold") or 1, 1))
    if not qr_code:
        return jsonify({"error": "qr_code required"}), 400

    db = get_db()
    # Validate item_type — reject individual card singles
    item_row = db.execute(
        "SELECT name, item_type FROM inventory WHERE qr_code=%s", (qr_code,)
    ).fetchone()
    if item_row and item_row["item_type"] and \
            item_row["item_type"].lower() in ("single", "card"):
        return jsonify({
            "error": "Low-stock alerts are for sealed products only (booster packs, boxes, ETBs). "
                     f"'{item_row['name']}' is a {item_row['item_type']}."
        }), 422

    db.execute(
        "INSERT INTO low_stock_config (qr_code, threshold, alerted) VALUES (%s, %s, 0) "
        "ON CONFLICT (qr_code) DO UPDATE SET threshold=EXCLUDED.threshold, alerted=0",
        (qr_code, threshold)
    )
    db.commit()
    _audit_write("stock_alert.set", qr_code, f"threshold={threshold}")
    item_name = item_row["name"] if item_row else qr_code
    return jsonify({"ok": True, "qr_code": qr_code, "name": item_name, "threshold": threshold}), 201


@app.route("/api/v1/stock-alerts/<path:qr_code>", methods=["DELETE"])
@require_admin
def api_delete_stock_alert(qr_code):
    db = get_db()
    db.execute("DELETE FROM low_stock_config WHERE qr_code=%s", (qr_code,))
    db.commit()
    _audit_write("stock_alert.delete", qr_code)
    return jsonify({"ok": True})


def _run_low_stock_checker():
    """Background thread: check every 15 min, email when stock drops below threshold."""
    import time as _t
    _t.sleep(60)   # give the server 60 s to finish startup
    while True:
        try:
            db = _direct_db()
            # Only alert for sealed/product items — never individual card singles
            rows = db.execute(
                "SELECT lsc.qr_code, lsc.threshold, lsc.alerted, i.name, i.stock, i.item_type "
                "FROM low_stock_config lsc "
                "JOIN inventory i ON i.qr_code=lsc.qr_code "
                "WHERE i.stock <= lsc.threshold AND lsc.alerted=0 "
                "AND LOWER(i.item_type) NOT IN ('single', 'card')"
            ).fetchall()
            for r in rows:
                cfg = _get_email_cfg()
                if cfg["enabled"]:
                    def _send_alert(name=r["name"], stock=r["stock"], threshold=r["threshold"],
                                    qr=r["qr_code"]):
                        try:
                            import smtplib as _sm, email.mime.multipart as _mm, email.mime.text as _mt
                            c = _get_email_cfg()
                            msg = _mm.MIMEMultipart("alternative")
                            msg["Subject"] = f"⚠️ Low Stock: {name} ({stock} left)"
                            msg["From"]    = f"HanryxVault <{c['user']}>"
                            msg["To"]      = c["notify"]
                            html = (f"<h2>Low Stock Alert</h2>"
                                    f"<p><strong>{name}</strong> ({qr}) is at <strong>{stock}</strong> "
                                    f"unit(s) — threshold: {threshold}.</p>"
                                    f"<p>Please reorder stock.</p>")
                            msg.attach(_mt.MIMEText(html, "html"))
                            with _sm.SMTP("smtp.gmail.com", 587, timeout=15) as sv:
                                sv.ehlo(); sv.starttls()
                                sv.login(c["user"], c["password"])
                                sv.sendmail(c["user"], c["notify"], msg.as_string())
                            log.info("[low-stock] Alert sent for %s (stock=%s)", name, stock)
                        except Exception as _e:
                            log.warning("[low-stock] Email failed: %s", _e)
                    _bg(_send_alert)
                db.execute(
                    "UPDATE low_stock_config SET alerted=1 WHERE qr_code=%s", (r["qr_code"],)
                )
            db.commit()
            db.close()
        except Exception as _e:
            try: db.close()
            except Exception: pass
            log.debug("[low-stock] checker error: %s", _e)
        import time as _t2; _t2.sleep(900)   # 15 min


# ---------------------------------------------------------------------------
# 8. PDF receipt for an individual sale — GET /api/v1/sales/<id>/receipt.pdf
# ---------------------------------------------------------------------------

@app.route("/api/v1/sales/<int:sale_id>/receipt.pdf", methods=["GET"])
@require_admin
def api_sale_receipt_pdf(sale_id):
    try:
        from reportlab.lib.pagesizes import A6
        from reportlab.lib import colors as _rlc
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
        from reportlab.lib.styles import getSampleStyleSheet
        from reportlab.lib.units import cm
    except ImportError:
        return jsonify({"error": "reportlab not installed"}), 501

    db  = get_db()
    row = db.execute("SELECT * FROM sales WHERE id=%s", (sale_id,)).fetchone()
    if not row:
        return jsonify({"error": "Sale not found"}), 404

    buf  = io.BytesIO()
    doc  = SimpleDocTemplate(buf, pagesize=A6, rightMargin=1*cm, leftMargin=1*cm,
                              topMargin=1*cm, bottomMargin=1*cm)
    ss   = getSampleStyleSheet()
    gold = _rlc.HexColor("#d4a843")

    def _lbl(text, size=9, bold=False):
        s = ss["Normal"].clone("l"); s.fontSize = size; s.spaceAfter = 2
        if bold: s.fontName = "Helvetica-Bold"
        return Paragraph(text, s)

    items_json = row.get("items") or "[]"
    try:
        items = json.loads(items_json) if isinstance(items_json, str) else items_json
    except Exception:
        items = []

    elems = [
        _lbl("HanryxVault", 14, bold=True),
        _lbl(f"Receipt #{sale_id}", 10),
        _lbl(datetime.datetime.fromtimestamp(row["sold_at"]/1000).strftime("%d %b %Y %H:%M"), 9),
        Spacer(1, 0.3*cm),
    ]

    if items:
        tdata = [["Item", "Qty", "Price"]] + [
            [i.get("name","")[:30], str(i.get("quantity",1)), f"${float(i.get('price',0)):.2f}"]
            for i in items
        ]
        t = Table(tdata, colWidths=[7*cm, 1.5*cm, 2.5*cm])
        t.setStyle(TableStyle([
            ("BACKGROUND", (0,0), (-1,0), gold),
            ("FONTNAME",   (0,0), (-1,0), "Helvetica-Bold"),
            ("FONTSIZE",   (0,0), (-1,-1), 8),
            ("GRID",       (0,0), (-1,-1), 0.3, _rlc.grey),
            ("LEFTPADDING",  (0,0), (-1,-1), 4),
            ("RIGHTPADDING", (0,0), (-1,-1), 4),
        ]))
        elems.append(t)
        elems.append(Spacer(1, 0.3*cm))

    total = float(row.get("sale_price") or row.get("total_price") or 0)
    method = row.get("payment_method") or "POS"
    elems += [
        _lbl(f"<b>Total: ${total:.2f}</b>", 11, bold=True),
        _lbl(f"Payment: {method}", 9),
        Spacer(1, 0.3*cm),
        _lbl("Thank you for your purchase!", 8),
    ]

    doc.build(elems)
    buf.seek(0)
    return send_file(buf, mimetype="application/pdf",
                     as_attachment=True, download_name=f"receipt-{sale_id}.pdf")


# ---------------------------------------------------------------------------
# 9. Connection pool health — GET /api/v1/health/pool
# ---------------------------------------------------------------------------

@app.route("/api/v1/health/pool", methods=["GET"])
@require_admin
def api_health_pool():
    pool = _get_pool()
    try:
        used = len(pool._used) if hasattr(pool, "_used") else "?"
        free = len(pool._pool) if hasattr(pool, "_pool") else "?"
        mx   = pool.maxconn   if hasattr(pool, "maxconn") else "?"
    except Exception:
        used = free = mx = "?"
    return jsonify({
        "pool_used":  used,
        "pool_free":  free,
        "pool_max":   mx,
        "status":     "ok" if used != "?" and used < (mx or 999) else "unknown",
    })


# ---------------------------------------------------------------------------
# Intelligent pricing engine
# ---------------------------------------------------------------------------
# Ported from the Node.js implementation:
#   - Multi-language card input normalisation via Google Translate
#   - eBay sold-listing scraper (3 pages in parallel)
#   - Score-based listing filter (name, number, set matching)
#   - Outlier-robust price model (median / mean / confidence)
#   - PostgreSQL-backed translation + pricing cache
#   - Redis-backed short-TTL pricing cache (10 min)
# ---------------------------------------------------------------------------

import statistics as _stats_mod


def _translate_with_cache(text: str, target_lang: str) -> str:
    """Translate text to target_lang, using the DB cache to avoid repeat API calls."""
    if not text or not _TRANSLATE_OK:
        return text
    if target_lang == "en" and all(ord(c) < 128 for c in text):
        return text  # already ASCII English — skip API
    try:
        db = _direct_db()
        row = db.execute(
            "SELECT translated FROM translation_cache WHERE original=%s AND lang=%s",
            (text, target_lang),
        ).fetchone()
        if row:
            db.close()
            return row["translated"]
        translated = _GoogleTranslator(source="auto", target=target_lang).translate(text)
        db.execute(
            "INSERT INTO translation_cache (original, lang, translated) VALUES (%s,%s,%s) "
            "ON CONFLICT (original, lang) DO UPDATE SET translated=EXCLUDED.translated",
            (text, target_lang, translated),
        )
        db.commit()
        db.close()
        return translated
    except Exception as _e:
        try: db.close()
        except Exception: pass
        log.debug("[translate] failed for %r → %s: %s", text[:30], target_lang, _e)
        return text


def _translate_card_input(card: dict, lang: str = "en") -> dict:
    """Normalise a card dict to English so eBay queries work correctly."""
    if lang == "en":
        return card
    return {
        "name":         _translate_with_cache(card.get("name", ""), "en"),
        "set":          _translate_with_cache(card.get("set", ""), "en") if card.get("set") else None,
        "number":       card.get("number"),
        "original_lang": lang,
    }


def _score_listing(title: str, card: dict) -> int:
    """
    Score an eBay listing against a card spec.
    Returns an integer; listings scoring < 6 are discarded.

    Positive signals:  name match (+5), number match (+5), set match (+3),
                       pokémon mention (+1)
    Negative signals:  ungraded card with PSA in title (−5),
                       bulk/lot keywords (−8, enough to always fail threshold)
    """
    t = title.lower()
    score = 0

    name = (card.get("name") or "").lower()
    if name and name in t:
        score += 5

    number = card.get("number") or ""
    if number and number in t:
        score += 5

    set_name = (card.get("set") or "").lower()
    if set_name and set_name in t:
        score += 3

    if "pokemon" in t or "pokémon" in t:
        score += 1

    # Graded-card penalty for raw lookups
    if card.get("grade", "raw") == "raw" and "psa" in t:
        score -= 5

    # Bulk-lot penalty — heavy enough to always drop below the 6-point threshold
    if any(kw in t for kw in _BULK_KEYWORDS):
        score -= 8

    return score


def _filter_and_score(items: list, card: dict) -> list:
    """
    Sanitise bulk lots, score every listing, keep score >= 6, sort descending.
    _sanitize_listings runs first as a fast pre-filter (no scoring overhead).
    """
    clean = _sanitize_listings(items)
    scored = [
        {**item, "score": _score_listing(item.get("title", ""), card)}
        for item in clean
    ]
    return sorted(
        (i for i in scored if i["score"] >= 6),
        key=lambda x: x["score"],
        reverse=True,
    )


def _filter_and_score_lang(items: list, card: dict) -> list:
    """
    Lenient scorer for non-English language eBay listings.

    Foreign-language listings (JP, KR, CN, TW) won't contain the English
    card name in their title, so the standard scorer's +5 name-match bonus
    is unavailable — every card would fail the ≥6 threshold even when it is
    exactly the right card.

    Changes vs the English scorer:
      • Threshold lowered to ≥ 2 (vs 6)
      • Name-match and set-name checks dropped (foreign titles won't match)
      • Card-number check kept (+5) — numbers are the same in every language
      • "pokemon" mention kept (+1) — appears in many foreign listings
      • Graded-card penalty kept (−5 for PSA on raw lookups)
      • Bulk-lot penalty kept (−8, belt-and-braces after _sanitize_listings)
    """
    clean = _sanitize_listings(items)
    scored = []
    for item in clean:
        t     = (item.get("title") or "").lower()
        score = 0

        number = card.get("number") or ""
        if number and number in t:
            score += 5

        if "pokemon" in t or "pokémon" in t:
            score += 1

        if card.get("grade", "raw") == "raw" and "psa" in t:
            score -= 5

        if any(kw in t for kw in _BULK_KEYWORDS):
            score -= 8

        if score >= 2:
            scored.append({**item, "score": score})

    return sorted(scored, key=lambda x: x["score"], reverse=True)


# Keywords that indicate bulk lots — excluded before price modelling
_BULK_KEYWORDS = frozenset([
    "lot", "bundle", "collection", "bulk", "joblot",
    "x10", "x20", "x25", "x50", "x100",
    "10x", "20x", "25x", "50x", "100x",
    "mixed lot", "random lot",
])


def _sanitize_listings(items: list[dict]) -> list[dict]:
    """
    Strip bulk-lot and obviously bad listings before scoring or price modelling.
    Keeps individual card listings only.
    """
    clean = []
    for item in items:
        title = item.get("title", "").lower()
        if any(kw in title for kw in _BULK_KEYWORDS):
            continue
        # Skip placeholder / free-shipping-only listings (price < $0.25)
        if (item.get("price") or 0) < 0.25:
            continue
        clean.append(item)
    return clean


def _remove_outliers(prices: list[float]) -> list[float]:
    """
    IQR-based outlier removal — robust against the right-skewed distributions
    typical of Pokémon card prices.

    Method (Tukey's fences):
      lo = Q1 − 1.5 × IQR
      hi = Q3 + 1.5 × IQR

    If IQR is 0 (cluster of identical prices) we fall back to ±60 % of the
    median so a handful of ludicrously high listings still get clipped.
    Always returns the original list when filtering would leave nothing.
    """
    prices = sorted(p for p in prices if p >= 0.25)   # hard floor
    if len(prices) < 3:
        return prices

    n   = len(prices)
    q1  = prices[n // 4]
    q3  = prices[(n * 3) // 4]
    iqr = q3 - q1

    if iqr == 0:
        median = prices[n // 2]
        lo, hi = median * 0.40, median * 1.60
    else:
        lo = q1 - 1.5 * iqr
        hi = q3 + 1.5 * iqr

    filtered = [p for p in prices if lo <= p <= hi]
    return filtered or prices   # never discard everything


def _build_price_model(items: list) -> dict:
    """
    Build a price model from scored listings.
    Runs sanitisation → IQR outlier removal → statistics.
    Returns market (median), average, low, high, confidence, sample_size,
    plus iqr_bounds so callers know what was kept.
    """
    # Sanitise bulk lots / junk first
    clean  = _sanitize_listings(items)
    raw_prices = [i["price"] for i in clean if i.get("price")]
    prices = sorted(_remove_outliers(raw_prices))

    if not prices:
        return {
            "market": None, "average": None, "low": None, "high": None,
            "confidence": 0, "sample_size": 0,
            "raw_sample": len(raw_prices), "iqr_bounds": None,
        }

    n      = len(prices)
    q1     = prices[n // 4]
    q3     = prices[(n * 3) // 4]
    # Trimmed median: drop top & bottom 20 % before taking the centre.
    # IQR removal above already handles wild outliers; this extra trim
    # protects against the soft right-skew typical of TCG singles
    # (e.g. one PSA-graded ringer in a sample of raws). Only applied
    # when sample is large enough that trimming still leaves >=3 points.
    if n >= 5:
        trim   = max(1, int(n * 0.20))
        core   = prices[trim : n - trim]
        median = core[len(core) // 2] if core else prices[n // 2]
    else:
        median = prices[n // 2]
    avg    = sum(prices) / n

    return {
        "market":      round(median, 2),
        "average":     round(avg, 2),
        "low":         round(prices[0], 2),
        "high":        round(prices[-1], 2),
        "confidence":  min(round(n / 20, 2), 1.0),
        "sample_size": n,
        "raw_sample":  len(raw_prices),      # before outlier removal
        "iqr_bounds":  {"lo": round(q1 - 1.5 * (q3 - q1), 2),
                        "hi": round(q3 + 1.5 * (q3 - q1), 2)},
    }


_EBAY_DATE_FMTS = (
    "%b %d, %Y",   # Nov 15, 2024
    "%d %b, %Y",   # 15 Nov, 2024
    "%B %d, %Y",   # November 15, 2024
    "%d %B %Y",    # 15 November 2024
    "%b %d %Y",    # Nov 15 2024
)


def _parse_ebay_date(raw: str) -> "datetime.date | None":
    """Parse an eBay sold-date string like 'Sold Nov 15, 2024' into a date."""
    clean = re.sub(r"^(sold|ended)\s*", "", raw.strip(), flags=re.IGNORECASE)
    clean = re.sub(r"\s+", " ", clean).strip()
    for fmt in _EBAY_DATE_FMTS:
        try:
            return datetime.datetime.strptime(clean, fmt).date()
        except ValueError:
            pass
    return None



# ---------------------------------------------------------------------------
# eBay Finding API — replaces HTML scraping
# ---------------------------------------------------------------------------
# Set EBAY_APP_ID (Client ID) and EBAY_CERT_ID (Client Secret) in .env
# The Finding API only needs EBAY_APP_ID; EBAY_CERT_ID is used to auto-fetch
# OAuth tokens for the Browse API if needed in future.
# ---------------------------------------------------------------------------

_EBAY_APP_ID  = os.environ.get("EBAY_APP_ID", "")
_EBAY_CERT_ID = os.environ.get("EBAY_CERT_ID", "")
_EBAY_FINDING_URL = "https://svcs.ebay.com/services/search/FindingService/v1"

# Thread-safe OAuth token cache
_ebay_token_lock  = threading.Lock()
_ebay_token_cache: dict = {}   # {"token": str, "expires": float}


def _ebay_app_token() -> str:
    """
    Return a valid eBay OAuth application token, refreshing when expired.
    Uses the Client Credentials Grant (no user interaction needed).
    Returns "" when credentials are not configured.
    """
    if not _EBAY_APP_ID or not _EBAY_CERT_ID:
        return ""
    with _ebay_token_lock:
        if _ebay_token_cache.get("token") and time.time() < _ebay_token_cache.get("expires", 0) - 60:
            return _ebay_token_cache["token"]
        try:
            import base64 as _b64
            creds = _b64.b64encode(f"{_EBAY_APP_ID}:{_EBAY_CERT_ID}".encode()).decode()
            r = _requests.post(
                "https://api.ebay.com/identity/v1/oauth2/token",
                headers={
                    "Authorization": f"Basic {creds}",
                    "Content-Type": "application/x-www-form-urlencoded",
                },
                data="grant_type=client_credentials&scope=https%3A%2F%2Fapi.ebay.com%2Foauth%2Fapi_scope",
                timeout=10,
            )
            r.raise_for_status()
            data = r.json()
            _ebay_token_cache["token"]   = data["access_token"]
            _ebay_token_cache["expires"] = time.time() + int(data.get("expires_in", 7200))
            log.info("[ebay] OAuth token refreshed, expires in %ss", data.get("expires_in"))
            return _ebay_token_cache["token"]
        except Exception as _e:
            log.warning("[ebay] token refresh failed: %s", _e)
            return ""


# Active-asking → estimated-sold ratio. eBay sold prices on TCG singles
# typically clear at ~78–82% of asking; 0.80 is the safe centre.
_EBAY_ACTIVE_TO_SOLD_RATIO = 0.80


def _ebay_browse_active_page(query: str, page: int) -> list[dict]:
    """
    Fallback when the legacy Finding API's `findCompletedItems` op is rate-
    limited (eBay throttles non-partner apps to ~5 calls/day) or returns
    nothing. Hits the modern, unrestricted Browse API for ACTIVE listings
    and applies _EBAY_ACTIVE_TO_SOLD_RATIO to estimate sold prices.

    Each returned dict carries `_estimated: True` so callers/UI can show
    a distinct badge ("asking-derived" vs true sold).
    """
    if not _EBAY_APP_ID or not _EBAY_CERT_ID:
        return []
    token = _ebay_app_token()
    if not token:
        return []
    try:
        r = _requests.get(
            "https://api.ebay.com/buy/browse/v1/item_summary/search",
            headers={
                "Authorization":          f"Bearer {token}",
                "X-EBAY-C-MARKETPLACE-ID": "EBAY_US",
            },
            params={
                "q":            query,
                "category_ids": "183050",   # Pokémon Individual Cards
                "limit":        100,
                "offset":       (max(page, 1) - 1) * 100,
                "filter":       "buyingOptions:{FIXED_PRICE|AUCTION}",
            },
            timeout=12,
        )
        r.raise_for_status()
        items = (r.json() or {}).get("itemSummaries", []) or []
    except Exception as _e:
        log.debug("[ebay] browse fallback page %d failed: %s", page, _e)
        return []

    today = datetime.date.today()
    out: list[dict] = []
    for it in items:
        try:
            title = (it.get("title") or "").strip()
            if not title:
                continue
            raw_price = (it.get("price") or {}).get("value")
            if raw_price is None:
                continue
            raw = float(raw_price)
            if raw <= 0:
                continue
            est = round(raw * _EBAY_ACTIVE_TO_SOLD_RATIO, 2)
            # Spread synthetic "sold dates" using listing creation date so
            # period buckets (7d/30d/90d) aren't all dumped into today.
            d_str = it.get("itemCreationDate") or ""
            try:
                sold_date = (
                    datetime.datetime.fromisoformat(d_str.replace("Z", "+00:00")).date()
                    if d_str else today
                )
            except Exception:
                sold_date = today
            out.append({
                "title":            title,
                "price":            est,
                "sold_date":        sold_date,
                "_estimated":       True,
                "_raw_active_price": raw,
            })
        except Exception:
            continue
    return out


def _ebay_finding_page(query: str, page: int) -> list[dict]:
    """
    Fetch one page of eBay completed/sold listings via the Finding API.
    Returns [{title, price, sold_date}] — no HTML parsing needed.

    Category 183050 = Pokémon Individual Cards.
    Falls back to empty list when EBAY_APP_ID is not set.
    """
    if not _EBAY_APP_ID:
        log.debug("[ebay] EBAY_APP_ID not set — skipping API call")
        return []

    params = {
        "OPERATION-NAME":          "findCompletedItems",
        "SERVICE-VERSION":         "1.0.0",
        "SECURITY-APPNAME":        _EBAY_APP_ID,
        "RESPONSE-DATA-FORMAT":    "JSON",
        "REST-PAYLOAD":            "",
        "keywords":                query,
        "categoryId":              "183050",
        "itemFilter(0).name":      "SoldItemsOnly",
        "itemFilter(0).value":     "true",
        "itemFilter(1).name":      "ListingType",
        "itemFilter(1).value(0)":  "FixedPrice",
        "itemFilter(1).value(1)":  "Auction",
        "itemFilter(1).value(2)":  "AuctionWithBIN",
        "paginationInput.pageNumber":     str(page),
        "paginationInput.entriesPerPage": "100",
        "sortOrder":               "EndTimeSoonest",
    }
    # eBay fully sunset findCompletedItems in Feb 2025 — every call now
    # returns 500 Internal Server Error for non-partner apps and burns
    # ~300ms of timeout per page (×3 pages = ~1s of cold-lookup latency
    # on every card). Skip it entirely and go straight to the Browse API
    # "active × 0.80" estimator. We only fetch page 1 because Browse is
    # paginated independently and 100 active listings is more than enough
    # signal for a price median.
    #
    # Set HANRYX_EBAY_TRY_FINDING=1 in .env if you happen to acquire a
    # partner-tier eBay app key that retains Finding API access.
    if page > 1:
        return []
    if os.environ.get("HANRYX_EBAY_TRY_FINDING") == "1":
        try:
            r = _requests.get(_EBAY_FINDING_URL, params=params, timeout=12)
            r.raise_for_status()
            data = r.json()
            resp = data.get("findCompletedItemsResponse", [{}])[0]
            search = resp.get("searchResult", [{}])[0]
            raw_items = search.get("item", [])
            if raw_items:
                # ... existing parser path below would handle this, but
                # since we never get here in production we just fall
                # through to Browse for simplicity.
                pass
        except Exception as _e:
            log.debug("[ebay] finding API attempt failed (%s)", _e)
    fb = _ebay_browse_active_page(query, page)
    if fb:
        log.info("[ebay] Browse API returned %d active listings for %r "
                 "(estimated sold = active × %.2f)",
                 len(fb), query, _EBAY_ACTIVE_TO_SOLD_RATIO)
    return fb

    results = []
    for it in raw_items:
        try:
            title = (it.get("title") or [""])[0]
            if not title:
                continue

            # Price
            selling = (it.get("sellingStatus") or [{}])[0]
            cp      = (selling.get("currentPrice") or [{}])[0]
            price   = float(cp.get("__value__", 0))
            if price <= 0:
                continue

            # Only include items that actually sold
            state = (selling.get("sellingState") or [""])[0].lower()
            if "sales" not in state and "sold" not in state:
                continue

            # End time → sold date
            listing  = (it.get("listingInfo") or [{}])[0]
            end_raw  = (listing.get("endTime") or [""])[0]
            sold_date = None
            if end_raw:
                try:
                    sold_date = datetime.datetime.fromisoformat(
                        end_raw.replace("Z", "+00:00")
                    ).date()
                except Exception:
                    pass

            results.append({"title": title, "price": price, "sold_date": sold_date})
        except Exception:
            continue

    # If sold-listings call returned nothing (rate-limited at ~5/day, or
    # genuinely no completed sales), fall back to active listings × 0.80
    # so the panel isn't left empty. Only fall back on page 1 — the Browse
    # API is paginated independently.
    if not results and page == 1:
        fb = _ebay_browse_active_page(query, page)
        if fb:
            log.info("[ebay] findCompletedItems empty/rate-limited for %r — "
                     "fell back to Browse API (%d active listings)", query, len(fb))
        return fb

    return results


# Keep these thin wrappers so existing call-sites (_fetch_ebay_sales, etc.) work unchanged
def _fetch_ebay_page(query: str, page: int) -> list:
    """Compatibility shim — now returns a list[dict] via the Finding API."""
    return _ebay_finding_page(query, page)


def _parse_ebay_page(raw) -> list[dict]:
    """Compatibility shim — raw is already a list[dict] from _fetch_ebay_page."""
    if isinstance(raw, list):
        return raw
    return []


_LANG_QUERY_SUFFIXES: dict[str, str] = {
    "jp": "japanese",
    "kr": "korean",
    "cn": "chinese simplified",
    "tw": "traditional chinese",
}


# ── Option B: native-market language pricing ─────────────────────────────────
# eBay's category 183050 (Pokémon Individual Cards) under-indexes foreign-
# language listings, and `_filter_and_score_lang` is too strict for raw eBay
# JP/KR titles. So for each language chip we cross-reference cards_master to
# get the *native* card name (e.g. EN "Charizard" → KR "리자몽" / JP "リザード"),
# then fan out to language-appropriate pricing sources that DO understand
# native names: tcgkorea + naver for KR, snkrdunk + cardmarket for JP, etc.
# Falls back to eBay-with-native-name as a safety net so we never go fully
# empty when a chip has at least *some* signal.

_LANG_NAME_COL: dict[str, str] = {
    "jp": "name_jp",
    "kr": "name_kr",
    "cn": "name_chs",
    "tw": "name_cht",
}


def _lookup_native_name(card: dict, lang: str) -> str | None:
    """
    Cross-reference cards_master to find the native-language name for a card.
    Tries the precise (name_en + card_number) match first, then loosens to
    name_en alone. Returns None if no row has a non-empty native name.
    """
    col = _LANG_NAME_COL.get(lang)
    if not col:
        return None
    name_en = (card.get("name") or "").strip()
    number  = (card.get("number") or "").strip()
    if not name_en:
        return None
    try:
        db = _direct_db()
        row = None
        if number:
            r = db.execute(
                f"SELECT {col} AS native FROM cards_master "
                f"WHERE LOWER(name_en) = LOWER(%s) "
                f"  AND card_number = %s "
                f"  AND {col} <> '' "
                f"LIMIT 1",
                (name_en, number),
            ).fetchone()
            if r:
                row = r
        if not row:
            r = db.execute(
                f"SELECT {col} AS native FROM cards_master "
                f"WHERE LOWER(name_en) = LOWER(%s) AND {col} <> '' "
                f"LIMIT 1",
                (name_en,),
            ).fetchone()
            if r:
                row = r
        db.close()
        if row:
            v = row["native"] if isinstance(row, dict) else row[0]
            return (v or "").strip() or None
    except Exception as _e:
        log.debug("[lang-native] lookup failed for %s/%s: %s", name_en, lang, _e)
    return None


def _fetch_native_lang_price(card: dict, lang: str) -> dict:
    """
    Fetch native-market price for a card in the requested language.

    Pipeline:
      1. Cross-reference cards_master to get the native-language card name.
      2. Build a query using the NATIVE name + card number (number
         disambiguates reprints across sets).
      3. Fan out to language-appropriate scrapers in parallel-ish (HTTP-bound,
         all sub-second so sequential is fine for this 4-language fan-out).
      4. Append eBay-with-native-name as a safety net.
      5. Normalise every listing to USD via fx_rates.
      6. Trimmed median (drop 10% tails when ≥5 listings).

    Returns:
      {market, sample_size, sources_used, native_name, native_query}
      market is None when no listings found anywhere.
    """
    native = _lookup_native_name(card, lang)
    name   = native or (card.get("name") or "").strip()
    number = (card.get("number") or "").strip()

    query = " ".join(p for p in [name, number] if p).strip()
    if not query:
        return {"market": None, "sample_size": 0, "sources_used": [],
                "native_name": native, "native_query": ""}

    listings: list[dict] = []
    used:     list[str]  = []

    try:
        from price_scrapers import naver_shopping, tcgkorea, snkrdunk, cardmarket
    except Exception as _e:
        log.info("[lang-native:%s] price_scrapers unavailable: %s", lang, _e)
        naver_shopping = tcgkorea = snkrdunk = cardmarket = None  # type: ignore

    def _try(src_name: str, fn, *args, **kwargs):
        if fn is None:
            return
        try:
            rows = fn(*args, **kwargs) or []
            if rows:
                listings.extend(rows)
                used.append(src_name)
        except Exception as _e:
            log.debug("[lang-native:%s] %s failed: %s", lang, src_name, _e)

    if lang == "kr":
        _try("tcgkorea", tcgkorea, query, limit=20)
        _try("naver",    naver_shopping, query, limit=20)
    elif lang == "jp":
        _try("snkrdunk",      snkrdunk, query, limit=20)
        _try("cardmarket_jp", cardmarket, query, limit=20, game="Pokemon")
    elif lang == "cn":
        _try("cardmarket_cn", cardmarket, query, limit=20, game="Pokemon")
    elif lang == "tw":
        _try("cardmarket_tw", cardmarket, query, limit=20, game="Pokemon")

    # eBay-with-native-name safety net — Browse API returns USD prices
    # directly so we apply the active→sold ratio inline to make them
    # comparable with the native sources' market prices.
    suffix_for_ebay = _LANG_QUERY_SUFFIXES.get(lang, "")
    ebay_query = " ".join(p for p in [name, suffix_for_ebay, number, "pokemon"] if p)
    try:
        ebay_rows = _ebay_browse_active_page(ebay_query, 1)
        if ebay_rows:
            for r in ebay_rows:
                listings.append({
                    "title":    r.get("title", ""),
                    "price":    float(r.get("price") or 0),
                    "currency": "USD",
                    "source":   f"ebay_{lang}",
                })
            used.append(f"ebay_{lang}")
    except Exception as _e:
        log.debug("[lang-native:%s] ebay safety net failed: %s", lang, _e)

    if not listings:
        return {"market": None, "sample_size": 0, "sources_used": used,
                "native_name": native, "native_query": query}

    # Normalise every listing to USD (KRW/JPY/EUR → USD via daily-cached fx)
    try:
        from fx_rates import normalize_listings
        listings_usd = normalize_listings(listings)
    except Exception as _e:
        log.info("[lang-native:%s] fx unavailable: %s", lang, _e)
        listings_usd = listings

    vals = sorted(float(r["price_usd"]) for r in listings_usd
                  if r.get("price_usd") and r["price_usd"] > 0)
    if not vals:
        return {"market": None, "sample_size": 0, "sources_used": used,
                "native_name": native, "native_query": query}

    # Trim 10% tails when we have enough samples to make trimming meaningful
    if len(vals) >= 5:
        lo = max(1, len(vals) // 10)
        if lo * 2 < len(vals):
            vals = vals[lo:-lo]

    n = len(vals)
    median = vals[n // 2] if n % 2 else (vals[n // 2 - 1] + vals[n // 2]) / 2
    return {
        "market":       round(median, 2),
        "sample_size":  len(listings_usd),
        "sources_used": used,
        "native_name":  native,
        "native_query": query,
    }


def _fetch_ebay_lang_price(card: dict, lang_suffix: str) -> dict:
    """
    Fetch eBay sold listings for a card with a language keyword appended to
    the query (e.g. "japanese", "korean", "chinese simplified").

    Uses the language-qualified query for the eBay search but scores results
    against the original card dict so _filter_and_score stays correct —
    card names don't contain "japanese" etc., so without this the scorer
    would unfairly penalise every result.

    Fetches 4 pages in parallel (enough for a representative sample).
    Returns a _build_price_model dict.  market=None when no listings found.
    """
    if not _EBAY_APP_ID:
        return {"market": None, "sample_size": 0}

    name   = (card.get("name") or "").strip()
    number = (card.get("number") or "").strip()
    set_n  = (card.get("set") or "").strip()

    parts = [p for p in [name, lang_suffix, number, set_n, "pokemon"] if p]
    query = " ".join(parts).strip()

    futs  = [_worker_pool.submit(_ebay_finding_page, query, p) for p in range(1, 4)]
    pages = [f.result(timeout=20) for f in futs]

    items: list[dict] = []
    seen:  set[str]   = set()
    for html in pages:
        for item in _parse_ebay_page(html):
            key = f"{item['title'][:60]}:{item['price']}"
            if key not in seen:
                seen.add(key)
                items.append(item)

    # Foreign-language listings won't have the English card name in the title,
    # so use the lenient scorer when a language suffix is present.
    if lang_suffix:
        scored = _filter_and_score_lang(items, card)
    else:
        scored = _filter_and_score(items, card)
    return _build_price_model(scored)


def _fetch_ebay_sales(card: dict) -> list[dict]:
    """
    Fetch eBay sold listings for a card across 6 pages in parallel (≤90 days).
    Returns [{title, price, sold_date}].

    Includes variant in the query when it adds information not already present
    in the card name — e.g. "Charizard" + "Rainbow Rare" → distinct results
    from just "Charizard", while "Charizard VMAX" + "VMAX" skips the duplicate.

    If the EBAY_APP_ID Finding-API key isn't set we fall back to the keyless
    HTML-scraper in ebay_sold.py so the dashboard still gets data without
    requiring an eBay developer account.
    """
    name    = (card.get("name") or "").strip()
    number  = (card.get("number") or "").strip()
    set_n   = (card.get("set") or "").strip()
    variant = (card.get("variant") or "").strip()

    # Only append variant if it's not already present in the card name
    variant_part = ""
    if variant and variant.lower() not in name.lower():
        variant_part = variant

    query        = " ".join(filter(None, [name, variant_part, number, set_n, "pokemon"])).strip()
    broad_query  = " ".join(filter(None, [name, variant_part, "pokemon"])).strip()
    use_broader  = (broad_query and broad_query != query)

    # Threshold: if the strict query returns fewer than this many sales we
    # also run the broad query and merge — gives the period models enough
    # data points to be statistically meaningful instead of "No sales data".
    BROADER_FALLBACK_THRESHOLD = 5

    # ── No Finding-API key? Use the keyless HTML scraper. ──────────────
    if not _EBAY_APP_ID:
        from ebay_sold import ebay_sold as _scrape
        def _scrape_safe(q):
            try:
                return _scrape(q, limit=180, pages=3)
            except Exception as exc:
                log.info("[ebay] keyless scraper failed: %s — %s", q, exc)
                return []
        rows = _scrape_safe(query)
        if len(rows) < BROADER_FALLBACK_THRESHOLD and use_broader:
            extra = _scrape_safe(broad_query)
            log.info("[ebay] strict %r → %d rows, broadening to %r → +%d rows",
                     query, len(rows), broad_query, len(extra))
            rows = rows + extra
        items: list[dict] = []
        seen: set[str] = set()
        for r in rows:
            key = f"{(r.get('title') or '')[:60]}:{r.get('price')}"
            if key in seen:
                continue
            seen.add(key)
            sd = None
            sa = r.get("sold_at")
            if isinstance(sa, (int, float)) and sa > 0:
                try:
                    sd = datetime.date.fromtimestamp(sa / 1000.0)
                except Exception:
                    sd = None
            items.append({
                "title":     r.get("title") or "",
                "price":     float(r.get("price") or 0),
                "sold_date": sd,
            })
        log.info("[ebay] keyless scraper %r → %d unique rows", query, len(items))
        return items

    # ── Normal Finding-API path (3 pages in parallel) ──────────────────
    futs  = [_worker_pool.submit(_ebay_finding_page, query, p) for p in range(1, 4)]
    pages = [f.result(timeout=20) for f in futs]

    items: list[dict] = []
    seen:  set[str]   = set()
    for page in pages:
        for item in _parse_ebay_page(page):
            key = f"{item['title'][:60]}:{item['price']}"
            if key not in seen:
                seen.add(key)
                items.append(item)

    # ── Broaden if the strict query returned almost nothing ────────────
    # Common cause: the card's number is mis-OCR'd ("199" vs "199/197") or
    # eBay sellers omit the set name. Dropping number+set widens the net.
    if len(items) < BROADER_FALLBACK_THRESHOLD and use_broader:
        log.info("[ebay] strict %r → %d items, broadening to %r",
                 query, len(items), broad_query)
        bfuts  = [_worker_pool.submit(_ebay_finding_page, broad_query, p) for p in range(1, 4)]
        bpages = [f.result(timeout=20) for f in bfuts]
        added  = 0
        for page in bpages:
            for item in _parse_ebay_page(page):
                key = f"{item['title'][:60]}:{item['price']}"
                if key not in seen:
                    seen.add(key)
                    items.append(item)
                    added += 1
        log.info("[ebay] broader query added %d items (total now %d)",
                 added, len(items))
    return items


def _build_period_model(items: list[dict], days: int) -> dict:
    """
    Build a price model for the last `days` days.
    Items without a sold_date are always included (conservative — don't discard).
    """
    cutoff = datetime.date.today() - datetime.timedelta(days=days)
    windowed = [
        i for i in items
        if i.get("sold_date") is None or i["sold_date"] >= cutoff
    ]
    return _build_price_model(windowed)


def _calc_price_trend(items: list[dict]) -> dict:
    """
    Calculate week-by-week median price for the last 13 weeks.
    Returns {weeks: [{week_ending, median, count}], direction: 'up'|'down'|'flat'}.
    """
    today   = datetime.date.today()
    buckets: dict[int, list[float]] = {}   # week_index → prices

    for item in items:
        d = item.get("sold_date")
        if d is None:
            continue
        delta = (today - d).days
        if delta < 0 or delta > 91:
            continue
        week_idx = delta // 7   # 0 = most recent, 12 = oldest
        buckets.setdefault(week_idx, []).append(item["price"])

    weeks = []
    for idx in sorted(buckets):
        prices = _remove_outliers(buckets[idx])
        if prices:
            week_end = today - datetime.timedelta(days=idx * 7)
            weeks.append({
                "week_ending": str(week_end),
                "median":      round(sorted(prices)[len(prices) // 2], 2),
                "count":       len(prices),
            })

    # Direction: compare average of most-recent 2 weeks vs oldest 2 weeks
    direction = "flat"
    if len(weeks) >= 4:
        recent = sum(w["median"] for w in weeks[:2]) / 2
        older  = sum(w["median"] for w in weeks[-2:]) / 2
        if older > 0:
            pct_change = (recent - older) / older
            if pct_change >  0.05:
                direction = "up"
            elif pct_change < -0.05:
                direction = "down"

    return {"weeks": weeks, "direction": direction}


def _get_pricing_cache(query: str):
    """Check Redis first, then PostgreSQL for a cached price model."""
    # L1: Redis (10 min TTL)
    rkey = f"hv:pricing:{hashlib.md5(query.encode()).hexdigest()}"
    cached = _rcache_get(rkey)
    if cached:
        return cached, True
    # L2: PostgreSQL (no TTL — manual invalidation via API)
    try:
        db = _direct_db()
        row = db.execute(
            "SELECT pricing FROM pricing_cache WHERE query=%s", (query,)
        ).fetchone()
        db.close()
        if row:
            val = row["pricing"] if isinstance(row["pricing"], dict) else json.loads(row["pricing"])
            _rcache_set(rkey, val, ttl=600)
            return val, True
    except Exception:
        try: db.close()
        except Exception: pass
    return None, False


def _set_pricing_cache(query: str, pricing: dict):
    """Write a price model to Redis + PostgreSQL."""
    rkey = f"hv:pricing:{hashlib.md5(query.encode()).hexdigest()}"
    _rcache_set(rkey, pricing, ttl=600)
    try:
        db = _direct_db()
        db.execute(
            "INSERT INTO pricing_cache (query, pricing) VALUES (%s, %s::jsonb) "
            "ON CONFLICT (query) DO UPDATE SET pricing=EXCLUDED.pricing, created_at=%s",
            (query, json.dumps(pricing), _now_ms()),
        )
        db.commit()
        db.close()
    except Exception as _e:
        try: db.close()
        except Exception: pass
        log.debug("[pricing-cache] write failed: %s", _e)


def _store_ebay_sales_bg(query: str, matched: list[dict]):
    """
    Persist eBay matched sold listings to ebay_sold_history for analytics.
    Runs in a background thread. Deduplicates within the last 24 hours so
    repeated refreshes don't double-count.
    """
    if not matched:
        return
    try:
        db   = _direct_db()
        now  = _now_ms()
        cutoff = now - 86_400_000  # 24 h ago in ms
        for item in matched:
            sold_date = item.get("sold_date")
            db.execute(
                """
                INSERT INTO ebay_sold_history (query, title, price, sold_date, score, scraped_at)
                SELECT %s, %s, %s, %s, %s, %s
                WHERE NOT EXISTS (
                    SELECT 1 FROM ebay_sold_history
                    WHERE query=%s AND title=%s AND scraped_at >= %s
                )
                """,
                (
                    query, item["title"], item["price"],
                    str(sold_date) if sold_date else None,
                    item.get("score", 0), now,
                    query, item["title"], cutoff,
                ),
            )
        db.commit()
        db.close()
    except Exception as _e:
        log.debug("[ebay-history] store failed: %s", _e)


def _load_ebay_history(query: str, days: int = 90) -> list[dict]:
    """Load stored eBay sold listings for a query from the last `days` days."""
    try:
        db      = _direct_db()
        cutoff  = datetime.date.today() - datetime.timedelta(days=days)
        rows    = db.execute(
            "SELECT title, price, sold_date, score "
            "FROM ebay_sold_history "
            "WHERE query=%s AND (sold_date IS NULL OR sold_date >= %s) "
            "ORDER BY sold_date DESC NULLS LAST",
            (query, str(cutoff)),
        ).fetchall()
        db.close()
        result = []
        for r in rows:
            sd = r["sold_date"]
            result.append({
                "title":     r["title"],
                "price":     r["price"],
                "sold_date": datetime.date.fromisoformat(str(sd)) if sd else None,
                "score":     r["score"],
            })
        return result
    except Exception:
        return []


# ── Pricing pre-warm helpers ──────────────────────────────────────────────────

_PREWARM_RATE_SLEEP = 2.5  # seconds between live eBay fetches during bulk pre-warm


def _prewarm_pricing_for_item(qr_code: str) -> None:
    """
    Background worker: ensure the pricing cache is hot for one inventory item.
    Safe to call from any thread.  Silently skips when cache is already present.
    """
    try:
        db  = _direct_db()
        row = db.execute(
            "SELECT name, set_code, card_number, variant "
            "FROM inventory WHERE qr_code=%s LIMIT 1",
            (qr_code,),
        ).fetchone()
        db.close()
        if not row or not (row["name"] or "").strip():
            return

        name    = (row["name"]        or "").strip()
        set_n   = (row["set_code"]    or "").strip()
        number  = (row["card_number"] or "").strip()
        variant = (row["variant"]     or "").strip()

        # Same query-building logic as _fetch_ebay_sales
        variant_part = variant if variant and variant.lower() not in name.lower() else ""
        query = " ".join(filter(None, [name, variant_part, number, set_n, "pokemon"])).strip()

        _, already_cached = _get_pricing_cache(query)
        if already_cached:
            log.debug("[prewarm] cache hot — skipping %s (%s)", qr_code, query[:60])
            return

        log.info("[prewarm] fetching eBay data for %s (%s)", qr_code, query[:60])
        card    = {"name": name, "set": set_n, "number": number, "variant": variant}
        sales   = _fetch_ebay_sales(card)
        matched = _filter_and_score(sales, card)
        if not matched:
            log.debug("[prewarm] no listings found for %s", query[:60])
            return

        pricing = _build_price_model(matched)
        _set_pricing_cache(query, pricing)
        _store_ebay_sales_bg(query, matched)
        log.info(
            "[prewarm] cached %d listings for '%s' — median £%.2f",
            len(matched), query[:60], pricing.get("median", 0),
        )
    except Exception as _e:
        log.warning("[prewarm] error for qr=%s: %s", qr_code, _e)


def _prewarm_all_pricing_bg() -> None:
    """
    Startup daemon: pre-warm the pricing cache for every item in inventory.

    Strategy
    --------
    - Waits 30 s after boot so the server is fully initialised.
    - Queries inventory ordered by most-recently updated first, so freshly
      added/edited cards are warmed before older ones.
    - Checks the two-level cache (Redis → PG) before each scrape — already-hot
      items are skipped instantly, so re-starts/redeployments are fast.
    - Sleeps 2.5 s between live scrapes to stay well under eBay's rate limits.
    """
    import time as _time
    _time.sleep(30)
    log.info("[prewarm] starting bulk pricing pre-warm …")
    try:
        db   = _direct_db()
        rows = db.execute(
            "SELECT qr_code, name, set_code, card_number, variant "
            "FROM inventory ORDER BY last_updated DESC NULLS LAST"
        ).fetchall()
        db.close()
    except Exception as _e:
        log.warning("[prewarm] could not load inventory: %s", _e)
        try:
            db.close()
        except Exception:
            pass
        return

    total   = len(rows)
    warmed  = 0
    skipped = 0

    for i, row in enumerate(rows, 1):
        qr      = row["qr_code"]
        name    = (row["name"]        or "").strip()
        set_n   = (row["set_code"]    or "").strip()
        number  = (row["card_number"] or "").strip()
        variant = (row["variant"]     or "").strip()

        if not name:
            skipped += 1
            continue

        variant_part = variant if variant and variant.lower() not in name.lower() else ""
        query = " ".join(filter(None, [name, variant_part, number, set_n, "pokemon"])).strip()

        try:
            _, cached = _get_pricing_cache(query)
            if cached:
                skipped += 1
                continue

            log.info("[prewarm] [%d/%d] fetching '%s' …", i, total, query[:60])
            card    = {"name": name, "set": set_n, "number": number, "variant": variant}
            sales   = _fetch_ebay_sales(card)
            matched = _filter_and_score(sales, card)
            if matched:
                pricing = _build_price_model(matched)
                _set_pricing_cache(query, pricing)
                _store_ebay_sales_bg(query, matched)
                warmed += 1
                log.info("[prewarm] [%d/%d] done — median £%.2f", i, total, pricing.get("median", 0))

        except Exception as _ie:
            log.warning("[prewarm] item %s error: %s", qr, _ie)

        _time.sleep(_PREWARM_RATE_SLEEP)

    log.info(
        "[prewarm] complete — %d warmed, %d already cached (skipped), %d total",
        warmed, skipped, total,
    )


def _prewarm_lang_all_bg() -> None:
    """
    Startup daemon: pre-warm the language pricing cache for every inventory item.

    Runs 10 minutes after boot so the EN pre-warm has had a head start and
    eBay rate limits are not doubled up.  Sleeps 5 s between items.

    Skips any item whose language cache key already exists in Redis.
    """
    import time as _time
    _time.sleep(600)   # let EN pre-warm finish first
    log.info("[lang-prewarm] starting language pricing pre-warm …")
    try:
        db   = _direct_db()
        rows = db.execute(
            "SELECT name, set_code, card_number, variant "
            "FROM inventory WHERE name IS NOT NULL AND name != '' "
            "ORDER BY last_updated DESC NULLS LAST"
        ).fetchall()
        db.close()
    except Exception as _e:
        log.warning("[lang-prewarm] could not load inventory: %s", _e)
        try:
            db.close()
        except Exception:
            pass
        return

    total = len(rows)
    done  = 0

    for i, row in enumerate(rows, 1):
        name    = (row["name"]        or "").strip()
        set_n   = (row["set_code"]    or "").strip()
        number  = (row["card_number"] or "").strip()
        variant = (row["variant"]     or "").strip()
        if not name:
            continue

        card = {"name": name, "set": set_n, "number": number, "variant": variant}
        rkey = "lang_pricing:" + hashlib.md5(
            json.dumps(
                {k: (card.get(k) or "").lower()
                 for k in ("name", "set", "number", "variant")},
                sort_keys=True,
            ).encode()
        ).hexdigest()

        if _rcache_get(rkey):
            log.debug("[lang-prewarm] [%d/%d] cached — skip '%s'", i, total, name[:40])
            continue

        try:
            log.info("[lang-prewarm] [%d/%d] fetching '%s' …", i, total, name[:40])
            lang_codes = list(_LANG_QUERY_SUFFIXES.keys())
            suffixes   = list(_LANG_QUERY_SUFFIXES.values())

            with _TPE(max_workers=5) as pool:
                fut_en    = pool.submit(_fetch_ebay_lang_price, card, "")
                fut_langs = [pool.submit(_fetch_native_lang_price, card, c)
                             for c in lang_codes]
                en_model  = fut_en.result()
                lang_models = [f.result() for f in fut_langs]

            en_med = en_model.get("market") or 0

            def _pct_off_pw(model: dict, _em: float = en_med):
                m = model.get("market")
                if not m or not _em:
                    return None
                return max(0, round((1 - m / _em) * 100))

            result: dict = {
                "card": card,
                "en":   {"median": en_model.get("market"),
                         "count":  en_model.get("sample_size", 0)},
            }
            for code, model in zip(lang_codes, lang_models):
                result[code] = {
                    "median":       model.get("market"),
                    "count":        model.get("sample_size", 0),
                    "pct_off":      _pct_off_pw(model),
                    "sources_used": model.get("sources_used", []),
                    "native_name":  model.get("native_name"),
                }

            _rcache_set(rkey, result, ttl=600)
            done += 1
            log.info("[lang-prewarm] [%d/%d] done for '%s'", i, total, name[:40])

        except Exception as _ie:
            log.warning("[lang-prewarm] error for '%s': %s", name[:40], _ie)

        _time.sleep(5)   # 5 s between items, rate-limit safe

    log.info("[lang-prewarm] complete — %d items processed of %d total", done, total)


# ── GET /api/v1/pricing/intelligent ─────────────────────────────────────────

@app.route("/api/v1/pricing/intelligent", methods=["GET"])
@require_api_token
def api_pricing_intelligent():
    """
    Intelligent market-price lookup combining:
      1. Optional multi-language input normalisation (Google Translate)
      2. eBay sold-listing scraper (6 pages, 90-day window, parallel, cached)
      3. Score-based listing filter (name/set/number matching)
      4. Outlier-robust price model (median, avg, confidence)

    Query params:
      name     — card name  (required)
      set      — set name   (optional)
      number   — card number (optional)
      variant  — card variant, e.g. "Rainbow Rare", "GX", "Holo" (optional)
      grade    — "raw" | "psa10" | "psa9" etc. (default "raw")
      lang     — input language ISO code, e.g. "ja", "de" (default "en")
      refresh  — set "1" to bypass cache and force a fresh eBay fetch

    Returns:
      { card, query, pricing, periods, trend, top_matches, canonical, input_name }
    """
    name    = (request.args.get("name") or "").strip()
    set_n   = (request.args.get("set") or "").strip()
    number  = (request.args.get("number") or "").strip()
    variant = (request.args.get("variant") or "").strip()
    grade   = (request.args.get("grade") or "raw").strip().lower()
    lang    = (request.args.get("lang") or "en").strip().lower()
    refresh = request.args.get("refresh", "0") == "1"

    if not name:
        return jsonify({"error": "name is required"}), 400

    # ── Step 1: translate non-English input to English ────────────────────────
    card = _translate_card_input(
        {
            "name":    name,
            "set":     set_n    or None,
            "number":  number   or None,
            "variant": variant  or None,
            "grade":   grade,
        },
        lang,
    )

    # ── Step 2: canonical name normalisation via PokéAPI name index ──────────
    # Corrects typos and non-canonical spellings before hitting eBay.
    # e.g. "Chrizard" → "Charizard", "Genger" → "Gengar"
    canon_match = None
    english_name = (card.get("name") or "").strip()
    if english_name:
        _ensure_pokeapi_names()
        canon_match = _normalize_to_canonical(english_name, threshold=72)
        if canon_match and not canon_match["exact"]:
            # Swap in the corrected name; preserve original for response transparency
            card = {**card, "name": canon_match["canonical"]}
            log.debug(
                "[pricing] canonical correction: %r → %r (score %.2f)",
                english_name, canon_match["canonical"], canon_match["score"],
            )

    # ── Step 3: build eBay query string ───────────────────────────────────────
    query = " ".join(filter(None, [
        card.get("name"), card.get("number"), card.get("set")
    ])).strip()

    # ── Step 4: check cache ───────────────────────────────────────────────────
    pricing    = None
    matched    = []
    from_cache = False
    if not refresh:
        pricing, from_cache = _get_pricing_cache(query)

    # ── Step 5: live eBay scrape ──────────────────────────────────────────────
    if not pricing:
        sales   = _fetch_ebay_sales(card)
        matched = _filter_and_score(sales, card)
        pricing = _build_price_model(matched)
        _bg(_set_pricing_cache, query, pricing)
        _bg(_store_ebay_sales_bg, query, matched)

    return jsonify({
        "card":             card,
        "query":            query,
        "pricing":          pricing,
        "from_cache":       from_cache,
        "top_matches":      matched[:5] if matched else [],
        "canonical":        canon_match,        # name correction info (or null)
        "input_name":       english_name,       # original name before correction
    })


@app.route("/api/v1/pricing/cache/<path:query_path>", methods=["DELETE"])
@require_admin
def api_pricing_cache_delete(query_path):
    """Delete a cached price model so the next request fetches fresh data."""
    query = urllib.parse.unquote(query_path)
    rkey  = f"hv:pricing:{hashlib.md5(query.encode()).hexdigest()}"
    _rcache_del(rkey)
    try:
        db = get_db()
        db.execute("DELETE FROM pricing_cache WHERE query=%s", (query,))
        db.commit()
    except Exception:
        pass
    return jsonify({"ok": True, "invalidated": query})


# ── GET /api/v1/reference/tcgpl ──────────────────────────────────────────────

@app.route("/api/v1/reference/tcgpl", methods=["GET"])
@require_api_token
def api_reference_tcgpl():
    """
    Reference-only price lookup via tcgpricelookup.com.

    NOT used in buylist computation — strictly a sidebar/sanity-check
    rendered next to our own model so the operator can spot-check.

    Query params:
      name        — card name (required)
      number      — collector number (optional)
      game        — internal game slug (pokemon, mtg, onepiece, lorcana, ...)
      our_market  — our computed market price (optional; if given, the
                    response includes delta_vs_our as a 0..1 fraction)

    Returns 200 with normalised reference dict, 404 when not found, 503
    when TCGPL_API_KEY missing or upstream unreachable, 429 on quota,
    400 on missing name.

    Korean Pokémon and Dragon Ball Super are not covered by this service
    — those calls return 404.
    """
    try:
        from tcg_price_lookup import search_card, compute_delta
    except Exception as e:
        log.warning("[tcgpl] module load failed: %s", e)
        return jsonify({"error": "tcgpl_unavailable"}), 503

    name = (request.args.get("name") or "").strip()
    if not name:
        return jsonify({"error": "name_required"}), 400

    number = request.args.get("number") or None
    game   = request.args.get("game")   or None

    try:
        our_market = float(request.args.get("our_market") or 0) or None
    except (TypeError, ValueError):
        our_market = None

    result = search_card(name, game=game, number=number, redis_client=_redis())

    if result is None:
        return jsonify({"error": "not_found", "name": name, "game": game}), 404

    if isinstance(result, dict) and result.get("error"):
        err = result["error"]
        status = {
            "no_token":     503,
            "bad_token":    503,
            "rate_limited": 429,
            "upstream":     502,
        }.get(err, 502)
        return jsonify(result), status

    if our_market is not None:
        delta = compute_delta(result, our_market)
        if delta is not None:
            result["delta_vs_our"] = delta
            result["agreement"]    = "high" if delta < 0.10 else (
                                     "medium" if delta < 0.25 else "low")

    return jsonify(result)


# ── GET /api/v1/cert/psa/<cert_number> ───────────────────────────────────────

@app.route("/api/v1/cert/psa/<cert_number>", methods=["GET"])
@require_api_token
def api_cert_psa(cert_number):
    """
    PSA cert authentication. Operator scans/types the cert number from a
    PSA slab (8 digits, printed under the barcode); we hit PSA's public
    API and return the canonical card identity + grade.

    Requires PSA_API_TOKEN in the environment. Free token from
    https://www.psacard.com/publicapi.

    Cert records are immutable so we cache 30 days; not-found 1 hour.

    Returns 200 with normalised cert dict, 404 when cert not found,
    503 when token missing or upstream unreachable, 400 on bad format.
    """
    try:
        from psa_cert import lookup_cert
    except Exception as e:
        log.warning("[psa] module load failed: %s", e)
        return jsonify({"error": "psa_unavailable"}), 503

    result = lookup_cert(cert_number, redis_client=_redis())

    if result is None:
        return jsonify({"error": "not_found", "cert_number": cert_number}), 404

    if isinstance(result, dict) and result.get("error"):
        err = result["error"]
        status = {
            "no_token":        503,   # PSA_API_TOKEN not configured on this Pi
            "bad_token":       503,   # token present but rejected by PSA
            "rate_limited":    429,
            "upstream":        502,
            "parse":           502,
            "bad_cert_format": 400,
        }.get(err, 502)
        return jsonify(result), status

    return jsonify(result)


# ── GET /api/v1/cert/cgc/<cert_number> ───────────────────────────────────────

@app.route("/api/v1/cert/cgc/<cert_number>", methods=["GET"])
@require_api_token
def api_cert_cgc(cert_number):
    """
    CGC (Certified Guaranty Company) cert lookup. Mirrors the PSA route.

    CGC has no public REST API for cards; we scrape their public cert
    verification page (https://www.cgccards.com/certlookup/<cert>/).
    Best-effort — if their HTML changes shape we return 502 'parse'.

    Cached 30 days for hits, 1 hour for misses, just like PSA.
    """
    try:
        from cgc_cert import lookup_cert as cgc_lookup
    except Exception as e:
        log.warning("[cgc] module load failed: %s", e)
        return jsonify({"error": "cgc_unavailable"}), 503

    result = cgc_lookup(cert_number, redis_client=_redis())

    if result is None:
        return jsonify({"error": "not_found", "cert_number": cert_number}), 404

    if isinstance(result, dict) and result.get("error"):
        err = result["error"]
        status = {
            "rate_limited":    429,
            "upstream":        502,
            "parse":           502,
            "bad_cert_format": 400,
        }.get(err, 502)
        return jsonify(result), status

    return jsonify(result)


# ── GET /api/v1/cert/<service>/<cert_number> — unified router ────────────────

@app.route("/api/v1/cert/<service>/<cert_number>", methods=["GET"])
@require_api_token
def api_cert_unified(service, cert_number):
    """
    Convenience route so frontends can hit one URL and pick the service:
      /api/v1/cert/psa/12345678
      /api/v1/cert/cgc/87654321

    Falls through to the explicit per-service handlers above; this only
    catches unknown services with a clean 404.
    """
    svc = (service or "").lower().strip()
    if svc == "psa":
        return api_cert_psa(cert_number)
    if svc == "cgc":
        return api_cert_cgc(cert_number)
    return jsonify({"error": "unknown_service",
                    "supported": ["psa", "cgc"]}), 404


# ── POST /ai/haggle, /ai/bundle, /ai/counterfeit ─────────────────────────────
# Tablet-side AI assist endpoints. All three degrade to deterministic
# fallbacks when OPENAI_API_KEY is missing, so the tablet UI never hangs.

_OPENAI_BASE_URL = "https://api.openai.com/v1"


def _openai_chat(model: str, messages: list, max_tokens: int,
                 temperature: float, timeout: int = 12) -> dict | None:
    """Thin wrapper around OpenAI chat completions. Returns None on failure."""
    if not _OPENAI_API_KEY:
        return None
    try:
        r = _requests.post(
            f"{_OPENAI_BASE_URL}/chat/completions",
            headers={
                "Authorization": f"Bearer {_OPENAI_API_KEY}",
                "Content-Type":  "application/json",
            },
            json={
                "model":       model,
                "messages":    messages,
                "max_tokens":  max_tokens,
                "temperature": temperature,
            },
            timeout=timeout,
        )
        r.raise_for_status()
        return r.json()
    except Exception as e:
        log.warning("[ai] openai call failed: %s", e)
        return None


def _extract_json(text: str) -> dict | None:
    import re as _re
    m = _re.search(r"\{.*\}", text or "", _re.DOTALL)
    if not m:
        return None
    try:
        return json.loads(m.group(0))
    except Exception:
        return None


@app.route("/ai/haggle", methods=["POST"])
@require_api_token
def ai_haggle():
    """
    Smart Haggle Assistant — given a card + market context, return the
    floor price the operator should hold to and a one-line counter script.
    Falls back to a deterministic stock-aware formula if OpenAI is absent.
    """
    body = request.get_json(silent=True) or {}
    card_name       = (body.get("name") or "").strip()
    market_price    = float(body.get("market_price")    or 0)
    store_price     = float(body.get("store_price")     or 0)
    stock_qty       = int(  body.get("stock_qty")       or 1)
    condition       = (body.get("condition")            or "NM").upper()
    trend_direction = (body.get("trend_direction")      or "STABLE").upper()
    trend_pct       = float(body.get("trend_pct")       or 0)

    if not card_name or market_price <= 0:
        return jsonify({"error": "name and market_price required"}), 400

    cond_mult = {"NM": 1.0, "LP": 0.85, "MP": 0.70, "HP": 0.55, "DMG": 0.40}.get(condition, 1.0)
    if   stock_qty <= 1: floor_pct = 0.90
    elif stock_qty <= 2: floor_pct = 0.85
    elif stock_qty <= 4: floor_pct = 0.80
    else:                floor_pct = 0.75
    if   trend_direction == "UP":   floor_pct = min(floor_pct + 0.05, 0.95)
    elif trend_direction == "DOWN": floor_pct = max(floor_pct - 0.05, 0.65)
    adj_market = market_price * cond_mult

    def _fallback() -> dict:
        floor = round(adj_market * floor_pct, 2)
        walk  = round(adj_market * (floor_pct - 0.08), 2)
        cond_note  = f" ({condition} → {int(cond_mult*100)}% of NM)" if condition != "NM" else ""
        stock_note = "Hold firm — low stock." if stock_qty <= 2 else "Room to negotiate — plenty in stock."
        return {
            "floor_price":    floor,
            "walk_away":      walk,
            "reasoning":      f"Market: ${market_price:.2f}{cond_note}. Floor ${floor:.2f} ({int(floor_pct*100)}%). {stock_note}",
            "counter_script": f"I can do ${floor:.2f} — that's already below market for this card.",
            "confidence":     "MEDIUM",
        }

    if not _OPENAI_API_KEY:
        return jsonify(_fallback())

    prompt = (
        f"You are a shrewd trading-card dealer at a card show. A customer wants to negotiate.\n\n"
        f"Card: {card_name}\nCondition: {condition}\nSticker price: ${store_price:.2f}\n"
        f"Market value (TCGPlayer + last-3 eBay sold avg): ${market_price:.2f}\n"
        f"Copies in stock: {stock_qty}\n30-day trend: {trend_direction} {abs(trend_pct):.0f}%\n\n"
        f"Reply ONLY with valid JSON:\n"
        f'{{"floor_price": <float>, "walk_away": <float>, '
        f'"reasoning": "1-2 sentence advice", '
        f'"counter_script": "What to say to the customer", '
        f'"confidence": "HIGH|MEDIUM|LOW"}}'
    )
    data = _openai_chat("gpt-4o-mini",
                        [{"role": "user", "content": prompt}],
                        max_tokens=200, temperature=0.3)
    if not data:
        return jsonify(_fallback())
    try:
        content = data["choices"][0]["message"]["content"].strip()
    except Exception:
        return jsonify(_fallback())
    parsed = _extract_json(content)
    if not parsed:
        return jsonify({**_fallback(), "reasoning": content[:200], "confidence": "LOW"})
    return jsonify({
        "floor_price":    round(float(parsed.get("floor_price", market_price * 0.75)), 2),
        "walk_away":      round(float(parsed.get("walk_away",  market_price * 0.60)), 2),
        "reasoning":      str(parsed.get("reasoning", "")),
        "counter_script": str(parsed.get("counter_script", "")),
        "confidence":     str(parsed.get("confidence", "MEDIUM")),
    })


@app.route("/ai/bundle", methods=["POST"])
@require_api_token
def ai_bundle():
    """Bundle Deal Suggestion — needs 3+ cart items."""
    body  = request.get_json(silent=True) or {}
    items = body.get("items") or []
    if len(items) < 3:
        return jsonify({"has_deal": False, "reason": "Need 3+ items for a bundle deal"})

    total_retail = sum(float(i.get("price", 0))        * int(i.get("qty", 1)) for i in items)
    total_market = sum(float(i.get("market_price") or i.get("price", 0)) * int(i.get("qty", 1)) for i in items)
    item_count   = sum(int(i.get("qty", 1)) for i in items)

    def _fallback() -> dict:
        discount_pct  = min(5 + (item_count - 3) * 2, 20)
        bundle_price  = round(total_retail * (1 - discount_pct / 100), 2)
        savings       = round(total_retail - bundle_price, 2)
        return {
            "has_deal":     True,
            "bundle_price": bundle_price,
            "savings":      savings,
            "discount_pct": discount_pct,
            "pitch":        f"Bundle all {item_count} for ${bundle_price:.2f} — saves ${savings:.2f}!",
            "confidence":   "LOW",
        }

    if not _OPENAI_API_KEY:
        return jsonify(_fallback())

    items_desc = "\n".join(
        f"- {i.get('name', '?')} x{i.get('qty', 1)}: ${float(i.get('price', 0)):.2f} "
        f"(market ${float(i.get('market_price') or i.get('price', 0)):.2f})"
        for i in items[:10]
    )
    prompt = (
        f"You are a card-show dealer. A customer is buying {item_count} items:\n{items_desc}\n"
        f"Total retail: ${total_retail:.2f}\nTotal market value: ${total_market:.2f}\n\n"
        f"Suggest a bundle. Rules: 5-20% off retail, more items = bigger discount, "
        f"never below 70% of market.\n"
        f"Reply ONLY with valid JSON:\n"
        f'{{"bundle_price": <float>, "discount_pct": <int>, '
        f'"pitch": "Short sentence to say", "confidence": "HIGH|MEDIUM|LOW"}}'
    )
    data = _openai_chat("gpt-4o-mini",
                        [{"role": "user", "content": prompt}],
                        max_tokens=150, temperature=0.4)
    if not data:
        return jsonify(_fallback())
    try:
        content = data["choices"][0]["message"]["content"].strip()
    except Exception:
        return jsonify(_fallback())
    parsed = _extract_json(content)
    if not parsed:
        return jsonify(_fallback())
    bp      = round(float(parsed.get("bundle_price", total_retail * 0.9)), 2)
    savings = round(total_retail - bp, 2)
    return jsonify({
        "has_deal":     True,
        "bundle_price": bp,
        "savings":      savings,
        "discount_pct": int(parsed.get("discount_pct", 10)),
        "pitch":        str(parsed.get("pitch", "")),
        "confidence":   str(parsed.get("confidence", "MEDIUM")),
    })


@app.route("/ai/counterfeit", methods=["POST"])
@require_api_token
def ai_counterfeit():
    """
    Counterfeit Detection — analyse a base64-JPEG card image with GPT-4o
    Vision. Hard 503 if no OPENAI key (no useful local fallback exists).
    """
    body       = request.get_json(silent=True) or {}
    image_b64  = (body.get("image_b64") or "").strip()
    card_name  = (body.get("name")      or "").strip()
    if not image_b64:
        return jsonify({"error": "image_b64 required"}), 400
    if not _OPENAI_API_KEY:
        return jsonify({"error": "AI not configured — cannot perform counterfeit check"}), 503

    name_hint = f" The card is claimed to be '{card_name}'." if card_name else ""
    prompt = (
        "You are a professional trading-card authenticator (Pokémon, Magic, Yu-Gi-Oh, OnePiece)."
        f"{name_hint} Analyse this card image for signs of being counterfeit or legitimate.\n\n"
        "Check: font consistency, color saturation, holo pattern, border alignment, "
        "print quality, card-stock sheen, set-symbol accuracy.\n\n"
        "Reply ONLY with valid JSON:\n"
        '{"verdict": "LIKELY_AUTHENTIC|SUSPICIOUS|LIKELY_FAKE", '
        '"confidence": <float 0.0-1.0>, '
        '"findings": ["finding 1", ...], '
        '"red_flags": ["flag 1", ...], '
        '"recommendation": "1-sentence action to take"}'
    )
    data = _openai_chat(
        "gpt-4o",
        [{"role": "user", "content": [
            {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_b64}"}},
            {"type": "text",      "text":  prompt},
        ]}],
        max_tokens=300, temperature=0.1, timeout=30,
    )
    if not data:
        return jsonify({"error": "ai_upstream_failed"}), 502
    try:
        content = data["choices"][0]["message"]["content"].strip()
    except Exception:
        return jsonify({"error": "ai_bad_shape"}), 502
    parsed = _extract_json(content)
    if not parsed:
        return jsonify({
            "verdict":        "SUSPICIOUS",
            "confidence":     0.5,
            "findings":       [content[:200]],
            "red_flags":      [],
            "recommendation": "AI response could not be parsed — manual inspection recommended.",
        })
    return jsonify({
        "verdict":        str(parsed.get("verdict", "SUSPICIOUS")),
        "confidence":     float(parsed.get("confidence", 0.5)),
        "findings":       list(parsed.get("findings",  []) or []),
        "red_flags":      list(parsed.get("red_flags", []) or []),
        "recommendation": str(parsed.get("recommendation", "")),
    })


# ── GET /api/v1/enrich/<game> ────────────────────────────────────────────────

@app.route("/api/v1/enrich/<game>", methods=["GET"])
@require_api_token
def api_enrich(game):
    """
    Canonical card lookup via free public APIs:
      • pokemon  → api.pokemontcg.io  (English Pokémon)
      • mtg      → api.scryfall.com   (Magic: The Gathering)

    Other games (onepiece, lorcana, dbs) currently return 404 — no
    free canonical API exists for them at time of writing. Fall back
    to operator-pick training when enrichment is unavailable.

    Query params:
      name     — card name (required)
      number   — collector number (optional, Pokémon only)
      set      — set code (optional, MTG only)

    Returns the canonical {game, name, set, set_code, number, rarity,
    image, source} dict or {error: "not_found"} with HTTP 404.
    """
    try:
        from card_enrich import enrich as _enrich
    except Exception as e:
        log.warning("[enrich] module load failed: %s", e)
        return jsonify({"error": "enrich_unavailable"}), 503

    name = (request.args.get("name") or "").strip()
    if not name:
        return jsonify({"error": "name_required"}), 400

    number   = request.args.get("number") or None
    set_code = request.args.get("set")    or None

    result = _enrich(
        game     = game,
        name     = name,
        number   = number,
        set_code = set_code,
        redis_client = _redis(),
    )
    if not result:
        return jsonify({"error": "not_found", "game": game, "name": name}), 404
    return jsonify(result)


# ── GET /api/v1/pricing/history ───────────────────────────────────────────────

@app.route("/api/v1/pricing/history", methods=["GET"])
@require_api_token
def api_pricing_history():
    """
    Full 90-day eBay price history for a card with period breakdowns and trend.

    Loads from the ebay_sold_history table first (zero eBay calls if data exists).
    Falls back to a live scrape when no stored history is found.

    Query params:
      name     — card name (required)
      set      — set name (optional)
      number   — card number (optional)
      variant  — e.g. "Rainbow Rare", "GX" (optional)
      lang     — input language ISO code (default "en")
      refresh  — "1" to force a live re-scrape even if stored data exists

    Returns:
      {
        card, query, periods: {7d, 30d, 90d, all}, trend,
        sold_listings: [{title, price, sold_date, score}],
        data_source: "stored" | "live",
        total_listings: int
      }
    """
    name    = (request.args.get("name") or "").strip()
    set_n   = (request.args.get("set") or "").strip()
    number  = (request.args.get("number") or "").strip()
    variant = (request.args.get("variant") or "").strip()
    lang    = (request.args.get("lang") or "en").strip().lower()
    refresh = request.args.get("refresh", "0") == "1"

    if not name:
        return jsonify({"error": "name is required"}), 400

    # Translate + canonicalise
    card = _translate_card_input(
        {"name": name, "set": set_n or None, "number": number or None,
         "variant": variant or None},
        lang,
    )
    _ensure_pokeapi_names()
    canon = _normalize_to_canonical((card.get("name") or ""), threshold=72)
    if canon and not canon["exact"]:
        card = {**card, "name": canon["canonical"]}

    query = " ".join(filter(None, [
        card.get("name"), card.get("variant"), card.get("number"), card.get("set")
    ])).strip()

    # Try stored history first (unless refresh forced)
    matched     = []
    data_source = "stored"
    if not refresh:
        matched = _load_ebay_history(query, days=90)

    # Fall back to live scrape when nothing stored
    if not matched:
        data_source = "live"
        sales   = _fetch_ebay_sales(card)
        matched = _filter_and_score(sales, card)
        if matched:
            _bg(_store_ebay_sales_bg, query, matched)

    # If any item came from the Browse-API fallback (active asking × 0.80),
    # flag the response so the UI shows an "asking-derived" badge.
    if matched:
        est_count = sum(1 for m in matched if m.get("_estimated"))
        if est_count == len(matched):
            data_source = "live_asking_x080"
        elif est_count:
            data_source = "live_mixed"

    # Build period models
    periods = {
        "7d":  _build_period_model(matched, 7),
        "30d": _build_period_model(matched, 30),
        "90d": _build_period_model(matched, 90),
        "all": _build_price_model(matched),
    }
    trend = _calc_price_trend(matched)

    # Serialise sold_date for JSON
    listings = [
        {
            "title":     m["title"],
            "price":     m["price"],
            "sold_date": str(m["sold_date"]) if m.get("sold_date") else None,
            "score":     m.get("score", 0),
        }
        for m in sorted(matched, key=lambda x: x.get("sold_date") or datetime.date.min, reverse=True)
    ]

    return jsonify({
        "card":           card,
        "query":          query,
        "periods":        periods,
        "trend":          trend,
        "sold_listings":  listings,
        "total_listings": len(listings),
        "data_source":    data_source,
        "canonical":      canon,
    })


# ── GET /api/v1/pricing/language ──────────────────────────────────────────────

@app.route("/api/v1/pricing/language", methods=["GET"])
@require_api_token
def api_pricing_language():
    """
    Real market-based language pricing for a Pokémon card.

    Fires 5 parallel eBay scrapes (EN + JP + KR + CN/Simplified +
    TW/Traditional Chinese) then calculates each language's actual median
    sold price and percentage discount vs the English baseline.

    Results are cached in Redis for 10 minutes so repeat views are instant.

    Query params:
      name     — card name (required)
      set      — set name (optional)
      number   — card number (optional)
      variant  — card variant e.g. "Rainbow Rare" (optional)
      lang     — input language ISO code (default "en")
      refresh  — "1" to skip cache and force fresh eBay scrapes

    Returns:
      {
        card, data_source,
        en: {median, count, query},
        jp: {median, count, pct_off, query},
        kr: {median, count, pct_off, query},
        cn: {median, count, pct_off, query},
        tw: {median, count, pct_off, query},
      }
    """
    name    = (request.args.get("name") or "").strip()
    set_n   = (request.args.get("set") or "").strip()
    number  = (request.args.get("number") or "").strip()
    variant = (request.args.get("variant") or "").strip()
    lang    = (request.args.get("lang") or "en").strip().lower()
    refresh = request.args.get("refresh", "0") == "1"

    if not name:
        return jsonify({"error": "name is required"}), 400

    # Translate + canonicalise
    card = _translate_card_input(
        {"name": name, "set": set_n or None, "number": number or None,
         "variant": variant or None},
        lang,
    )
    _ensure_pokeapi_names()
    canon = _normalize_to_canonical((card.get("name") or ""), threshold=72)
    if canon and not canon["exact"]:
        card = {**card, "name": canon["canonical"]}

    # Cache key — shared across all callers for the same card
    rkey = "lang_pricing:" + hashlib.md5(
        json.dumps(
            {k: (card.get(k) or "").lower()
             for k in ("name", "set", "number", "variant")},
            sort_keys=True,
        ).encode()
    ).hexdigest()

    if not refresh:
        cached = _rcache_get(rkey)
        if cached:
            return jsonify({**cached, "data_source": "cached"})

    # EN via eBay sold + 4 language chips via NATIVE-market sources
    # (cards_master cross-ref → tcgkorea/snkrdunk/cardmarket/naver, then
    # eBay-with-native-name as a safety net) — all in parallel.
    lang_codes = list(_LANG_QUERY_SUFFIXES.keys())   # jp, kr, cn, tw

    with _TPE(max_workers=5) as pool:
        fut_en    = pool.submit(_fetch_ebay_lang_price, card, "")
        fut_langs = [pool.submit(_fetch_native_lang_price, card, c)
                     for c in lang_codes]
        en_model  = fut_en.result()
        lang_models = [f.result() for f in fut_langs]

    en_med = en_model.get("market") or 0

    def _pct_off(model: dict):
        m = model.get("market")
        if not m or not en_med:
            return None
        return max(0, round((1 - m / en_med) * 100))

    en_query = " ".join(filter(None, [
        card.get("name"), card.get("number"), card.get("set"), "pokemon"
    ]))

    result: dict = {
        "card": card,
        "en":   {
            "median": en_model.get("market"),
            "count":  en_model.get("sample_size", 0),
            "query":  en_query,
        },
    }

    for code, model in zip(lang_codes, lang_models):
        result[code] = {
            "median":       model.get("market"),
            "count":        model.get("sample_size", 0),
            "pct_off":      _pct_off(model),
            "query":        model.get("native_query", ""),
            "sources_used": model.get("sources_used", []),
            "native_name":  model.get("native_name"),
        }

    _rcache_set(rkey, result, ttl=600)

    return jsonify({**result, "data_source": "live"})


# ── GET /api/v1/pokeapi/normalize ─────────────────────────────────────────────

@app.route("/api/v1/pokeapi/normalize", methods=["GET"])
def api_pokeapi_normalize():
    """
    Canonicalise any Pokémon name string using the PokéAPI species index.

    Query params:
      q         — input name (required)
      threshold — minimum score 0–100 (default 70)

    Returns:
      { input, canonical, slug, pokedex_no, score, exact, in_stock,
        inventory_item }
    """
    q         = (request.args.get("q") or "").strip()
    threshold = _safe_int(request.args.get("threshold", 70), 70)
    if not q:
        return jsonify({"error": "q is required"}), 400

    _ensure_pokeapi_names()
    match = _normalize_to_canonical(q, threshold=threshold)
    if not match:
        return jsonify({"input": q, "canonical": None, "score": 0, "exact": False})

    # Check if the canonical name is in stock
    db = get_db()
    inv_row = db.execute(
        "SELECT qr_code, name, price, stock, rarity, image_url "
        "FROM inventory WHERE LOWER(name) LIKE %s AND stock > 0 LIMIT 1",
        (f"%{match['canonical'].lower()}%",),
    ).fetchone()

    return jsonify({
        "input":          q,
        "canonical":      match["canonical"],
        "slug":           match["slug"],
        "pokedex_no":     match["pokedex_no"],
        "score":          match["score"],
        "exact":          match["exact"],
        "in_stock":       inv_row is not None,
        "inventory_item": dict(inv_row) if inv_row else None,
        "sprite_url": (
            f"https://raw.githubusercontent.com/PokeAPI/sprites/master/"
            f"sprites/pokemon/other/official-artwork/{match['pokedex_no']}.png"
        ),
    })


# ── POST /api/v1/pokeapi/names/refresh ───────────────────────────────────────

@app.route("/api/v1/pokeapi/names/refresh", methods=["POST"])
@require_admin
def api_pokeapi_names_refresh():
    """
    Force a fresh fetch of all Pokémon species names from PokéAPI.
    Runs in the background — returns immediately.
    """
    global _pokeapi_names_ready
    with _pokeapi_names_lock:
        _pokeapi_names_ready = False   # mark stale so _ensure_pokeapi_names re-fetches

    def _do_refresh():
        count = _pokeapi_fetch_and_store()
        if count:
            entries = _load_pokeapi_names_from_db()
            global _pokeapi_names_list, _pokeapi_names_strs, _pokeapi_names_ready
            with _pokeapi_names_lock:
                _pokeapi_names_list  = entries
                _pokeapi_names_strs  = [e["name"] for e in entries]
                _pokeapi_names_ready = True
            log.info("[pokeapi] refresh complete: %d names", count)

    _bg(_do_refresh)
    return jsonify({"ok": True, "message": "Refresh started in background"})


