_RECEIPT_SETTINGS_KEY = "receipt_settings_v2"


def _load_receipt_settings() -> dict:
    defaults = {
        "store_name":               "HanryxVault",
        "tagline":                  "Korean Pokemon TCG Specialists",
        "website":                  "hanryxvault.cards",
        "instagram":                "",
        "phone":                    "",
        "address":                  "",
        "footer_msg":               "Thank you for collecting with us!",
        "paper_width":              "80",
        # Multi-line disclosure printed near the bottom of the receipt.
        # Edit on the Receipt Settings admin page; supports plain text with
        # blank lines between paragraphs. Wraps automatically to paper width.
        "disclosure":               "",
        # 1 = customer copy only.  2 = customer + merchant copy.
        "print_copies":             "2",
        # When printing 2 copies, omit the disclosure block on the merchant
        # copy (saves ~1.5" of paper per sale; the merchant already knows the
        # policy). "1"/"0" string for HTML form compatibility.
        "merchant_skip_disclosure": "1",
    }
    try:
        db  = _direct_db()
        row = db.execute("SELECT value FROM server_state WHERE key=%s", (_RECEIPT_SETTINGS_KEY,)).fetchone()
        db.close()
        if row:
            stored = json.loads(row["value"]) if isinstance(row["value"], str) else row["value"]
            defaults.update(stored)
    except Exception:
        pass
    return defaults


def _save_receipt_settings(settings: dict):
    try:
        db = _direct_db()
        db.execute(
            "INSERT INTO server_state (key, value) VALUES (%s, %s) "
            "ON CONFLICT (key) DO UPDATE SET value=EXCLUDED.value",
            (_RECEIPT_SETTINGS_KEY, json.dumps(settings)),
        )
        db.commit()
        db.close()
    except Exception as _e:
        try: db.close()
        except Exception: pass
        log.warning("[receipt-settings] save failed: %s", _e)


