# ---------------------------------------------------------------------------
# Twilio SMS — digital receipt sender
# ---------------------------------------------------------------------------
_twilio_client_obj  = None
_twilio_client_lock = threading.Lock()


def _twilio_enabled() -> bool:
    return bool(os.environ.get("TWILIO_SID") and
                os.environ.get("TWILIO_TOKEN") and
                os.environ.get("TWILIO_FROM"))


def _twilio_client():
    """Lazy-build a Twilio REST client. Returns None if creds missing or import fails."""
    global _twilio_client_obj
    if _twilio_client_obj is not None:
        return _twilio_client_obj
    if not _twilio_enabled():
        return None
    with _twilio_client_lock:
        if _twilio_client_obj is not None:
            return _twilio_client_obj
        try:
            from twilio.rest import Client as _TwilioClient
            _twilio_client_obj = _TwilioClient(
                os.environ["TWILIO_SID"], os.environ["TWILIO_TOKEN"]
            )
        except Exception as exc:
            log.warning("[twilio] init failed: %s", exc)
            return None
    return _twilio_client_obj


_PHONE_RE = re.compile(r"^\+?[0-9 ()\-]{7,20}$")


def _normalize_phone(raw: str) -> str:
    """Best-effort E.164 normalization — defaults to UK (+44) if no country code.
    Also strips a leading '0' national-trunk prefix that follows a country code,
    e.g. '+44 (0) 7700 900 123' → '+447700900123'."""
    if not raw:
        return ""
    cleaned = re.sub(r"[^\d+]", "", raw)
    # Drop any '+' that isn't at position 0 (e.g. people typing "44+7…")
    if cleaned.count("+") > 1 or (cleaned.find("+") > 0):
        cleaned = "+" + cleaned.replace("+", "")
    if cleaned.startswith("+"):
        # Strip a trunk-prefix '0' that some users include after the country code
        # (most common form: "+44 (0) 7700 ..." → "+4407700...")
        # We strip ONE leading '0' immediately after the 2-3 digit country code
        m = re.match(r"^\+(\d{1,3})0(\d+)$", cleaned)
        if m and len(m.group(2)) >= 7:
            cleaned = "+" + m.group(1) + m.group(2)
        return cleaned
    if cleaned.startswith("00"):
        return "+" + cleaned[2:]
    if cleaned.startswith("0"):
        return "+44" + cleaned[1:]
    return "+" + cleaned


def _send_sms(to: str, body: str) -> tuple[bool, str, str]:
    """Send an SMS via Twilio. Returns (ok, message_sid_or_empty, error_string)."""
    client = _twilio_client()
    if not client:
        return False, "", "SMS service not configured"
    try:
        msg = client.messages.create(
            body=body, from_=os.environ["TWILIO_FROM"], to=to,
        )
        return True, getattr(msg, "sid", "") or "", ""
    except Exception as exc:
        return False, "", str(exc)[:240]


@app.route("/receipt/<token>/sms", methods=["POST"])
def receipt_sms(token):
    """Send a digital receipt link to a customer phone via Twilio.
    Rate-limited: max 3 sends per token, max 8 sends per IP per hour."""
    if not _twilio_enabled():
        return jsonify(ok=False, error="SMS receipts are not enabled on this store"), 503

    body = request.get_json(silent=True) or {}
    phone_raw = (body.get("phone") or "").strip()
    if not phone_raw or not _PHONE_RE.match(phone_raw):
        return jsonify(ok=False, error="Please enter a valid phone number"), 400
    phone = _normalize_phone(phone_raw)
    if not phone or len(phone) < 8:
        return jsonify(ok=False, error="Please enter a valid phone number"), 400

    ip = (request.headers.get("X-Forwarded-For") or request.remote_addr or "").split(",")[0].strip()

    try:
        db  = get_db()
        row = db.execute(
            "SELECT total, payment_method FROM digital_receipts "
            "WHERE token=%s AND expires_at > %s",
            (token, _now_ms()),
        ).fetchone()
    except Exception as exc:
        app.logger.error("[sms] receipt lookup failed for token=%s: %s", token, exc)
        return jsonify(ok=False, error="Receipt not found"), 404
    if not row:
        return jsonify(ok=False, error="Receipt not found or expired"), 404

    # Rate limits
    try:
        hour_ago = _now_ms() - 3_600_000
        n_token = db.execute(
            "SELECT COUNT(*) AS c FROM receipt_sms_log WHERE token=%s AND ok=1",
            (token,),
        ).fetchone()
        if n_token and _safe_int(n_token["c"], 0) >= 3:
            return jsonify(ok=False, error="This receipt has already been texted 3 times"), 429
        n_ip = db.execute(
            "SELECT COUNT(*) AS c FROM receipt_sms_log WHERE ip=%s AND sent_at > %s",
            (ip, hour_ago),
        ).fetchone()
        if n_ip and _safe_int(n_ip["c"], 0) >= 8:
            return jsonify(ok=False, error="Too many requests — please try again later"), 429
    except Exception as exc:
        app.logger.warning("[sms] rate-limit check failed: %s", exc)

    receipt_url = (request.host_url.rstrip("/") + f"/receipt/{token}")
    sms_body = (
        f"HanryxVault receipt £{_safe_float(row['total'], 0):.2f}"
        + (f" ({row['payment_method']})" if row.get('payment_method') else "")
        + f"\n{receipt_url}\nThanks for your order!"
    )

    ok, sid, err = _send_sms(phone, sms_body)
    try:
        db.execute(
            "INSERT INTO receipt_sms_log (token, phone, sent_at, ip, ok, err, twilio_sid) "
            "VALUES (%s,%s,%s,%s,%s,%s,%s)",
            (token, phone, _now_ms(), ip, 1 if ok else 0, err, sid),
        )
    except Exception as exc:
        app.logger.warning("[sms] audit log insert failed: %s", exc)

    if not ok:
        return jsonify(ok=False, error="Could not send SMS — please try again"), 502
    return jsonify(ok=True)


# ---------------------------------------------------------------------------
# Offline sale queue — helpers
# ---------------------------------------------------------------------------

def _process_one_queued_sale(db, row_id: int, client_id: str,
                              items: list, queued_at: int,
                              payment_method: str) -> tuple[bool, str]:
    """
    Fully process a single offline-queued sale:
      1. Deduct inventory for each line item (floor at 0, match by name)
      2. Write to sale_history — skip if already present (dedup by name+sold_at)
      3. Mark the queue row synced=1
    Returns (success, error_message).
    """
    try:
        for item in items:
            if not isinstance(item, dict):
                continue
            name  = (item.get("name") or "").strip()
            price = _safe_float(item.get("price"), 0)
            qty   = max(1, _safe_int(
                item.get("qty") or item.get("quantity") or 1, 1))
            if not name or price <= 0:
                continue

            # Deduct stock (by name — best match without qr_code)
            db.execute(
                "UPDATE inventory "
                "SET quantity = GREATEST(0, quantity - %s), "
                "    last_updated = %s "
                "WHERE LOWER(name) = LOWER(%s) AND quantity > 0",
                (qty, _now_ms(), name),
            )

            # Write sale_history — skip exact duplicate (same name + timestamp)
            exists = db.execute(
                "SELECT 1 FROM sale_history "
                "WHERE name = %s AND sold_at = %s LIMIT 1",
                (name, queued_at),
            ).fetchone()
            if not exists:
                db.execute(
                    "INSERT INTO sale_history "
                    "(name, price, quantity, sold_at) VALUES (%s,%s,%s,%s)",
                    (name, price, qty, queued_at),
                )

        # Mark synced
        db.execute(
            "UPDATE offline_sale_queue "
            "SET synced = 1, synced_at = %s WHERE id = %s",
            (_now_ms(), row_id),
        )
        return True, ""
    except Exception as exc:
        log.exception(f"[sales/queue] Failed to process row id={row_id}")
        return False, str(exc)


# ---------------------------------------------------------------------------
# Offline sale queue — endpoints
# ---------------------------------------------------------------------------

@app.route("/sales/queue", methods=["POST"])
def sales_queue_submit():
    """
    Offline-queue drain endpoint.
    Tablet calls this with locally-queued sales when connectivity returns.
    Body: { client_id, sales: [{items, total, payment_method, queued_at}] }
    Each sale is saved to the queue then immediately processed (inventory
    deduction + sale_history). Duplicate sales (same client_id + queued_at)
    are silently skipped.
    """
    data   = request.get_json(force=True, silent=True) or {}
    client = (data.get("client_id") or "").strip()[:64]
    sales  = data.get("sales", [])
    if not isinstance(sales, list):
        return jsonify({"error": "sales must be array"}), 400

    db = get_db()
    saved = processed = skipped = errors = 0

    for s in sales:
        if not isinstance(s, dict):
            continue
        queued_at = _safe_int(s.get("queued_at") or _now_ms(), _now_ms())
        total     = _safe_float(s.get("total"), 0)
        method    = str(s.get("payment_method") or "offline")[:32]
        items     = s.get("items") or []

        # Dedup: skip if same client already submitted this exact timestamp
        already = db.execute(
            "SELECT id FROM offline_sale_queue "
            "WHERE client_id = %s AND queued_at = %s LIMIT 1",
            (client, queued_at),
        ).fetchone()
        if already:
            skipped += 1
            continue

        try:
            cur = db.execute(
                "INSERT INTO offline_sale_queue "
                "(client_id, items_json, total, payment_method, queued_at) "
                "VALUES (%s, %s, %s, %s, %s) RETURNING id",
                (client, json.dumps(items), total, method, queued_at),
            )
            row_id = cur.fetchone()[0]
            saved += 1
        except Exception:
            log.exception("[sales/queue] INSERT failed")
            errors += 1
            continue

        # Immediately process — deduct inventory + write history + mark synced
        ok, _err = _process_one_queued_sale(
            db, row_id, client, items, queued_at, method)
        if ok:
            processed += 1
        else:
            errors += 1

    db.commit()
    _audit_write("sales.queue.drain",
                 f"client={client}",
                 f"saved={saved} processed={processed} skipped={skipped}")
    return jsonify({
        "ok":        True,
        "saved":     saved,
        "processed": processed,
        "skipped":   skipped,
        "errors":    errors,
    })


@app.route("/sales/queue/stats", methods=["GET"])
@require_admin
def sales_queue_stats():
    """Return a summary of the offline queue for the dashboard."""
    db = get_db()
    pending = db.execute(
        "SELECT COUNT(*) as c, COALESCE(SUM(total),0) as v "
        "FROM offline_sale_queue WHERE synced = 0"
    ).fetchone()
    synced_today = db.execute(
        "SELECT COUNT(*) as c "
        "FROM offline_sale_queue "
        "WHERE synced = 1 "
        "  AND synced_at >= (EXTRACT(EPOCH FROM NOW()-INTERVAL '1 day')*1000)::BIGINT"
    ).fetchone()
    oldest = db.execute(
        "SELECT queued_at FROM offline_sale_queue "
        "WHERE synced = 0 ORDER BY queued_at ASC LIMIT 1"
    ).fetchone()
    return jsonify({
        "pending_count":     int(pending["c"]) if pending else 0,
        "pending_value":     round(float(pending["v"]), 2) if pending else 0,
        "synced_today":      int(synced_today["c"]) if synced_today else 0,
        "oldest_pending_ms": oldest["queued_at"] if oldest else None,
    })


@app.route("/sales/queue/flush", methods=["POST"])
@require_admin
def sales_queue_flush():
    """
    Admin-triggered: process all synced=0 rows right now.
    Useful after the server recovers from an outage and the tablet
    has already sent everything but processing failed mid-flight.
    """
    db = get_db()
    rows = db.execute(
        "SELECT id, client_id, items_json, total, payment_method, queued_at "
        "FROM offline_sale_queue WHERE synced = 0 ORDER BY queued_at ASC"
    ).fetchall()

    done = failed = 0
    for r in rows:
        try:
            items = json.loads(r["items_json"] or "[]")
        except Exception:
            items = []
        ok, _err = _process_one_queued_sale(
            db, r["id"], r["client_id"], items,
            r["queued_at"], r["payment_method"])
        if ok:
            done += 1
        else:
            failed += 1

    db.commit()
    _audit_write("sales.queue.flush", f"processed={done}", f"failed={failed}")
    return jsonify({"ok": True, "processed": done, "failed": failed})


@app.route("/sales/queue/pending", methods=["GET"])
@require_admin
def sales_queue_pending():
    """Admin view of all queue rows with full item detail."""
    db  = get_db()
    status = request.args.get("status", "pending")   # pending | synced | all
    where  = ("WHERE synced = 0" if status == "pending"
              else "WHERE synced = 1" if status == "synced"
              else "")
    rows = db.execute(
        f"SELECT id, client_id, items_json, total, payment_method, "
        f"       queued_at, synced, synced_at "
        f"FROM offline_sale_queue {where} "
        f"ORDER BY queued_at DESC LIMIT 200"
    ).fetchall()
    result = []
    for r in rows:
        try:
            items = json.loads(r["items_json"] or "[]")
        except Exception:
            items = []
        result.append({
            "id":             r["id"],
            "client_id":      r["client_id"],
            "total":          r["total"],
            "payment_method": r["payment_method"],
            "queued_at":      r["queued_at"],
            "synced":         bool(r["synced"]),
            "synced_at":      r["synced_at"],
            "item_count":     len(items),
            "items":          items,
        })
    return jsonify(result)


@app.route("/kiosk/stream")
@require_api_token
def kiosk_sse_stream():
    """SSE stream — kiosk display subscribes here for live cart updates."""
    try:
        # Use gevent-compatible queue when available, fall back to stdlib
        try:
            from gevent.queue import Queue as _GQueue
            _q = _GQueue(maxsize=20)
        except ImportError:
            import queue as _q_mod
            _q = _q_mod.Queue(maxsize=20)

        with _kiosk_sse_lock:
            _kiosk_sse_subscribers.append(_q)

        def _generate():
            try:
                # Send current state immediately on connect.
                # Prefer Redis (survives restarts) over in-memory.
                snapshot = _kiosk_cart_load_redis()
                if snapshot is None:
                    with _kiosk_cart_lock:
                        snapshot = dict(_kiosk_cart)
                yield f"data: {json.dumps(snapshot)}\n\n"
                while True:
                    try:
                        msg = _q.get(timeout=25)
                        yield msg
                    except Exception:
                        yield ":\n\n"   # keepalive ping
            finally:
                # Clean up subscriber on disconnect
                with _kiosk_sse_lock:
                    try:
                        _kiosk_sse_subscribers.remove(_q)
                    except ValueError:
                        pass

        # Do NOT use stream_with_context — generator needs no Flask request context
        return Response(
            _generate(),
            mimetype="text/event-stream",
            headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no",
                     "Connection": "keep-alive"},
        )
    except Exception as _sse_err:
        app.logger.error("kiosk_sse_stream setup failed: %s", _sse_err)
        return Response(
            f"data: {json.dumps({'error': str(_sse_err)})}\n\n",
            mimetype="text/event-stream",
            status=500,
        )


# ─────────────────────────────────────────────────────────────────────────────
# Local idle-screen video playlist
#   download-playlist.sh drops MP4 files into KIOSK_VIDEOS_DIR.  The kiosk
#   page fetches /kiosk/videos.json (a shuffled list) and plays each clip via
#   an HTML5 <video> element, advancing on `ended` — no YouTube iframe, no
#   ads, no V8 OOM, no network dependency once downloaded.
# ─────────────────────────────────────────────────────────────────────────────
KIOSK_VIDEOS_DIR = os.environ.get("KIOSK_VIDEOS_DIR", "/opt/hanryxvault/kiosk/videos")


def _kiosk_local_videos() -> list[dict]:
    """Return [{name, url, size}, …] of MP4s in KIOSK_VIDEOS_DIR."""
    out = []
    try:
        if not os.path.isdir(KIOSK_VIDEOS_DIR):
            return out
        for fn in sorted(os.listdir(KIOSK_VIDEOS_DIR)):
            if not fn.lower().endswith(".mp4"):
                continue
            full = os.path.join(KIOSK_VIDEOS_DIR, fn)
            try:
                sz = os.path.getsize(full)
            except OSError:
                continue
            if sz < 64 * 1024:   # skip placeholder/partial files
                continue
            out.append({
                "name": fn,
                "url":  "/kiosk/videos/" + quote(fn),
                "size": sz,
            })
    except Exception as _e:
        app.logger.warning("kiosk videos list failed: %s", _e)
    return out


@app.route("/kiosk/videos.json")
def kiosk_videos_list():
    """JSON list of local idle-screen MP4s.  Shuffled client-side."""
    vids = _kiosk_local_videos()
    return jsonify({"count": len(vids), "videos": vids})


@app.route("/kiosk/videos/<path:filename>")
def kiosk_videos_file(filename: str):
    """Serve a single MP4 from KIOSK_VIDEOS_DIR (with HTTP Range support)."""
    # send_from_directory blocks path traversal automatically.
    safe_name = os.path.basename(filename)
    if not safe_name.lower().endswith(".mp4"):
        return ("not found", 404)
    resp = send_from_directory(
        KIOSK_VIDEOS_DIR, safe_name,
        mimetype="video/mp4", conditional=True,
    )
    # Long cache — filenames include the YouTube video ID, so they're stable.
    resp.headers["Cache-Control"] = "public, max-age=86400"
    return resp


@app.route("/kiosk")
def kiosk_display():
    """Customer-facing kiosk display — one screen, four modes: idle / cart / trade / thankyou."""
    ks              = _load_kiosk_settings()
    bg              = ks["bg_color"]
    accent          = ks["accent_color"]
    name            = ks["store_name"]
    tagline         = ks["tagline"]
    idle_msg        = ks["idle_message"]
    ig              = ks["instagram"] if ks.get("show_social") else ""
    web             = ks["website"]   if ks.get("show_social") else ""
    enabled         = ks["enabled"]
    vid_mode        = ks.get("video_mode", False)
    vid_url         = ks.get("video_url", "")
    # Per-screen override — append ?idle=off (or ?video=off) to the kiosk URL on
    # any display that should NOT play the idle-screen video.  Used to keep one
    # monitor on the working POS UI while another monitor still cycles videos.
    if request.args.get("idle", "").lower() in ("off", "0", "false", "no") \
       or request.args.get("video", "").lower() in ("off", "0", "false", "no"):
        vid_mode = False
    show_receipt_qr = "true" if ks.get("show_receipt_qr", True) else "false"
    price_confirm_ms = int(ks.get("price_confirm_ms", 2200))

    # Compute initial kiosk state signature — baked into the page so the
    # 500 ms sig-poll knows what state was rendered.  Changes → reload.
    _st = _kiosk_get_state()
    _kiosk_sig_init = (
        (_st.get("mode") or "idle")
        + ("1" if _st.get("active") else "0")
        + ("1" if _st.get("paid") else "0")
        + ("1" if _st.get("payment_processing") else "0")
        + str(len(_st.get("items") or []))
        + str(round((_st.get("total") or 0) * 100))
    )

    # Parse YouTube URL
    yt_vid, yt_pid = _parse_youtube_id(vid_url)
    # Build embed params
    yt_embed_id = yt_vid or (yt_pid or "")

    # Prefer locally-downloaded MP4s (rock-solid, no V8 OOM, no network deps).
    # Falls back to the YouTube iframe only if no local files are present.
    _local_vids = _kiosk_local_videos() if vid_mode else []

    if vid_mode and _local_vids:
        # ── Local-MP4 idle-screen player ────────────────────────────────────
        # Plays a randomly-shuffled rotation of the downloaded playlist via a
        # plain <video> element.  No iframe, no YT player JS, no leaks.
        _yt_api_tag = ""
        _yt_init_js = (
            "var _vidEl = null;\n"
            "var _vidQueue = [];\n"
            "var _vidIdx = 0;\n"
            "var _vidShuffled = false;\n"
            "function _vidShuffle(arr){\n"
            "  for(var i=arr.length-1;i>0;i--){\n"
            "    var j=Math.floor(Math.random()*(i+1));\n"
            "    var t=arr[i]; arr[i]=arr[j]; arr[j]=t;\n"
            "  }\n"
            "  return arr;\n"
            "}\n"
            "function _vidShow(){\n"
            "  var w=document.getElementById('yt-wrap');\n"
            "  var b=document.getElementById('unmute-btn');\n"
            "  var t=document.getElementById('idle-text');\n"
            "  if(w){w.style.opacity='1';w.style.pointerEvents='auto';}\n"
            "  if(b){b.style.display='flex';}\n"
            "  if(t){t.style.display='none';}\n"
            "}\n"
            "function _vidHide(){\n"
            "  var w=document.getElementById('yt-wrap');\n"
            "  var b=document.getElementById('unmute-btn');\n"
            "  var t=document.getElementById('idle-text');\n"
            "  if(w){w.style.opacity='0';w.style.pointerEvents='none';}\n"
            "  if(b){b.style.display='none';}\n"
            "  if(t){t.style.display='flex';}\n"
            "}\n"
            "function _vidNext(){\n"
            "  if(!_vidQueue.length){ return; }\n"
            "  if(_vidIdx >= _vidQueue.length){\n"
            "    _vidShuffle(_vidQueue);\n"
            "    _vidIdx = 0;\n"
            "  }\n"
            "  var src = _vidQueue[_vidIdx++];\n"
            "  if(_vidEl){\n"
            "    try { _vidEl.src = src; _vidEl.load(); _vidEl.play().catch(function(){}); }\n"
            "    catch(e){ console.warn('[kiosk] video load failed', e); }\n"
            "  }\n"
            "}\n"
            "function _vidLoadList(){\n"
            "  fetch('/kiosk/videos.json', {cache:'no-store'})\n"
            "    .then(function(r){ return r.json(); })\n"
            "    .then(function(j){\n"
            "      var v = (j && j.videos) || [];\n"
            "      _vidQueue = v.map(function(x){ return x.url; });\n"
            "      if(!_vidShuffled){ _vidShuffle(_vidQueue); _vidShuffled = true; }\n"
            "      _vidIdx = 0;\n"
            "      console.log('[kiosk] local playlist: '+_vidQueue.length+' videos');\n"
            "      if(_vidQueue.length){ _vidNext(); _vidShow(); }\n"
            "    })\n"
            "    .catch(function(e){ console.warn('[kiosk] /kiosk/videos.json failed', e); });\n"
            "}\n"
            "function _vidBuild(){\n"
            "  var host = document.getElementById('yt-wrap');\n"
            "  if(!host) return;\n"
            "  host.innerHTML = '';\n"
            "  _vidEl = document.createElement('video');\n"
            "  _vidEl.id = 'yt-frame';\n"
            "  _vidEl.muted = true;\n"
            "  _vidEl.autoplay = true;\n"
            "  _vidEl.playsInline = true;\n"
            "  _vidEl.preload = 'auto';\n"
            "  _vidEl.style.width = '100%';\n"
            "  _vidEl.style.height = '100%';\n"
            "  _vidEl.style.objectFit = 'cover';\n"
            "  _vidEl.style.background = '#000';\n"
            "  _vidEl.addEventListener('ended', _vidNext);\n"
            "  _vidEl.addEventListener('error', function(){\n"
            "    console.warn('[kiosk] video error, advancing');\n"
            "    setTimeout(_vidNext, 500);\n"
            "  });\n"
            "  host.appendChild(_vidEl);\n"
            "  _vidLoadList();\n"
            "}\n"
            "// Refresh the playlist every 6 hours so newly-downloaded clips appear\n"
            "// without needing to reload the page.\n"
            "setInterval(function(){ try { _vidLoadList(); } catch(e){} }, 6*60*60*1000);\n"
            "// Watchdog: if the element ever stalls (paused while idle is visible,\n"
            "// or readyState 0 for >30 s), advance to the next clip.\n"
            "var _vidLastAdvance = Date.now();\n"
            "setInterval(function(){\n"
            "  var elI = document.getElementById('idle');\n"
            "  if(!elI || elI.style.display === 'none') return;\n"
            "  if(!_vidEl) return;\n"
            "  var stalled = _vidEl.paused || _vidEl.readyState < 2;\n"
            "  if(stalled && (Date.now() - _vidLastAdvance) > 30000){\n"
            "    console.warn('[kiosk] local video stalled — advancing');\n"
            "    _vidLastAdvance = Date.now();\n"
            "    _vidNext();\n"
            "  } else if(!stalled){\n"
            "    _vidLastAdvance = Date.now();\n"
            "  }\n"
            "}, 10000);\n"
            "document.addEventListener('DOMContentLoaded', _vidBuild);\n"
            "function ytPlay(){ if(_vidEl){ try{_vidEl.muted=true;_vidEl.play();}catch(e){} _vidShow(); } }\n"
            "function ytPause(){ if(_vidEl){ try{_vidEl.pause();}catch(e){} _vidHide(); } }\n"
        )
        _yt_idle_html = """
<div id="yt-wrap" style="position:fixed;inset:0;z-index:1;opacity:0;pointer-events:none;transition:opacity 1s">
</div>
<button id="unmute-btn" onclick="toggleMute(this)"
  style="position:fixed;bottom:20px;right:20px;z-index:30;
         background:#0009;border:1px solid #f59e0b55;border-radius:50%;
         width:52px;height:52px;font-size:22px;cursor:pointer;
         display:none;align-items:center;justify-content:center;color:#fff">
  🔇
</button>"""
        _yt_mute_js = """
var _muted = true;
function toggleMute(btn) {
  _muted = !_muted;
  if (_vidEl) { _vidEl.muted = _muted; }
  btn.textContent = _muted ? '🔇' : '🔊';
}"""
    elif vid_mode and yt_embed_id:
        # Pre-compute optional playerVars fragments to avoid quote conflicts in f-strings
        _loop_param    = ("loop:1,playlist:'" + yt_vid + "'") if (yt_vid and not yt_pid) else ""
        _list_param    = ("list:'" + yt_pid + "',listType:'playlist'") if yt_pid else ""
        _loop_comma    = (_loop_param + ",") if _loop_param else ""
        _list_comma    = (_list_param + ",") if _list_param else ""
        _video_id_safe = yt_vid or ""

        _yt_api_tag = '<script src="https://www.youtube.com/iframe_api"></script>'
        _yt_init_js = (
            "var ytPlayer = null;\n"
            "var _ytLastPlayingAt = Date.now();\n"
            "var _ytErrorCount = 0;\n"
            "var _ytRebuildPending = false;\n"
            "function _ytShow() {\n"
            "  var w=document.getElementById('yt-wrap');\n"
            "  var b=document.getElementById('unmute-btn');\n"
            "  var t=document.getElementById('idle-text');\n"
            "  if(w){w.style.opacity='1';w.style.pointerEvents='auto';}\n"
            "  if(b){b.style.display='flex';}\n"
            "  if(t){t.style.display='none';}\n"
            "}\n"
            "function _ytHide() {\n"
            "  var w=document.getElementById('yt-wrap');\n"
            "  var b=document.getElementById('unmute-btn');\n"
            "  var t=document.getElementById('idle-text');\n"
            "  if(w){w.style.opacity='0';w.style.pointerEvents='none';}\n"
            "  if(b){b.style.display='none';}\n"
            "  if(t){t.style.display='flex';}\n"
            "}\n"
            "function _ytBuildPlayer() {\n"
            "  ytPlayer = new YT.Player('yt-frame', {\n"
            "    videoId: '" + _video_id_safe + "',\n"
            "    playerVars: {autoplay:1,mute:1,controls:0,rel:0,modestbranding:1,playsinline:1,\n"
            "      cc_load_policy:1,cc_lang_pref:'en'," + _loop_comma + _list_comma + "},\n"
            "    events: {\n"
            "      onReady: function(e) { try{ e.target.playVideo(); }catch(_){} },\n"
            "      onStateChange: function(e) {\n"
            "        if(e.data===YT.PlayerState.PLAYING) { _ytShow(); _ytLastPlayingAt = Date.now(); _ytErrorCount = 0; }\n"
            "        else if(e.data===YT.PlayerState.ENDED) { _ytHide(); }\n"
            "        else if(e.data===-1) { _ytHide(); }\n"
            "      },\n"
            "      onError: function(e) {\n"
            "        _ytHide();\n"
            "        _ytErrorCount++;\n"
            "        console.warn('[kiosk] YT error code='+(e&&e.data)+' count='+_ytErrorCount);\n"
            "        _ytScheduleRebuild(_ytErrorCount > 3 ? 30000 : 6000);\n"
            "      }\n"
            "    }\n"
            "  });\n"
            "}\n"
            "function _ytScheduleRebuild(delayMs) {\n"
            "  if(_ytRebuildPending) return;\n"
            "  _ytRebuildPending = true;\n"
            "  setTimeout(function(){\n"
            "    _ytRebuildPending = false;\n"
            "    try { if(ytPlayer && ytPlayer.destroy) ytPlayer.destroy(); } catch(_){}\n"
            "    var host = document.getElementById('yt-wrap');\n"
            "    if(host){ host.innerHTML = '<div id=\"yt-frame\" style=\"width:100%;height:100%\"></div>'; }\n"
            "    if(window.YT && YT.Player) { try { _ytBuildPlayer(); _ytLastPlayingAt = Date.now(); } catch(e){ console.warn('[kiosk] rebuild failed', e); } }\n"
            "  }, delayMs || 6000);\n"
            "}\n"
            "function onYouTubeIframeAPIReady() { _ytBuildPlayer(); }\n"
            "// Watchdog: if the player has been not-PLAYING for >45 s while the idle\n"
            "// screen is on, the iframe is wedged (broken video, lost network, lost\n"
            "// session). Tear it down and rebuild instead of showing a broken tile.\n"
            "setInterval(function(){\n"
            "  var idleVisible = false;\n"
            "  var elI = document.getElementById('idle');\n"
            "  if(elI && elI.style && elI.style.display !== 'none') idleVisible = true;\n"
            "  if(!idleVisible) return;\n"
            "  var stateOk = false;\n"
            "  try {\n"
            "    var st = ytPlayer && ytPlayer.getPlayerState ? ytPlayer.getPlayerState() : null;\n"
            "    if(st === 1 /* PLAYING */ || st === 3 /* BUFFERING */) { _ytLastPlayingAt = Date.now(); stateOk = true; }\n"
            "  } catch(_){}\n"
            "  var silentMs = Date.now() - _ytLastPlayingAt;\n"
            "  if(!stateOk && silentMs > 45000) {\n"
            "    console.warn('[kiosk] YT watchdog: idle '+silentMs+'ms — rebuilding player');\n"
            "    _ytScheduleRebuild(1000);\n"
            "    _ytLastPlayingAt = Date.now();  // reset so we don't immediately retrigger\n"
            "  }\n"
            "}, 15000);\n"
            "function _ytFadeVol(target, ms){\n"
            "  if(!ytPlayer || !ytPlayer.getVolume || !ytPlayer.setVolume) return;\n"
            "  var start = ytPlayer.getVolume();\n"
            "  var steps = 16, i = 0;\n"
            "  var iv = setInterval(function(){\n"
            "    i++; var v = start + (target - start) * (i/steps);\n"
            "    try{ ytPlayer.setVolume(Math.max(0, Math.min(100, v))); }catch(e){}\n"
            "    if(i>=steps){ clearInterval(iv); }\n"
            "  }, Math.max(20, Math.floor(ms/steps)));\n"
            "}\n"
            "function ytPlay()  { if(ytPlayer && ytPlayer.playVideo)  { try{ytPlayer.setVolume(0);}catch(e){} ytPlayer.playVideo();  _ytShow(); _ytFadeVol(70, 800); } }\n"
            "function ytPause() { if(ytPlayer && ytPlayer.pauseVideo) { _ytFadeVol(0, 400); setTimeout(function(){ try{ytPlayer.pauseVideo();}catch(e){} _ytHide(); }, 420); } }\n"
        )
        _yt_idle_html = """
<div id="yt-wrap" style="position:fixed;inset:0;z-index:1;opacity:0;pointer-events:none;transition:opacity 1s">
  <div id="yt-frame" style="width:100%;height:100%"></div>
</div>
<button id="unmute-btn" onclick="toggleMute(this)"
  style="position:fixed;bottom:20px;right:20px;z-index:30;
         background:#0009;border:1px solid #f59e0b55;border-radius:50%;
         width:52px;height:52px;font-size:22px;cursor:pointer;
         display:none;align-items:center;justify-content:center;color:#fff">
  🔇
</button>"""
        _yt_mute_js = """
var _muted = true;
function toggleMute(btn) {
  _muted = !_muted;
  if (_muted) { if(ytPlayer) ytPlayer.mute();   btn.textContent = '🔇'; }
  else         { if(ytPlayer) ytPlayer.unMute(); btn.textContent = '🔊'; }
}"""
    else:
        _yt_api_tag  = ""
        _yt_init_js  = "function ytPlay(){} function ytPause(){}"
        _yt_idle_html = ""
        _yt_mute_js  = ""

    social_html = ""
    if ig:  social_html += f'<span class="social-item">📸 {ig}</span>'
    if web: social_html += f'<span class="social-item">🌐 {web}</span>'

    dis = ('<div id="dis-overlay">🖥️ Kiosk not enabled — Admin → Kiosk</div>'
           if not enabled else "")

    return f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>{name}</title>
<!-- QRCode.js — tiny library for generating QR codes client-side -->
<script src="https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js"
        integrity="sha512-CNgIRecGo7nphbeZ04Sc13ka07paqdeTu0WR1IM4kNcpmBAUSHSAX0tiW3oBn88Z5YDwuP3V34FIzAFJd5cSA=="
        crossorigin="anonymous" referrerpolicy="no-referrer"></script>
<link rel="preconnect" href="https://www.youtube.com">
<link rel="preconnect" href="https://i.ytimg.com">
<link rel="dns-prefetch" href="https://www.youtube.com">
{_yt_api_tag}
<style>
*{{box-sizing:border-box;margin:0;padding:0}}
html,body{{height:100%;overflow:hidden;background:{bg};color:#fff;
  font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,sans-serif}}

/* ── Layout shell ──────────────────────────────── */
#shell{{display:flex;flex-direction:column;height:100vh}}
#topbar{{display:flex;justify-content:space-between;align-items:center;
  padding:18px 40px;border-bottom:1px solid #1a1a1a;flex-shrink:0;
  position:relative;z-index:20;
  background:{'linear-gradient(to bottom,rgba(0,0,0,0.82) 0%,rgba(0,0,0,0.55) 100%)' if vid_mode and yt_embed_id else bg}}}
#store-name{{font-size:clamp(18px,2.8vw,36px);font-weight:900;color:{accent};letter-spacing:1px}}
#store-tag{{font-size:clamp(11px,1.4vw,18px);color:#555;margin-top:2px}}
#topbar-right{{text-align:right}}
#clock{{font-size:clamp(22px,3.5vw,48px);font-weight:200;color:{accent};letter-spacing:3px}}
#net-badge{{font-size:clamp(10px,1.2vw,14px);padding:2px 8px;border-radius:6px;
  letter-spacing:.5px;font-weight:600}}
#net-badge.online{{color:#4ade80;background:#16653411}}
#net-badge.offline{{color:#f87171;background:#7f1d1d22}}
#net-badge.checking{{color:#888}}
#mode-badge{{font-size:clamp(10px,1.2vw,15px);color:#444;text-transform:uppercase;
  letter-spacing:1.5px;margin-top:4px}}
#main{{flex:1;overflow:hidden;display:flex;flex-direction:column}}

/* ── IDLE ─────────────────────────────────────── */
#idle{{flex:1;display:flex;flex-direction:column;align-items:center;
  justify-content:center;gap:18px;text-align:center;padding:40px;position:relative;overflow:hidden}}
#idle-text{{position:relative;z-index:5;display:flex;
  flex-direction:column;align-items:center;gap:18px}}
#idle-msg{{font-size:clamp(20px,3.5vw,52px);color:#ddd;font-weight:300;line-height:1.4;max-width:860px}}
.social-item{{font-size:clamp(13px,1.6vw,22px);color:#555;margin:0 16px}}
#yt-wrap{{position:absolute;inset:0}}
#yt-wrap iframe,#yt-wrap div{{width:100%!important;height:100%!important}}

/* ── CART ─────────────────────────────────────── */
#cart{{flex:1;display:none;flex-direction:column;padding:0 40px 30px}}
#cart-header{{font-size:clamp(13px,1.4vw,18px);color:#555;text-transform:uppercase;
  letter-spacing:1.5px;padding:20px 0 14px;border-bottom:1px solid #1a1a1a}}
#cart-items{{flex:1;overflow:hidden}}
.ci{{display:flex;align-items:baseline;padding:14px 0;border-bottom:1px solid #161616;gap:14px}}
.ci-name{{flex:1;font-size:clamp(15px,2.2vw,32px);font-weight:600;color:#f0f0f0;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis}}
.ci-cond{{font-size:clamp(11px,1.2vw,16px);color:#555;margin-left:6px;font-weight:400}}
.ci-qty{{font-size:clamp(13px,1.6vw,22px);color:#666;min-width:44px;text-align:right}}
.ci-price{{font-size:clamp(15px,2.2vw,32px);font-weight:700;color:{accent};
  min-width:90px;text-align:right}}
#cart-totals{{border-top:2px solid {accent};padding-top:18px;margin-top:8px}}
.tr{{display:flex;justify-content:space-between;padding:5px 0;
  font-size:clamp(14px,1.8vw,26px);color:#888}}
.tr.grand{{color:#fff;font-size:clamp(24px,3.8vw,52px);font-weight:900;
  padding-top:14px;margin-top:6px;border-top:1px solid #222}}
.tv{{color:{accent}}}

/* ── CARD PROCESSING ─────────────────────────────── */
#card-processing{{flex:1;display:none;flex-direction:column;align-items:center;
  justify-content:center;gap:24px;text-align:center;padding:60px}}
#cp-icon{{font-size:clamp(64px,12vw,140px);animation:cp-pulse 1.6s ease-in-out infinite}}
@keyframes cp-pulse{{0%,100%{{transform:scale(1);opacity:1}}50%{{transform:scale(1.08);opacity:0.85}}}}
#cp-msg{{font-size:clamp(24px,4.5vw,64px);font-weight:700;color:#fff;line-height:1.2}}
#cp-sub{{font-size:clamp(14px,2vw,28px);color:#555;margin-top:4px}}
#cp-total{{font-size:clamp(32px,6vw,80px);font-weight:900;color:{accent};
  margin-top:8px;letter-spacing:2px}}
#cp-bar{{width:min(380px,80vw);height:5px;background:#1a1a1a;border-radius:4px;
  overflow:hidden;margin-top:8px}}
#cp-bar-inner{{height:100%;background:{accent};border-radius:4px;
  animation:cp-bar-anim 1.8s ease-in-out infinite}}
@keyframes cp-bar-anim{{0%{{width:0%}}60%{{width:100%}}100%{{width:100%;opacity:0}}}}

/* ── TRADE ─────────────────────────────────────── */
#trade{{flex:1;display:none;flex-direction:column;padding:0 40px 30px}}
#trade-header{{padding:20px 0 14px;border-bottom:1px solid #1a1a1a}}
#trade-customer{{font-size:clamp(20px,3vw,44px);font-weight:900;color:#fff}}
#trade-ref{{font-size:clamp(11px,1.3vw,17px);color:#555;margin-top:4px;letter-spacing:1px}}
#trade-items{{flex:1;overflow:hidden}}
.ti{{display:flex;align-items:baseline;padding:12px 0;border-bottom:1px solid #161616;gap:14px}}
.ti-name{{flex:1;font-size:clamp(14px,2vw,28px);font-weight:600;color:#f0f0f0}}
.ti-cond{{font-size:clamp(11px,1.2vw,16px);padding:2px 8px;border-radius:4px;
  background:#1a1a1a;color:#888;margin-left:6px}}
.ti-market{{font-size:clamp(12px,1.4vw,19px);color:#444;min-width:70px;text-align:right}}
.ti-offer{{font-size:clamp(15px,2vw,28px);font-weight:700;color:{accent};min-width:80px;text-align:right}}
#trade-totals{{border-top:2px solid #333;padding-top:18px;margin-top:8px;
  display:grid;grid-template-columns:1fr 1fr;gap:14px}}
.tot-card{{background:#111;border:1px solid #222;border-radius:12px;padding:16px 20px;text-align:center}}
.tot-label{{font-size:clamp(11px,1.3vw,17px);color:#555;text-transform:uppercase;
  letter-spacing:1px;margin-bottom:8px}}
.tot-value{{font-size:clamp(28px,4.5vw,62px);font-weight:900}}
.tot-card.cash .tot-value{{color:#22c55e}}
.tot-card.credit .tot-value{{color:{accent}}}
.credit-bonus{{font-size:clamp(10px,1.1vw,14px);color:#555;margin-top:4px}}

/* ── TRADE COMPLETE ────────────────────────────── */
#trade-done{{flex:1;display:none;flex-direction:column;align-items:center;
  justify-content:center;gap:24px;text-align:center;padding:40px}}
#td-name{{font-size:clamp(22px,3.5vw,50px);color:#fff;font-weight:300}}
#td-totals{{display:flex;gap:24px;flex-wrap:wrap;justify-content:center;margin-top:10px}}
.td-card{{background:#111;border:1px solid #222;border-radius:14px;padding:24px 40px;min-width:200px}}
.td-lbl{{font-size:clamp(12px,1.4vw,18px);color:#555;text-transform:uppercase;letter-spacing:1px;margin-bottom:10px}}
.td-amt{{font-size:clamp(36px,5.5vw,80px);font-weight:900}}

/* ── THANK YOU ─────────────────────────────────── */
#ty{{flex:1;display:none;flex-direction:column;align-items:center;
  justify-content:center;gap:16px;text-align:center;padding:40px}}
#ty h2{{font-size:clamp(42px,8vw,110px);font-weight:900;color:{accent}}}
#ty p{{font-size:clamp(18px,3vw,42px);color:#ccc;font-weight:300}}
#ty-method{{font-size:clamp(14px,1.8vw,26px);color:#555;margin-top:6px}}

/* ── PRICE CONFIRM (per-item flash, no backend) ── */
#price-confirm{{flex:1;display:none;flex-direction:column;align-items:center;
  justify-content:center;gap:18px;text-align:center;padding:60px;
  background:radial-gradient(circle at 50% 42%,{accent}09 0%,transparent 60%)}}
#pc-label{{font-size:clamp(13px,1.6vw,20px);color:#555;text-transform:uppercase;
  letter-spacing:2px}}
#pc-name{{font-size:clamp(22px,4vw,56px);font-weight:700;color:#fff;line-height:1.25;
  max-width:75vw}}
#pc-price{{font-size:clamp(52px,10vw,130px);font-weight:900;color:{accent};
  letter-spacing:2px;line-height:1;
  text-shadow:0 0 32px {accent}44;
  animation:pc-price-pop .45s cubic-bezier(.36,1.1,.46,1.3) both}}
@keyframes pc-price-pop{{
  0%{{transform:scale(0.4);opacity:0;filter:brightness(2)}}
  60%{{transform:scale(1.08);opacity:1}}
  100%{{transform:scale(1);opacity:1}}
}}
#pc-cond{{font-size:clamp(13px,1.4vw,18px);padding:4px 14px;border-radius:8px;
  background:#1a1a1a;color:#888;border:1px solid #222}}
#pc-add-more{{font-size:clamp(11px,1.3vw,17px);color:#333;margin-top:8px}}

/* ── RECEIPT QR (shown after sale) ──────────────── */
#receipt-qr{{flex:1;display:none;flex-direction:column;align-items:center;
  justify-content:center;gap:20px;text-align:center;padding:40px}}
#rq-icon{{font-size:clamp(42px,7vw,88px)}}
#rq-msg{{font-size:clamp(20px,3.5vw,48px);font-weight:700;color:#fff}}
#rq-sub{{font-size:clamp(13px,1.8vw,24px);color:#555;margin-top:-8px}}
#rq-qr{{background:#fff;border-radius:16px;padding:16px;
  box-shadow:0 0 40px {accent}33;
  animation:qr-appear .6s cubic-bezier(.36,1.1,.46,1.3) .15s both}}
@keyframes qr-appear{{
  0%{{transform:scale(0.3) rotate(-6deg);opacity:0}}
  60%{{transform:scale(1.06) rotate(1deg);opacity:1}}
  100%{{transform:scale(1) rotate(0);opacity:1}}
}}
#rq-url{{font-size:clamp(10px,1.1vw,14px);color:#333;margin-top:-4px;word-break:break-all}}

/* ── Disabled ──────────────────────────────────── */
#dis-overlay{{position:fixed;inset:0;background:{bg};display:flex;align-items:center;
  justify-content:center;font-size:clamp(16px,2vw,28px);color:#333;z-index:9999;
  text-align:center;padding:40px}}

/* ═══════════════════════════════════════════════════
   HANRYXVAULT ANIMATIONS — Pokémon-themed, gold & black
   ═══════════════════════════════════════════════════ */

/* ── ambient gold dust particles ── */
#particles{{position:fixed;inset:0;pointer-events:none;z-index:0;overflow:hidden}}
.particle{{position:absolute;border-radius:50%;opacity:0;animation:gold-rise linear infinite}}
@keyframes gold-rise{{
  0%{{transform:translateY(100vh) scale(0);opacity:0}}
  10%{{opacity:.7}}
  50%{{opacity:.5}}
  90%{{opacity:.2}}
  100%{{transform:translateY(-10vh) scale(1);opacity:0}}
}}

/* ── CSS Pokéball shapes (pure CSS, no images) ── */
.pokeball-float{{
  width:clamp(28px,4vw,52px);height:clamp(28px,4vw,52px);
  border-radius:50%;position:absolute;pointer-events:none;z-index:2;
  background:linear-gradient(to bottom,#cc0000 0%,#cc0000 45%,#111 45%,#111 55%,#fff 55%,#fff 100%);
  border:2px solid #222;
  box-shadow:0 0 12px {accent}22;
  animation:float-drift 14s ease-in-out infinite;font-size:0;opacity:0;
}}
.pokeball-float::after{{
  content:'';position:absolute;top:50%;left:50%;
  width:30%;height:30%;border-radius:50%;transform:translate(-50%,-50%);
  background:#fff;border:2px solid #333;box-shadow:0 0 4px {accent}44;
}}
.pokeball-float.ultra{{
  background:linear-gradient(to bottom,#111 0%,#111 45%,#facc15 45%,#facc15 55%,#111 55%,#111 100%);
}}
.pokeball-float.ultra::after{{background:{accent};border-color:#000}}
.pokeball-float.master{{
  background:linear-gradient(to bottom,#6b21a8 0%,#6b21a8 45%,#facc15 45%,#facc15 55%,#333 55%,#333 100%);
}}
.pokeball-float.master::after{{background:{accent};border-color:#6b21a8}}

@keyframes float-drift{{
  0%{{transform:translateY(20px) rotate(-8deg) scale(.85);opacity:0}}
  12%{{opacity:.30}}
  50%{{transform:translateY(-35px) rotate(8deg) scale(1);opacity:.22}}
  88%{{opacity:.12}}
  100%{{transform:translateY(20px) rotate(-8deg) scale(.85);opacity:0}}
}}

/* ── energy type icons (CSS-drawn) ── */
.energy-icon{{
  width:clamp(24px,3.5vw,44px);height:clamp(24px,3.5vw,44px);
  border-radius:50%;position:absolute;pointer-events:none;z-index:2;
  border:2px solid;display:flex;align-items:center;justify-content:center;
  font-size:clamp(12px,1.8vw,22px);font-weight:900;
  animation:float-drift 16s ease-in-out infinite;opacity:0;
}}
.energy-icon[data-type="fire"]{{
  background:radial-gradient(circle,#ff6b3520,#ff2d0010);border-color:#ff6b3544;color:#ff6b35;
}}
.energy-icon[data-type="fire"]::after{{content:'🔥';font-size:clamp(14px,2vw,26px)}}
.energy-icon[data-type="electric"]{{
  background:radial-gradient(circle,{accent}20,{accent}08);border-color:{accent}44;color:{accent};
}}
.energy-icon[data-type="electric"]::after{{content:'⚡';font-size:clamp(14px,2vw,26px)}}
.energy-icon[data-type="water"]{{
  background:radial-gradient(circle,#3b82f620,#3b82f608);border-color:#3b82f644;color:#3b82f6;
}}
.energy-icon[data-type="water"]::after{{content:'💧';font-size:clamp(14px,2vw,26px)}}
.energy-icon[data-type="psychic"]{{
  background:radial-gradient(circle,#a855f720,#a855f708);border-color:#a855f744;color:#a855f7;
}}
.energy-icon[data-type="psychic"]::after{{content:'🔮';font-size:clamp(14px,2vw,26px)}}

/* ── idle screen — gold text shimmer ── */
#idle-msg{{
  animation:gold-shimmer 4s ease-in-out infinite;
}}
@keyframes gold-shimmer{{
  0%,100%{{opacity:.85;filter:brightness(1);text-shadow:0 0 0 transparent}}
  50%{{opacity:1;filter:brightness(1.1);text-shadow:0 2px 16px {accent}22}}
}}

/* ── store name gold glow ── */
#store-name{{
  animation:vault-glow 3s ease-in-out infinite;
}}
@keyframes vault-glow{{
  0%,100%{{text-shadow:0 0 6px {accent}33}}
  50%{{text-shadow:0 0 18px {accent}66,0 0 36px {accent}22}}
}}

/* ── logo border shimmer ── */
#topbar img{{
  animation:logo-ring 4s ease-in-out infinite;
}}
@keyframes logo-ring{{
  0%,100%{{box-shadow:0 0 0 0 {accent}44}}
  50%{{box-shadow:0 0 14px 3px {accent}44}}
}}

/* ── cart item slide-in ── */
.ci{{animation:vault-slide-in .45s ease-out both}}
@keyframes vault-slide-in{{
  from{{transform:translateX(50px);opacity:0}}
  to{{transform:translateX(0);opacity:1}}
}}

/* cart item flash on new */
.ci-new{{animation:vault-item-flash .6s ease-out}}
@keyframes vault-item-flash{{
  0%{{background:{accent}18;transform:scale(1.02);box-shadow:inset 0 0 20px {accent}11}}
  100%{{background:transparent;transform:scale(1);box-shadow:none}}
}}

/* ── grand total gold glow ── */
.tr.grand .tv{{animation:gold-price-glow 2.5s ease-in-out infinite}}
@keyframes gold-price-glow{{
  0%,100%{{text-shadow:0 0 4px {accent}44}}
  50%{{text-shadow:0 0 16px {accent}88,0 0 32px {accent}33}}
}}

/* ── card processing — Pokéball orbit rings ── */
#card-processing{{
  background:radial-gradient(circle at 50% 40%,{accent}06 0%,transparent 55%);
}}
#cp-icon{{
  animation:cp-pulse 1.6s ease-in-out infinite, pokeball-wobble 3s ease-in-out infinite;
}}
@keyframes pokeball-wobble{{
  0%,100%{{transform:scale(1) perspective(300px) rotateY(0deg)}}
  25%{{transform:scale(1.06) perspective(300px) rotateY(10deg)}}
  75%{{transform:scale(1.06) perspective(300px) rotateY(-10deg)}}
}}
#cp-ring{{position:absolute;width:clamp(160px,28vw,280px);height:clamp(160px,28vw,280px);
  border:3px solid {accent}33;border-top-color:{accent}77;border-radius:50%;
  animation:pokering 3s linear infinite}}
@keyframes pokering{{
  0%{{transform:rotate(0deg)}}
  100%{{transform:rotate(360deg)}}
}}
#cp-ring2{{position:absolute;width:clamp(200px,34vw,340px);height:clamp(200px,34vw,340px);
  border:2px dashed {accent}18;border-left-color:{accent}44;border-radius:50%;
  animation:pokering 6s linear infinite reverse}}

/* ── thank you — Pokéball catch celebration ── */
#ty h2{{animation:vault-catch .9s cubic-bezier(.36,1.1,.46,1.3) both}}
@keyframes vault-catch{{
  0%{{transform:scale(0) rotate(-5deg);opacity:0;filter:brightness(2)}}
  50%{{transform:scale(1.1) rotate(1deg);opacity:1;filter:brightness(1.3)}}
  100%{{transform:scale(1) rotate(0);opacity:1;filter:brightness(1)}}
}}
#ty p{{animation:vault-rise .7s ease-out .35s both}}
@keyframes vault-rise{{
  from{{transform:translateY(24px);opacity:0}}
  to{{transform:translateY(0);opacity:1}}
}}
#confetti-canvas{{position:fixed;inset:0;pointer-events:none;z-index:25}}

/* ── trade-in item entrance ── */
.ti{{animation:vault-slide-in .4s ease-out both}}

/* ── trade done — gold burst ── */
#trade-done .td-card{{animation:vault-pop .5s cubic-bezier(.36,1.1,.46,1.3) both}}
@keyframes vault-pop{{
  from{{transform:scale(0);opacity:0}}
  to{{transform:scale(1);opacity:1}}
}}

/* ── BRAND PULSE screen (sale complete interstitial) ── */
#brand-pulse{{
  display:none;flex-direction:column;align-items:center;justify-content:center;
  position:relative;overflow:hidden;gap:0;
}}
#bp-logo{{
  width:clamp(180px,30vw,380px);height:auto;border-radius:18px;
  animation:bp-zoom 2.2s cubic-bezier(.22,1,.36,1) both;
  position:relative;z-index:3;
  border:3px solid {accent}55;
  filter:drop-shadow(0 0 24px {accent}66);
}}
@keyframes bp-zoom{{
  0%{{transform:scale(0) rotate(-10deg);opacity:0;filter:drop-shadow(0 0 0 transparent)}}
  40%{{transform:scale(1.15) rotate(2deg);opacity:1;filter:drop-shadow(0 0 40px {accent}88)}}
  60%{{transform:scale(.95) rotate(-1deg);filter:drop-shadow(0 0 30px {accent}66)}}
  80%{{transform:scale(1.05) rotate(0);filter:drop-shadow(0 0 50px {accent}aa)}}
  100%{{transform:scale(1) rotate(0);filter:drop-shadow(0 0 20px {accent}66)}}
}}
#bp-ring-outer{{
  position:absolute;width:clamp(200px,36vw,400px);height:clamp(200px,36vw,400px);
  border:3px solid {accent}44;border-top-color:{accent};border-radius:50%;z-index:2;
  animation:bp-ring-spin 1.8s linear infinite, bp-ring-grow 2s ease-out both;
}}
#bp-ring-inner{{
  position:absolute;width:clamp(160px,28vw,320px);height:clamp(160px,28vw,320px);
  border:2px solid {accent}22;border-bottom-color:{accent}66;border-radius:50%;z-index:2;
  animation:bp-ring-spin 2.4s linear infinite reverse, bp-ring-grow 2s ease-out .1s both;
}}
@keyframes bp-ring-spin{{0%{{transform:rotate(0)}}100%{{transform:rotate(360deg)}}}}
@keyframes bp-ring-grow{{
  0%{{transform:scale(0);opacity:0}}
  50%{{opacity:1}}
  100%{{transform:scale(1);opacity:.7}}
}}
#bp-text{{
  font-size:clamp(22px,4.5vw,56px);font-weight:900;letter-spacing:.15em;
  color:{accent};margin-top:clamp(16px,3vw,36px);z-index:3;
  animation:bp-text-in 1s ease-out .6s both;
  text-shadow:0 0 20px {accent}44;
}}
@keyframes bp-text-in{{
  0%{{transform:translateY(30px) scale(.8);opacity:0;letter-spacing:.6em}}
  100%{{transform:translateY(0) scale(1);opacity:1;letter-spacing:.15em}}
}}
#bp-flash{{
  position:absolute;inset:0;z-index:1;
  background:radial-gradient(circle at 50% 45%,{accent}18 0%,transparent 65%);
  animation:bp-flash-pulse 1.2s ease-in-out infinite;
}}
@keyframes bp-flash-pulse{{
  0%,100%{{opacity:.3}}
  50%{{opacity:.8}}
}}

/* ── gold sparkles on price updates ── */
.sparkle{{position:absolute;width:5px;height:5px;border-radius:50%;
  background:{accent};pointer-events:none;z-index:30;
  animation:gold-spark .7s ease-out forwards}}
@keyframes gold-spark{{
  0%{{transform:scale(1);opacity:1}}
  100%{{transform:scale(0) translate(var(--sx),var(--sy));opacity:0}}
}}
</style>
</head>
<body>
{dis}
<!-- Ambient floating particles -->
<div id="particles"></div>
<!-- Confetti canvas (thank you + trade done) -->
<canvas id="confetti-canvas"></canvas>
<div id="shell">

  <!-- Top bar — always visible -->
  <div id="topbar">
    <div style="display:flex;align-items:center;gap:16px">
      <img src="/static/logo.png" alt="HanryxVault"
           style="height:52px;width:52px;object-fit:cover;border-radius:50%;
                  border:2px solid {accent};flex-shrink:0">
      <div>
        <div id="store-name">{name}</div>
        <div id="store-tag">{tagline}</div>
      </div>
    </div>
    <div id="topbar-right">
      <div id="net-badge" title="Network status">⏳</div>
      <div id="clock"></div>
      <div id="mode-badge">Ready</div>
    </div>
  </div>

  <div id="main">

    <!-- IDLE -->
    <div id="idle">
      {_yt_idle_html}
      <div class="float-card pokeball-float" style="left:6%;top:22%;animation-delay:0s"></div>
      <div class="float-card energy-icon" style="left:78%;top:12%;animation-delay:2.5s" data-type="fire"></div>
      <div class="float-card pokeball-float ultra" style="left:88%;top:58%;animation-delay:4.5s"></div>
      <div class="float-card energy-icon" style="left:14%;top:68%;animation-delay:6.5s" data-type="electric"></div>
      <div class="float-card pokeball-float" style="left:52%;top:8%;animation-delay:8s"></div>
      <div class="float-card energy-icon" style="left:62%;top:72%;animation-delay:3.5s" data-type="water"></div>
      <div class="float-card energy-icon" style="left:32%;top:38%;animation-delay:5.5s" data-type="psychic"></div>
      <div class="float-card pokeball-float master" style="left:42%;top:82%;animation-delay:7s"></div>
      <div id="idle-text">
        <div id="idle-msg">{idle_msg}</div>
        <div style="margin-top:8px">{social_html}</div>
      </div>
    </div>

    <!-- CART (checkout) -->
    <div id="cart">
      <div id="cart-header">Your order</div>
      <div id="cart-items"></div>
      <div id="cart-totals"></div>
    </div>

    <!-- TRADE (trade-in calculator) -->
    <div id="trade">
      <div id="trade-header">
        <div id="trade-customer"></div>
        <div id="trade-ref"></div>
      </div>
      <div id="trade-items"></div>
      <div id="ai-breakdown" style="display:none;padding:12px 20px">
        <div style="font-size:clamp(11px,1.2vw,15px);color:#facc15;font-weight:700;text-transform:uppercase;letter-spacing:2px;margin-bottom:8px">
          Price Breakdown
        </div>
        <div id="ai-range" style="display:flex;gap:14px;margin-bottom:8px"></div>
        <div id="ai-reasons" style="font-size:clamp(11px,1.3vw,16px);color:#555;line-height:1.6"></div>
        <div id="ai-source" style="font-size:clamp(9px,1vw,12px);color:#333;margin-top:6px;font-style:italic"></div>
      </div>
      <div id="trade-totals">
        <div class="tot-card cash">
          <div class="tot-label">Cash Value</div>
          <div class="tot-value" id="trade-cash">£0.00</div>
        </div>
        <div class="tot-card credit">
          <div class="tot-label">Store Credit</div>
          <div class="tot-value" id="trade-credit">£0.00</div>
          <div class="credit-bonus">+20% bonus vs cash</div>
        </div>
      </div>
    </div>

    <!-- CARD LOOKUP (customer sees the card being looked up) -->
    <div id="lookup" style="display:none;flex-direction:column;align-items:center;
         justify-content:center;padding:40px;text-align:center;gap:20px">
      <div id="lookup-img-wrap" style="position:relative">
        <img id="lookup-img" src="" alt=""
             style="max-height:45vh;border-radius:16px;box-shadow:0 0 40px rgba(250,204,21,0.3);
                    border:2px solid #facc1544">
      </div>
      <div id="lookup-name" style="font-size:clamp(22px,3.5vw,48px);font-weight:900;color:#fff"></div>
      <div id="lookup-meta" style="font-size:clamp(12px,1.5vw,18px);color:#666"></div>
      <div id="lookup-price" style="font-size:clamp(36px,5vw,72px);font-weight:900;
           color:#facc15;text-shadow:0 0 30px rgba(250,204,21,0.4)"></div>
      <div id="lookup-stock" style="font-size:clamp(13px,1.5vw,20px);color:#444"></div>
    </div>

    <!-- TRADE DONE -->
    <div id="trade-done">
      <div style="font-size:clamp(48px,8vw,96px)">🎉</div>
      <div id="td-name"></div>
      <div id="td-totals">
        <div class="td-card"><div class="td-lbl">Cash Value</div><div class="td-amt" style="color:#22c55e" id="td-cash"></div></div>
        <div class="td-card"><div class="td-lbl">Store Credit</div><div class="td-amt" style="color:{accent}" id="td-credit"></div></div>
      </div>
      <div style="font-size:clamp(16px,2vw,28px);color:#555;margin-top:8px">Thank you for trading with us!</div>
    </div>

    <!-- CARD PROCESSING (tap / insert card) -->
    <div id="card-processing">
      <div style="position:relative;display:flex;align-items:center;justify-content:center">
        <div id="cp-ring"></div>
        <div id="cp-ring2"></div>
        <div id="cp-icon">💳</div>
      </div>
      <div id="cp-msg">Please continue<br>on the card reader</div>
      <div id="cp-sub">Tap, insert, or swipe your card</div>
      <div id="cp-total"></div>
      <div id="cp-bar"><div id="cp-bar-inner"></div></div>
    </div>

    <!-- SALE COMPLETE — brand pulse (before thank you) -->
    <div id="brand-pulse">
      <div id="bp-ring-outer"></div>
      <div id="bp-ring-inner"></div>
      <img id="bp-logo" src="/static/brand-pulse.jpeg" alt="HanryxVault">
      <div id="bp-text">SALE COMPLETE</div>
      <div id="bp-flash"></div>
    </div>

    <!-- THANK YOU (after sale) -->
    <div id="ty">
      <h2>Thank you for supporting my small business!</h2>
      <div id="ty-method"></div>
    </div>

    <!-- PRICE CONFIRM (flashes full-screen when an item is added) -->
    <div id="price-confirm">
      <div id="pc-label">Item added</div>
      <div id="pc-name"></div>
      <div id="pc-price"></div>
      <div id="pc-cond" style="display:none"></div>
      <div id="pc-add-more">Scan another card or proceed to payment</div>
    </div>

    <!-- RECEIPT QR (shown after sale completes) -->
    <div id="receipt-qr">
      <div id="rq-icon">🧾</div>
      <div id="rq-msg">Scan for your receipt</div>
      <div id="rq-sub">Point your phone camera at the QR code</div>
      <div id="rq-qr"></div>
      <div id="rq-url"></div>
    </div>

  </div>
</div>

<script>
(function(){{
  var elIdle   = document.getElementById("idle");
  var elCart   = document.getElementById("cart");
  var elTrade  = document.getElementById("trade");
  var elTDone  = document.getElementById("trade-done");
  var elLookup = document.getElementById("lookup");
  var elTy     = document.getElementById("ty");
  var elCP     = document.getElementById("card-processing");
  var elBP     = document.getElementById("brand-pulse");
  var elPC     = document.getElementById("price-confirm");
  var elRQ     = document.getElementById("receipt-qr");
  var elBadge  = document.getElementById("mode-badge");

  /* clock */
  var clk = document.getElementById("clock");
  function tick(){{ clk.textContent = new Date().toLocaleTimeString([],{{hour:"2-digit",minute:"2-digit"}}); }}
  tick(); setInterval(tick,1000);

  /* ═══ NETWORK STATUS CHECKER ═══ */
  var netBadge = document.getElementById("net-badge");
  function checkNetwork(){{
    if(!netBadge) return;
    fetch("/health",{{method:"GET",cache:"no-store"}})
      .then(function(r){{ return r.json(); }})
      .then(function(d){{
        var online = navigator.onLine;
        netBadge.textContent = online ? "🟢 Online" : "🔴 Offline";
        netBadge.className = online ? "online" : "offline";
        netBadge.title = online ? "Connected to internet" : "Running on cached data — all features work locally";
      }})
      .catch(function(){{
        netBadge.textContent = "⚠️ Server";
        netBadge.className = "offline";
        netBadge.title = "POS server not responding";
      }});
  }}
  checkNetwork(); setInterval(checkNetwork, 30000);

  function f(n){{ return "£"+parseFloat(n||0).toFixed(2); }}
  function esc(s){{ var d=document.createElement("div"); d.textContent=s; return d.innerHTML; }}

  var elUnmute = document.getElementById("unmute-btn");

  /* ═══ GOLD DUST PARTICLE SYSTEM ═══ */
  (function initParticles(){{
    var box = document.getElementById("particles");
    if(!box) return;
    var goldShades = ["{accent}","#d4a017","#b8860b","#daa520","#f5c842"];
    function spawn(){{
      var p = document.createElement("div");
      p.className = "particle";
      var size = 2 + Math.random()*4;
      var dur  = 8 + Math.random()*14;
      var clr  = goldShades[Math.floor(Math.random()*goldShades.length)];
      p.style.cssText = "width:"+size+"px;height:"+size+"px;left:"+Math.random()*100+
        "%;background:"+clr+";animation-duration:"+dur+"s;animation-delay:"+Math.random()*6+"s;"+
        "box-shadow:0 0 "+(size*2)+"px "+clr+"44";
      box.appendChild(p);
      setTimeout(function(){{ p.remove(); }}, (dur+6)*1000);
    }}
    for(var i=0;i<18;i++) spawn();
    setInterval(function(){{ if(box.children.length<30) spawn(); }}, 1200);
  }})();

  /* ═══ CONFETTI CANNON (gold Pokéball-themed) ═══ */
  var confCanvas = document.getElementById("confetti-canvas");
  var confCtx = confCanvas ? confCanvas.getContext("2d") : null;
  var confPieces = [];
  var confRunning = false;

  function resizeConfetti(){{
    if(!confCanvas) return;
    confCanvas.width = window.innerWidth;
    confCanvas.height = window.innerHeight;
  }}
  window.addEventListener("resize", resizeConfetti);
  resizeConfetti();

  function fireConfetti(){{
    if(!confCtx) return;
    confPieces = [];
    var colors = ["{accent}","#fff","#cc0000","#d4a017","#f5c842","#b8860b","#6b21a8"];
    for(var i=0;i<120;i++){{
      confPieces.push({{
        x: window.innerWidth/2 + (Math.random()-.5)*200,
        y: window.innerHeight/2,
        vx: (Math.random()-.5)*14,
        vy: -8 - Math.random()*10,
        w: 4+Math.random()*6, h: 6+Math.random()*8,
        rot: Math.random()*360, rv: (Math.random()-.5)*12,
        color: colors[Math.floor(Math.random()*colors.length)],
        gravity: 0.15+Math.random()*0.1,
        life: 1
      }});
    }}
    if(!confRunning){{ confRunning=true; animConfetti(); }}
  }}

  function animConfetti(){{
    if(!confCtx) return;
    confCtx.clearRect(0,0,confCanvas.width,confCanvas.height);
    var alive = false;
    for(var i=0;i<confPieces.length;i++){{
      var p=confPieces[i];
      if(p.life<=0) continue;
      alive=true;
      p.x+=p.vx; p.y+=p.vy; p.vy+=p.gravity;
      p.rot+=p.rv; p.life-=0.006;
      confCtx.save();
      confCtx.translate(p.x,p.y);
      confCtx.rotate(p.rot*Math.PI/180);
      confCtx.globalAlpha=Math.max(0,p.life);
      confCtx.fillStyle=p.color;
      confCtx.fillRect(-p.w/2,-p.h/2,p.w,p.h);
      confCtx.restore();
    }}
    if(alive) requestAnimationFrame(animConfetti);
    else{{ confRunning=false; confCtx.clearRect(0,0,confCanvas.width,confCanvas.height); }}
  }}

  /* ═══ SPARKLE BURST (fires around a target element) ═══ */
  function spawnSparkles(el){{
    if(!el) return;
    var rect=el.getBoundingClientRect();
    var cx=rect.left+rect.width/2, cy=rect.top+rect.height/2;
    for(var i=0;i<8;i++){{
      var sp=document.createElement("div");
      sp.className="sparkle";
      var angle=Math.random()*Math.PI*2;
      var dist=30+Math.random()*50;
      sp.style.left=cx+"px"; sp.style.top=cy+"px";
      sp.style.setProperty("--sx",Math.cos(angle)*dist+"px");
      sp.style.setProperty("--sy",Math.sin(angle)*dist+"px");
      document.body.appendChild(sp);
      setTimeout(function(){{ sp.remove(); }},700);
    }}
  }}

  function showOnly(el, badge){{
    [elIdle,elCart,elTrade,elTDone,elLookup,elTy,elCP,elBP,elPC,elRQ].forEach(function(e){{
      if(e) e.style.display="none";
    }});
    el.style.display="flex";
    if(elBadge) elBadge.textContent = badge||"";
    if(el !== elIdle){{
      ytPause();
      if(elUnmute) elUnmute.style.display="none";
    }}
  }}

  function goIdle(){{
    _prevItemCount = 0;
    _pendingConfirm = null;
    showOnly(elIdle,"Ready");
    ytPlay();
    if(elUnmute) elUnmute.style.display="flex";
  }}

  function goStandby(){{
    // Hide every panel and pause the video — pure black screen
    [elIdle,elCart,elTrade,elTDone,elLookup,elTy,elCP,elBP,elPC,elRQ].forEach(function(e){{
      if(e) e.style.display="none";
    }});
    ytPause();
    if(elUnmute) elUnmute.style.display="none";
    if(elBadge)  elBadge.textContent = "";
  }}

  /* ══════════════════════════════════════════════════
     PRICE CONFIRM — full-screen item flash
     Shows when an item is added to the cart.
     After _PC_DURATION ms, slides back to full cart.
  ══════════════════════════════════════════════════ */
  var _PC_DURATION     = {price_confirm_ms};   // ms to show price-confirm (from admin settings)
  var _SHOW_RECEIPT_QR = {show_receipt_qr};    // show QR receipt after sale (from admin settings)
  var _pendingConfirm = null;
  var _pcTimer = null;

  function showPriceConfirm(item, cartState){{
    if(!item) return;
    var elName  = document.getElementById("pc-name");
    var elPrice = document.getElementById("pc-price");
    var elCond  = document.getElementById("pc-cond");
    var elLabel = document.getElementById("pc-label");
    if(elName)  elName.textContent  = item.name  || "";
    if(elPrice){{ elPrice.textContent = f(item.price);
                  elPrice.style.animation="none"; void elPrice.offsetWidth; elPrice.style.animation=""; }}
    if(elCond){{
      var c = item.condition||"";
      elCond.textContent = c; elCond.style.display = c ? "" : "none";
    }}
    if(elLabel) elLabel.textContent = "Item added — " + f(item.price);
    spawnSparkles(elPrice);
    showOnly(elPC, "Item added");
    clearTimeout(_pcTimer);
    _pcTimer = setTimeout(function(){{
      if(_pendingConfirm){{ renderCartView(_pendingConfirm); _pendingConfirm=null; }}
    }}, _PC_DURATION);
  }}

  /* ══════════════════════════════════════════════════
     RECEIPT QR — shown after sale, customer scans QR
  ══════════════════════════════════════════════════ */
  var _qrGenerated = "";

  function showReceiptQR(s){{
    var url = s.receipt_url ? (window.location.origin + s.receipt_url) : "";
    if(!url) {{ goIdle(); return; }}
    showOnly(elRQ, "Receipt");
    var box = document.getElementById("rq-qr");
    var urlEl = document.getElementById("rq-url");
    if(urlEl) urlEl.textContent = "";
    if(box){{
      if(_qrGenerated !== url){{
        box.innerHTML = "";
        try{{
          new QRCode(box, {{
            text: url,
            width:  Math.min(280, window.innerWidth * 0.38),
            height: Math.min(280, window.innerWidth * 0.38),
            colorDark: "#000000",
            colorLight: "#ffffff",
            correctLevel: QRCode.CorrectLevel.M
          }});
          _qrGenerated = url;
        }} catch(e){{
          box.innerHTML = "<span style='color:#555;font-size:12px'>QR unavailable</span>";
        }}
      }}
    }}
    // Auto-dismiss after 12 s → thank you → idle

    setTimeout(function(){{
      showOnly(elTy,"Thank you");
      var m=document.getElementById("ty-method");
      if(m) m.textContent = s.payment_method ? "Paid by "+s.payment_method : "";
      fireConfetti();
      setTimeout(function(){{ spawnSparkles(document.querySelector("#ty h2")); }},300);
      setTimeout(goIdle,6000);
    }}, 12000);
  }}

  /* ── CART rendering (inner) ── */
  function renderCartView(s){{
    showOnly(elCart,"Checkout");
    var ci=document.getElementById("cart-items");
    ci.innerHTML=s.items.map(function(it,idx){{
      var cond=it.condition?" <span class='ci-cond'>"+esc(it.condition)+"</span>":"";
      return "<div class='ci' style='animation-delay:"+(idx*0.06)+"s'>"
        +"<div class='ci-name'>"+esc(it.name||"")+cond+"</div>"
        +"<div class='ci-qty'>x"+(it.qty||1)+"</div>"
        +"<div class='ci-price'>"+f(it.price)+"</div></div>";
    }}).join("");
    var sub=s.subtotal||0,tax=s.tax||0,tot=s.total||0;
    var rows="<div class='tr'><span>Subtotal</span><span class='tv'>"+f(sub)+"</span></div>";
    if(tax>0) rows+="<div class='tr'><span>Tax</span><span class='tv'>"+f(tax)+"</span></div>";
    rows+="<div class='tr grand'><span>TOTAL</span><span class='tv'>"+f(tot)+"</span></div>";
    document.getElementById("cart-totals").innerHTML=rows;
    spawnSparkles(document.querySelector(".tr.grand .tv"));
  }}

  /* ── CART mode (SSE dispatcher entry) ── */
  var _prevItemCount = 0;
  function renderCart(s){{
    if(s.paid){{
      _prevItemCount = 0;
      clearTimeout(_pcTimer); _pendingConfirm = null;
      showOnly(elBP,"Sale complete");
      var bpLogo=document.getElementById("bp-logo");
      if(bpLogo){{ bpLogo.style.animation="none"; void bpLogo.offsetWidth; bpLogo.style.animation=""; }}
      var bpText=document.getElementById("bp-text");
      if(bpText){{ bpText.style.animation="none"; void bpText.offsetWidth; bpText.style.animation=""; }}
      var bpRO=document.getElementById("bp-ring-outer");
      if(bpRO){{ bpRO.style.animation="none"; void bpRO.offsetWidth; bpRO.style.animation=""; }}
      var bpRI=document.getElementById("bp-ring-inner");
      if(bpRI){{ bpRI.style.animation="none"; void bpRI.offsetWidth; bpRI.style.animation=""; }}
      setTimeout(function(){{
        if(_SHOW_RECEIPT_QR && s.receipt_url){{
          _qrGenerated = "";   // force re-render each time
          showReceiptQR(s);
        }} else {{
          showOnly(elTy,"Thank you");
          var m=document.getElementById("ty-method");
          if(m) m.textContent=s.payment_method ? "Paid by "+s.payment_method : "";
          fireConfetti();
          setTimeout(function(){{ spawnSparkles(document.querySelector("#ty h2")); }},300);
          setTimeout(goIdle,6000);
        }}
      }}, 2800);
      return;
    }}
    if(s.payment_processing){{
      showOnly(elCP,"Processing payment");
      var cpTot=document.getElementById("cp-total");
      if(cpTot) cpTot.textContent=s.total ? "£"+parseFloat(s.total).toFixed(2) : "";
      return;
    }}
    if(!s.active||!s.items||!s.items.length){{ _prevItemCount=0; goIdle(); return; }}
    var newCount=s.items.length;
    var newItem = (newCount > _prevItemCount) ? s.items[s.items.length-1] : null;
    _prevItemCount = newCount;
    if(newItem && newCount > 1){{
      // Flash price-confirm for the newly added item, then show full cart
      _pendingConfirm = s;
      showPriceConfirm(newItem, s);
    }} else {{
      renderCartView(s);
    }}
  }}

  /* ── TRADE mode ── */
  function renderTrade(s){{
    if(s.trade_complete){{
      showOnly(elTDone,"Trade complete");
      document.getElementById("td-name").textContent="Thank you, "+(s.trade_customer||"")+"!";
      document.getElementById("td-cash").textContent=f(s.trade_cash||0);
      document.getElementById("td-credit").textContent=f(s.trade_credit||0);
      fireConfetti();
      setTimeout(function(){{ spawnSparkles(document.querySelector("#trade-done h2,#trade-done .td-card")); }}, 300);
      setTimeout(goIdle,10000);
      return;
    }}
    showOnly(elTrade,"Trade-In");
    document.getElementById("trade-customer").textContent="Trade-In — "+(s.trade_customer||"");
    document.getElementById("trade-ref").textContent=s.trade_reference||"";
    var items=s.trade_items||[];
    var ti=document.getElementById("trade-items");
    ti.innerHTML=items.length ? items.map(function(it){{
      return "<div class='ti'>"
        +"<div class='ti-name'>"+esc(it.name)+"<span class='ti-cond'>"+esc(it.condition||"")+"</span></div>"
        +"<div class='ti-market'>"+f(it.market)+" market</div>"
        +"<div class='ti-offer'>"+f(it.offer)+"</div>"
        +"</div>";
    }}).join("")
    : "<div style='color:#444;padding:20px 0;font-size:clamp(14px,1.8vw,22px)'>Waiting for cards to be assessed…</div>";
    document.getElementById("trade-cash").textContent=f(s.trade_cash||0);
    document.getElementById("trade-credit").textContent=f(s.trade_credit||0);

    /* AI breakdown (from /admin/ai-tradein) */
    var bd=document.getElementById("ai-breakdown");
    if(s.ai_breakdown){{
      var ai=s.ai_breakdown;
      bd.style.display="block";
      document.getElementById("ai-range").innerHTML=[
        "<div style='flex:1;text-align:center;padding:8px;background:#111;border-radius:8px'>"
          +"<div style='font-size:clamp(9px,1vw,12px);color:#666;text-transform:uppercase'>Min</div>"
          +"<div style='font-size:clamp(16px,2vw,28px);font-weight:900;color:#888'>"+f(ai.buy_floor)+"</div></div>",
        "<div style='flex:1;text-align:center;padding:8px;background:#1a1a00;border:1px solid #facc1544;border-radius:8px'>"
          +"<div style='font-size:clamp(9px,1vw,12px);color:#facc15;text-transform:uppercase;font-weight:700'>Our Offer</div>"
          +"<div style='font-size:clamp(20px,2.5vw,36px);font-weight:900;color:#facc15'>"+f(ai.buy_ideal)+"</div></div>",
        "<div style='flex:1;text-align:center;padding:8px;background:#111;border-radius:8px'>"
          +"<div style='font-size:clamp(9px,1vw,12px);color:#666;text-transform:uppercase'>Max</div>"
          +"<div style='font-size:clamp(16px,2vw,28px);font-weight:900;color:#888'>"+f(ai.buy_max)+"</div></div>",
        "<div style='flex:1;text-align:center;padding:8px;background:#111;border-radius:8px'>"
          +"<div style='font-size:clamp(9px,1vw,12px);color:#22c55e;text-transform:uppercase'>Market</div>"
          +"<div style='font-size:clamp(16px,2vw,28px);font-weight:900;color:#22c55e'>"+f(ai.ebay_median)+"</div></div>"
      ].join("");
      document.getElementById("ai-reasons").innerHTML=(ai.reasoning||[]).map(function(r){{
        return "<div style='padding:3px 0'>• "+esc(r)+"</div>";
      }}).join("");
      document.getElementById("ai-source").textContent="Source: "+(ai.source||"");
    }} else {{
      bd.style.display="none";
    }}
  }}

  /* ── LOOKUP mode (card lookup mirrored to customer) ── */
  var elLookup=document.getElementById("lookup");
  function renderLookup(s){{
    showOnly(elLookup,"Card Lookup");
    var img=document.getElementById("lookup-img");
    if(s.card_image){{
      img.src=s.card_image; img.style.display="block";
    }} else {{
      img.style.display="none";
    }}
    document.getElementById("lookup-name").textContent=s.card_name||"";
    var meta=[];
    if(s.card_set) meta.push(s.card_set+(s.card_number?" #"+s.card_number:""));
    if(s.card_rarity) meta.push(s.card_rarity);
    document.getElementById("lookup-meta").textContent=meta.join(" · ");
    document.getElementById("lookup-price").textContent=s.card_price>0 ? f(s.card_price) : "";
    document.getElementById("lookup-stock").textContent=s.stock_qty>0
      ? s.stock_qty+" in stock" : (s.card_price>0 ? "In stock" : "");
    setTimeout(goIdle, 30000);
  }}

  /* ── PREFETCH: warm browser cache with recently-scanned card images ──
     Polls the server every 90 s for the URLs most likely to appear next.
     Eliminates the ~150 ms image fetch when a customer scans a card. */
  var _prefetched = {{}};
  function prefetchScanImages(){{
    fetch("/kiosk/prefetch?limit=60", {{credentials:"same-origin"}})
      .then(function(r){{ return r.ok ? r.json() : null; }})
      .then(function(j){{
        if(!j || !j.urls) return;
        for(var i=0;i<j.urls.length;i++){{
          var u = j.urls[i];
          if(!u || _prefetched[u]) continue;
          _prefetched[u] = 1;
          var img = new Image();   // chromium caches the response
          img.decoding = "async";
          img.src = u;
        }}
      }})
      .catch(function(){{ /* offline — try again next tick */ }});
  }}
  // First warm-up shortly after load, then every 90 s
  setTimeout(prefetchScanImages, 4000);
  setInterval(prefetchScanImages, 90000);

  /* ── SSE dispatcher ── */
  function onData(s){{
    /* Payment / paid screens take priority over whatever mode the cart is in.
       Without this, /kiosk/payment-processing (which doesn't change mode)
       would be ignored when mode==="idle" and the customer would never see
       the "Processing payment" or "Thank you" views. */
    if(s.payment_processing || s.paid){{ renderCart(s); return; }}
    if(s.mode==="standby"){{ goStandby(); return; }}
    if(s.mode==="trade"){{ renderTrade(s); return; }}
    if(s.mode==="lookup"){{ renderLookup(s); return; }}
    if(s.mode==="idle"){{ goIdle(); return; }}
    renderCart(s);
  }}

/* ── SSE connection with visible reconnect overlay ───────────────────────── */
  var _sse = null;
  var _sseBackoff = 2000;   // start at 2 s, doubles to 30 s max
  var _sseLostAt  = 0;
  var _sseOverlay = null;

  function _sseGetOverlay(){{
    if(!_sseOverlay){{
      var o=document.createElement("div");
      o.id="sse-reconnect-overlay";
      o.style.cssText=[
        "position:fixed","top:0","left:0","width:100%","height:100%",
        "background:rgba(0,0,0,0.82)","display:none","z-index:9999",
        "flex-direction:column","align-items:center","justify-content:center",
        "font-family:sans-serif"
      ].join(";");
      o.innerHTML=[
        '<div style="font-size:48px;margin-bottom:20px;animation:pulse 1.8s ease-in-out infinite">⚡</div>',
        '<div style="font-size:22px;font-weight:700;color:#facc15;margin-bottom:8px">Reconnecting to POS…</div>',
        '<div id="sse-rc-status" style="font-size:13px;color:#555">Please wait</div>',
        '<style>@keyframes pulse{{0%,100%{{opacity:.5;transform:scale(1)}}50%{{opacity:1;transform:scale(1.1)}}}}</style>'
      ].join("");
      document.body.appendChild(o);
      _sseOverlay=o;
    }}
    return _sseOverlay;
  }}

  function _sseShowOverlay(msg){{
    var o=_sseGetOverlay();
    o.style.display="flex";
    var st=document.getElementById("sse-rc-status");
    if(st) st.textContent=msg||"Reconnecting…";
  }}

  function _sseHideOverlay(){{
    if(_sseOverlay) _sseOverlay.style.display="none";
  }}

  /* ── Kiosk state signature ───────────────────────────────────────────────
     Baked in by the server on page render.  The 500 ms sig-poll below
     compares against this value; a change means the server state has moved
     on without SSE delivering it, so we reload to get a fresh render.
     SSE onmessage keeps _kiosk_sig in sync so working SSE never reloads.
  ── */
  var _kiosk_sig = "{_kiosk_sig_init}";

  function _computeKioskSig(d){{
    return (d.mode||'idle')
      + (d.active?'1':'0')
      + (d.paid?'1':'0')
      + ((d.payment_processing||d.checkout)?'1':'0')
      + (d.items ? d.items.length : 0)
      + Math.round((d.total||0)*100);
  }}

  /* ── SSE connection with polling fallback ────────────────────────────────
     _lastSseMsg tracks the last time an SSE message arrived.
     If silent for >20 s (broken pipe, nginx buffer, Tailscale blip),
     the sig-poll below reloads the page instead of calling onData in-place.
  ── */
  var _lastSseMsg = Date.now();

  function _sseConnect(){{
    if(_sse){{ try{{_sse.close();}}catch(e){{}} }}
    _sse=new EventSource("/kiosk/stream");
    _sse.onmessage=function(e){{
      _lastSseMsg = Date.now();          // ← timestamp every message
      _sseBackoff=2000;
      _sseLostAt=0;
      _sseHideOverlay();
      try{{
        var _d = JSON.parse(e.data);
        _kiosk_sig = _computeKioskSig(_d);  // keep sig current → no spurious reload
        onData(_d);
      }}catch(err){{ console.warn("[kiosk]",err); }}
    }};
    _sse.onerror=function(){{
      if(!_sseLostAt) _sseLostAt=Date.now();
      var lostSec=Math.round((Date.now()-_sseLostAt)/1000);
      if(lostSec>=5){{
        // Show overlay only after 5 s of silence (avoids flicker on brief drops)
        _sseShowOverlay("Lost connection "+lostSec+"s ago — retrying in "+(_sseBackoff/1000)+"s…");
      }}
      try{{_sse.close();}}catch(e){{}}
      setTimeout(function(){{
        _sseBackoff=Math.min(_sseBackoff*2, 30000);
        _sseConnect();
      }}, _sseBackoff);
    }};
  }}

  /* Show idle screen immediately on page load — don't wait for SSE */
  goIdle();

  _sseConnect();

  /* ── 500 ms signature poll ───────────────────────────────────────────────
     Polls /kiosk/state.json every 500 ms and compares the sig.
     · SSE working  → _kiosk_sig is kept current by onmessage → no reload.
     · SSE broken   → sig drifts after state change → page reloads,
                       picking up fresh server-rendered state + new sig.
     The _lastSseMsg update suppresses the SSE lost-connection overlay
     while the poll is succeeding (proves the server is reachable).
  ── */
  (function(){{
    var _busy = false;
    function _sigPoll(){{
      if(_busy) return;
      _busy = true;
      fetch("/kiosk/state.json", {{cache:"no-store"}})
        .then(function(r){{ return r.json(); }})
        .then(function(d){{
          var sig = _computeKioskSig(d);
          // Polling is a TRUE fallback delivery mechanism — if the sig has
          // moved on, dispatch the new state directly via onData() instead of
          // waiting for SSE.  SSE delivery can silently break (cross-worker
          // broadcasts, proxy buffering, gunicorn worker churn) while the
          // EventSource still appears connected, so we can never trust SSE
          // alone.  No more sseSilent gate, no more page reloads.
          if(sig !== _kiosk_sig){{
            _kiosk_sig = sig;
            try{{ onData(d); }}catch(err){{ console.warn("[kiosk poll]", err); }}
          }}
          _busy = false;
          setTimeout(_sigPoll, 500);
        }})
        .catch(function(){{
          _busy = false;
          setTimeout(_sigPoll, 1000);  // back off on network error
        }});
    }}
    setTimeout(_sigPoll, 500);
  }})();

  /* ── Nightly auto-reload at 04:00 local ─────────────────────────────
     Refreshes the kiosk page once per night to clear chromium memory
     leaks, drop stale iframes, and re-fetch the latest server template.
     Only fires while idle (no active cart) so we never interrupt a sale.
  ── */
  (function(){{
    var _lastReloadDay = -1;
    setInterval(function(){{
      var now = new Date();
      var day = now.getDate();
      // Window: 04:00–04:05 local. Only once per day. Skip if not idle.
      if(now.getHours() !== 4 || now.getMinutes() > 5) return;
      if(day === _lastReloadDay) return;
      var idleVisible = false;
      var elI = document.getElementById('idle');
      if(elI && elI.style && elI.style.display !== 'none') idleVisible = true;
      if(!idleVisible) return;
      _lastReloadDay = day;
      console.warn('[kiosk] nightly auto-reload');
      setTimeout(function(){{ window.location.reload(); }}, 500);
    }}, 60000);  // check once a minute
  }})();

}})();

/* ══════════════════════════════════════════════════════════════════════
   OFFLINE SALE QUEUE
   When the tablet/browser can't reach the server, sales are stored in
   localStorage under key "hvault_offline_queue" as a JSON array.
   On reconnect, they are automatically drained to /sales/queue.
   ══════════════════════════════════════════════════════════════════════ */
(function(){{
  var QUEUE_KEY    = "hvault_offline_queue";
  var CLIENT_KEY   = "hvault_client_id";
  var DRAIN_URL    = "/sales/queue";
  var HEALTH_URL   = "/health";
  var _draining    = false;
  var _serverOnline = true;

  /* Stable per-device client ID stored in localStorage */
  function getClientId(){{
    var id = localStorage.getItem(CLIENT_KEY);
    if(!id){{
      id = "kiosk-" + Date.now() + "-" + Math.random().toString(36).slice(2,8);
      localStorage.setItem(CLIENT_KEY, id);
    }}
    return id;
  }}

  /* Get pending queue */
  function getQueue(){{
    try{{ return JSON.parse(localStorage.getItem(QUEUE_KEY)||"[]"); }}
    catch(e){{ return []; }}
  }}

  /* Add a sale to the queue */
  window.hvaultQueueSale = function(items, total, paymentMethod){{
    var q = getQueue();
    if(q.length >= 100){{
      // Hard cap — refuse rather than silently drop
      console.error("[offline-queue] Queue full (100) — refusing to enqueue more");
      try{{ alert("⚠️ Offline queue full (100 sales). Reconnect to server before taking more orders."); }}catch(e){{}}
      return false;
    }}
    q.push({{
      items:          items||[],
      total:          parseFloat(total)||0,
      payment_method: paymentMethod||"offline",
      queued_at:      Date.now()
    }});
    localStorage.setItem(QUEUE_KEY, JSON.stringify(q));
    console.log("[offline-queue] Queued sale. Queue length:", q.length);
    if(q.length === 20 || q.length === 50 || q.length === 80){{
      try{{ alert("⚠️ "+q.length+" offline sales queued. Reconnect soon to sync."); }}catch(e){{}}
    }}
    updateOfflineBadge();
    return true;
  }};

  /* Drain the queue to the server */
  function drainQueue(){{
    if(_draining) return;
    var q = getQueue();
    if(!q.length) return;
    _draining = true;
    fetch(DRAIN_URL, {{
      method: "POST",
      headers: {{"Content-Type":"application/json"}},
      body: JSON.stringify({{client_id: getClientId(), sales: q}})
    }})
    .then(function(r){{ return r.json(); }})
    .then(function(d){{
      if(d.ok){{
        localStorage.removeItem(QUEUE_KEY);
        console.log("[offline-queue] Drained", d.saved, "sale(s)");
        updateOfflineBadge();
      }}
    }})
    .catch(function(e){{
      console.warn("[offline-queue] Drain failed, will retry:", e);
    }})
    .finally(function(){{ _draining=false; }});
  }}

  /* Poll server health; drain queue when it comes back */
  function pollServer(){{
    fetch(HEALTH_URL, {{method:"GET",cache:"no-store"}})
      .then(function(r){{
        if(r.ok){{
          if(!_serverOnline){{
            _serverOnline = true;
            console.log("[offline-queue] Server back online — draining queue");
            drainQueue();
          }}
          _serverOnline = true;
        }}
      }})
      .catch(function(){{
        _serverOnline = false;
        updateOfflineBadge();
      }});
  }}

  /* Update the net-badge to also reflect queued sales */
  function updateOfflineBadge(){{
    var q = getQueue();
    if(!q.length) return;
    var badge = document.getElementById("net-badge");
    if(badge){{
      badge.textContent = "⚠️ " + q.length + " sale"+(q.length>1?"s":"")+" queued";
      badge.className = "offline";
      badge.title = q.length + " sale(s) queued offline — will sync automatically when server reconnects";
    }}
  }}

  /* Listen for browser online event */
  window.addEventListener("online", function(){{
    console.log("[offline-queue] Browser online event");
    drainQueue();
  }});

  /* Try to drain any leftover queue on page load */
  drainQueue();
  /* Check server every 60 s */
  setInterval(pollServer, 60000);
  updateOfflineBadge();
}})();


{_yt_init_js}
{_yt_mute_js}
</script>
<script>
/* ── Fit-to-screen for sub-1024px panels ─────────────────────────────────────
   The kiosk page is designed for ≥1024px wide. On the satellite's 800×480
   touch panel (or any narrow display), proportionally scale the entire body
   down so nothing wraps or gets clipped. Layout stays pixel-perfect, just
   smaller. No effect on screens ≥ 1024px.
─────────────────────────────────────────────────────────────────────────── */
(function(){{
  var DESIGN_W = 1024;
  function fit(){{
    var vw = window.innerWidth;
    var vh = window.innerHeight;
    if (vw >= DESIGN_W) {{
      document.body.style.transform = '';
      document.body.style.width = '';
      document.body.style.height = '';
      document.body.style.transformOrigin = '';
      return;
    }}
    var s = vw / DESIGN_W;
    document.body.style.transformOrigin = 'top left';
    document.body.style.transform       = 'scale(' + s + ')';
    document.body.style.width           = DESIGN_W + 'px';
    /* Inflate logical height so the scaled body still fills the viewport. */
    document.body.style.height          = (vh / s) + 'px';
  }}
  fit();
  window.addEventListener('resize', fit);
  /* Also re-fit after orientation change & after fonts/images load,
     since wrap behaviour can shift the effective viewport. */
  window.addEventListener('orientationchange', fit);
  window.addEventListener('load', fit);
}})();
</script>
</body>
</html>"""


